        AH_YOU_VE_RETURNED_YOU_WERE_GONE_SO                                     = 41,  -- Ah, you've returned! You were gone so long, I feared a warmachine had got you!
        AT_ANY_RATE_MISSION_COMPLETE_AND_TO_REWARD                              = 42,  -- At any rate, mission complete! And to reward your accomplishment...
        I_HEREBY_RECOGNIZE_YOU_AS_A_CERTIFIED_ADVENTURER                        = 43,  -- I hereby recognize you, %, as a certified adventurer of San d'Oria! You're now mission rank two, as well.
