        THE_PAPSQUE_OFTEN_COMES_ACROSS_AS_A_DIFFICULT                           = 124,  -- The papsque often comes across as a difficult man, but he is actually very kindhearted and compassionate. If you change your mind, I'll be waiting here.
        THE_FAIR_CLAIDIE_I_D_ORAGUILLE_HAS_INVITED                              = 125,  -- The fair Claidie I d'Oraguille has invited you to the chateau. She wishes for you to see the flowers that have bloomed from the seeds you brought back from Altepa.
        IT_IS_AN_HONOR_TO_BE_INVITED_TO                                         = 126,  -- It is an honor to be invited to the chateau garden. One day you may even have the opportunity to attend one of their royal garden parties.
        WE_CANNOT_KEEP_THE_PRINCESS_WAITING_NOW_OFF                             = 127,  -- We cannot keep the princess waiting. Now, off to the chateau!
        A_PARTY_OF_ROYAL_KNIGHTS_STATIONED_IN_GHELSBA                           = 128,  -- A party of Royal Knights stationed in Ghelsba Outpost have reported strange activity by Orcs deep within Yughott Grotto.
        FROM_YOUR_REPORTS_WE_ALREADY_KNOW_THAT_THE                              = 129,  -- From your reports, we already know that the beastmen have built a giant portal, but their motives remain unclear.
