        TRADE_GUILD_POINTS_FOR_3                                                = 7034,  -- Trade # guild points for %?
        YOU_ARE_A_REGISTERED_CRAFTSMAN_AT_THE_FOLLOWING                         = 7035,  -- You are a registered craftsman at the following guild(s): [/Carpenters' ][/Blacksmiths' ][/Goldsmiths' ][/Weavers' ][/Tanners' ][/Boneworkers' ][/Alchemists' ][/Culinarians' ] By revoking your status, you will be reduced to journeyman and your synthesis skills will be adjusted accordingly.
        PROCEED_YES_NO                                                          = 7036,  -- Proceed? Yes. No.
        YOUR_CRAFTSMAN_STATUS_AT_THE_GUILD_HAS_BEEN                             = 7037,  -- Your craftsman status at the [Carpenters'/Blacksmiths'/Goldsmiths'/Weavers'/Tanners'/Boneworkers'/Alchemists'/Culinarians'] Guild has been revoked.
        WHICH_RANK_OF_SYNTHESIS_DO_YOU_ASK_ABOUT                                = 7038,  -- Which rank of synthesis do you ask about? Never mind. Amateur. Recruit. Initiate. Novice. Apprentice. Journeyman. Craftsman. Artisan. Adept. Veteran. Expert. Authority. Luminary. Master. Grandmaster.
