        BECOMING_A_CRAFTSMAN_IN_ANY_GUILD_REQUIRES_A                            = 7081,  -- Becoming a craftsman in any guild requires a high level of skill and concentration. But there is only so much that people like us can fit into our heads. Remember that.
        EXCELLENT_WORK_I_KNEW_THAT_YOU_COULD_DO                                 = 7082,  -- Excellent work! I knew that you could do it! I hereby grant you the title of craftsman. You are ready to accept the responsibility that comes with that name.
        THERE_IS_NO_NEED_TO_RUSH_YOUR_WORK                                      = 7083,  -- There is no need to rush your work. Continue slowly along your path and you will not fail. Just remember to never stray too far from the road.
        IS_A_WONDERFUL_NEW_METHOD_OF_WOODWORKING_THAT                           = 7084,  -- % is a wonderful new method of woodworking that allows you to enchant lumber with the mysterious energy of black magic and anima.
        IS_A_WONDERFUL_NEW_METHOD_OF_WOODWORKING_THAT_2                         = 7085,  -- % is a wonderful new method of woodworking that allows you to enchant lumber with the mysterious energy of white magic and anima.
