        JUST_A_MOMENT                                                           = 7559,  -- Just a moment.
        PRINCE_TRION_IS_THERE_SOMETHING_YOU_WISH_TO                             = 7560,  -- Prince Trion, is there something you wish to add?
        I_WILL_NOT_DENY_THAT_THE_PARTICIPATION_OF                               = 7561,  -- ... I will not deny that the participation of adventurers has been of great benefit to the conquest, as well as maintained a new level of safety in the outlying regions.
        IN_ADDITION_THE_MANY_TREATIES_SIGNED_BY_OUR                             = 7562,  -- In addition, the many treaties signed by our nations have successfully paved a path of peace. No longer need our border guards fear attacks from our friends to the south and east.
        HOWEVER_THE_BEASTMAN_FORCES_DISPLAY_NO_SIGNS_OF                         = 7563,  -- However, the beastman forces display no signs of weakening. Those noble guards stationed in faraway lands must deal with this reality constantly...and the burden has begun taking its toll.
        THE_ALREADY_LARGE_GAP_BETWEEN_THE_GUARDS_ON                             = 7564,  -- The already large gap between the guards on our borders and the guards in the Outlands expands with each day. If nothing is done, morale shall continue to fall while discontent grows.
        I_SENSE_THAT_MY_KINGDOM_IS_NOT_ALONE                                    = 7565,  -- I sense that my kingdom is not alone in these worries.
        SOLDIER_MORALE                                                          = 7566,  -- Soldier morale...
        WELL_WELL_WELL_I_NEVER_THOUGHT_I_D                                      = 7567,  -- Well, well, well! I never thought I'd see such a lack of confidence from a member of the mighty d'Oraguille family!
        OHOHOHO_I_NEVER_THOUGHT_I_D_SEE_SUCH                                    = 7568,  -- Ohohoho! I never thought I'd see such a lack of confidence from Destin's baby boy--Trion, the prince.
        HOW_DARE_YOU                                                            = 7569,  -- How dare you!?
        I_THINK_THAT_IS_QUITE_ENOUGH_MINISTER                                   = 7570,  -- I think that is quite enough, Minister.
        I_FULLY_UNDERSTAND_THE_CONCERNS_OF_PRINCE_TRION                         = 7571,  -- I fully understand the concerns of Prince Trion, and believe he has a point.
        DOCTOR_SHANTOTTO_I_FULLY_UNDERSTAND_THE_CONCERNS_OF                     = 7572,  -- Doctor Shantotto... I fully understand the concerns of Prince Trion, and believe he has a point.
        IN_A_REPUBLIC_LIKE_BASTOK_WHERE_A_LARGE                                 = 7573,  -- In a republic like Bastok, where a large portion of our army is made up of normal citizens, it is easy for morale levels to slide. This is a problem that is constantly being tackled by our officials.
        REALLY_WELL_THAT_S_YOUR_NATION_WINDURST_DOESN                           = 7574,  -- Really? Well, that's your nation. Windurst doesn't face such problems.
        OUR_MITHRAN_MERCENARIES_ENJOY_BEING_SENT_TO_FAR                         = 7575,  -- Our Mithran Mercenaries enjoy being sent to far-off places. It gives them the opportunity to run and jump and hunt and roll around in the mud--whatever those feminine felines like to do in their free time.
        MAYBE_INSTEAD_OF_BUFFING_UP_YOUR_SOLDIERS_MUSCLES                       = 7576,  -- Maybe instead of buffing up your soldiers' muscles all day, you should try training their minds...like we do. And that's my two gil!
        OH_REA_LLY_WELL_THAT_S_YOUR_NATION                                      = 7577,  -- Oh, rea`lly? Well, that's your nation. We don't have such problems in the Federation.
        OUR_MITHRAN_MERCENARIES_ENJOY_BEING_SENT_TO_FARAWAY                     = 7578,  -- Our Mithran Mercenaries enjoy being sent to faraway places. It gives them time to take their naps, hunt their mice, and go on their chases.
        MAYBE_IT_S_TO_THE_LACK_OF_CONFIDENCE                                    = 7579,  -- Maybe it's to the lack of confidence that you can give thanks for the drastic fall of morale in your pathetic ranks.
        ID_7580                                                                 = 7580,  -- ...
        YES_BUT_HIRING_MERCENARIES_CAN_BE_QUITE_THE                             = 7581,  -- Yes, but hiring mercenaries can be quite the burden on the Federation's treasury, can it not?
        YES_BUT_HIRING_MERCENARIES_CAN_BE_QUITE_THE_2                           = 7582,  -- Yes, but hiring mercenaries can be quite the burden on the Federation's treasury, can it not?
        THE_MORE_REGIONS_UNDER_YOUR_NATION_S_CONTROL                            = 7583,  -- The more regions under your nation's control, the more mercenaries you must hire. And before you realize it, your vaults will be empty.
        I_SUSPECT_THAT_THE_CONQUEST_IS_TAKING_ITS                               = 7584,  -- I suspect that the conquest is taking its toll on the Federation.
        WELL_WE                                                                 = 7585,  -- Well, we...
        OHOHOHOHO_IN_A_MATTER_OF_MONTHS_OUR_WISHY                               = 7586,  -- Ohohohoho! In a matter of months, our wishy-worries will be gone, When our Outland regions are patrolled by automatons.
        OPERATION_COSTS_WILL_STAY_LOWER_THAN_LOW_AND                            = 7587,  -- Operation costs will stay lower than low. And into our vaults the gil shall flow. Ohoho!
        SHANTOTTO                                                               = 7588,  -- Shantotto!
        IF_YOU_WISH_WINDURST_CAN_ALSO_BUILD_SOME                                = 7589,  -- If you wish, Windurst can also build some for use by the king and the president. All for a small fee payable in five easy installments.
        OHOHOHOHO_IN_A_MATTER_OF_MONTHS_OUR_WISHY_2                             = 7590,  -- Ohohohoho! In a matter of months, our wishy-worries will be gone, when our Outland regions are patrolled by automatons.
        OPERATION_COSTS_WILL_STAY_LOWER_THAN_LOW_AND_2                          = 7591,  -- Operation costs will stay lower than low. And into our vaults the gil shall flow. Ohoho!
        WHILE_WE_APPRECIATE_THE_CONCERN_FROM_DESTIN_S                           = 7592,  -- While we appreciate the concern from Destin's baby and Karst's pet, I don't think Windurst will be taking any drastic actions yet.
        BUT_IF_YOU_WISH_WE_COULD_BUILD_SOME                                     = 7593,  -- But if you wish, we could build some Cardians for use by the king and the president. All for a small fee payable in five easy installments. O`hohohohoho!
        THAT_SOUNDS_LIKE_A_LOVELY_PLAN_MINISTER_SHANTOTTO                       = 7594,  -- That sounds like a lovely plan, Minister Shantotto.
        BUT_WOULDN_T_THE_USE_OF_AUTOMATONS_IN                                   = 7595,  -- But wouldn't the use of automatons in the conquest be in violation of the Treaty of Nations...?
        HMPH_AND_I_HAVE_HEARD_MANY_A_TALE                                       = 7596,  -- Hmph. And I have heard many a tale of those walking scarecrows turning on their masters...
        LIKE_FATHER_LIKE_SON_I_SAY_I_WOULD                                      = 7597,  -- Like father, like son, I say. I would not trust a lump of rubbish made by one of you lunatics any more than I would trust one of you lunatics!
        HOW_CAN_ONE_CALL_A_SOLDIER_THAT_DOES                                    = 7598,  -- How can one call a soldier that does not obey his leader a soldier? And how can one call a leader who cannot control his soldiers a leader?
        OOH_SOMEBODY_S_IN_A_BAD_MOOD                                            = 7599,  -- Ooh, somebody's in a bad mood...
        PRINCE_TRION_YOU_CERTAINLY_DID_NOT_BRING_UP                             = 7600,  -- Prince Trion. You certainly did not bring up this issue without having a solution in mind.
        EXACTLY_YOU_D_BETTER_HAVE_SOMETHING_INTERESTING_TO                      = 7601,  -- Exactly! You'd better have something interesting to say. Or Ajido and I will pack up our things and be on our way.
        RECENTLY_ONE_OF_OUR_ROYAL_KNIGHTS_MADE_HIS                              = 7602,  -- Recently one of our Royal Knights made his return journey from our kingdom's territories to the north--Lord Excenmille.
        EXCENMILLE_THE_MAN_WHO_AFTER_THE_GREAT_WAR                              = 7603,  -- Excenmille? The man who, after the Great War, took a handful of soldiers and successfully invaded the Orcish Empire using guerilla tactics?
        YES_SWORD_IN_HAND_DONNING_ARMOR_STAINED_WITH                            = 7604,  -- Yes. Sword in hand, donning armor stained with the blood of a thousand foes, he returned to his homeland for the first time in twenty years...and was shocked at what he found lurking beyond its gates.
        FOREIGN_MERCHANTS_OF_ALL_SHAPES_AND_SIZES_PEDDLING                      = 7605,  -- Foreign merchants of all shapes and sizes peddling their trinkets. Scruffy adventurers shouting out their petty problems as they walked freely among the streets and alleys. Local shopkeeps and Temple Knights laughing as they mingled with the scum washed up from all corners of the continent.
        EXCENMILLE_WAS_FURIOUS                                                  = 7606,  -- Excenmille was furious.
        WHY_WOULD_HE_BE_FURIOUS_THE_INFLUX_OF                                   = 7607,  -- Why would he be furious? The influx of adventurers has revitalized your nation.
        ACCORDING_TO_EXCENMILLE_TWENTY_FIVE_YEARS_AGO_A                         = 7608,  -- According to Excenmille, twenty-five years ago, a union among the children of Altana was necessary to defeat the armies of darkness.
        HOWEVER_NOW_THAT_THE_THREAT_HAS_GONE_THERE                              = 7609,  -- However, now that the threat has gone, there is no reason for San d'Oria's citizens to be brushing shoulders with the common folk of other nations. It is this symbiotic relationship that plagues the Kingdom and keeps the once mighty red lion shackled down.
        THAT_SEEMS_LIKE_QUITE_AN_ANACHRONOUS_OPINION                            = 7610,  -- That seems like quite an anachronous opinion...
        EXCENMILLE_S_WAY_OF_THINKING_MAY_SEEM_OUT                               = 7611,  -- Excenmille's way of thinking may seem out-of-date, but his logic cannot be denied. Ever since the opening of our gates to outsiders, the quality of our knights has fallen dramatically.
        I_M_TIRED_OF_HEARING_STORIES_ABOUT_SOME                                 = 7612,  -- ... I'm tired of hearing stories about some pumpkin-bumpkin knight. Are you going to get to the point, or are we going to be here all night?
        EXCENMILLE_OFFERED_ME_WITH_THE_FOLLOWING_SUGGESTION                     = 7613,  -- Excenmille offered me with the following suggestion...
        REVIVE_CONFLICT                                                         = 7614,  -- Revive Conflict!
        ID_7615                                                                 = 7615,  -- ...
        ID_7616                                                                 = 7616,  -- ...!?
        C_CONFLICT_A_SERIES_OF_GAMES_BASED_ON                                   = 7617,  -- C-Conflict!? A series of games based on battle exercises, played by select heroes from each of the nations...
        DUE_TO_THE_EXTREME_LEVEL_OF_DANGER_INVOLVED                             = 7618,  -- Due to the extreme level of danger involved, it was banned well before the Great War. You are not suggesting that we reinstate Conflict, are you?
        THAT_IS_WHAT_I_PROPOSE                                                  = 7619,  -- That is what I propose.
        CONFLICT_AN_INTERESTING_IDEA                                            = 7620,  -- Conflict... An interesting idea...
        THERE_WAS_ONCE_A_TIME_WHEN_CONFLICT_IGNITED                             = 7621,  -- There was once a time when Conflict ignited the spirits of the people of Bastok--players and fans alike.
        HOWEVER_AFTER_NUMEROUS_ACCIDENTS_THE_GAMES_WERE_DEEMED                  = 7622,  -- However, after numerous accidents, the games were deemed a bad influence on the Republic's image, and were banned by law.
        IF_CONFLICT_WAS_REINSTATED_IT_COULD_RE_IGNITE                           = 7623,  -- If Conflict was reinstated, it could re-ignite the flames in the hearts of all Bastokers and renew their faith in the Republican Army. Morale would be restored, and our problems solved.
        PRINCE_TRION_PRINCE_TRION_IF_THAT_S_ALL                                 = 7624,  -- Prince Trion, Prince Trion. If that's all that you wanted to say, you didn't have to go beat around the bush all day.
        WINDURST_WELCOMES_CONFLICT_WITH_OPEN_ARMS_A_LITTLE                      = 7625,  -- Windurst welcomes Conflict with open arms! A little feuding fun could do no harm.
        SHANTOTTO_2                                                             = 7626,  -- Shantotto!?
        OH_THERE_S_NOTHING_TO_GET_ALL_EXCITED                                   = 7627,  -- Oh, there's nothing to get all excited about. The forces of Windurst are in good hands. A couple of knutty knights and measly musketeers are no match for Shantotto's superior battle plans.
        THE_FORCES_OF_WINDURST_ARE_IN_GOOD_HANDS                                = 7628,  -- The forces of Windurst are in good hands. A couple of knutty knights and measly musketeers are no match for Shantotto's superior battle plans.
        AND_ONCE_WE_GET_OUR_FEARLESS_LOYAL_ADVENTURERS                          = 7629,  -- And once we get our fearless loyal adventurers to help, it will be your two nations letting out cries and yelps.
        IF_SAN_D_ORIA_AND_WINDURST_HAVE_AGREED                                  = 7630,  -- If San d'Oria and Windurst have agreed to participate, the president is sure to grant his approval.
        AND_I_KNOW_OUR_ADVENTURERS_WILL_BE_MORE                                 = 7631,  -- And I know our adventurers will be more than happy to take up their swords for the Republic.
        EXCELLENT_I_LOOK_FORWARD_TO_MEETING_YOU_ALL                             = 7632,  -- Excellent. I look forward to meeting you all again on the battlefield.
        WELL_IT_IS_A_RARE_OCCASION_THAT_ALL                                     = 7633,  -- Well... It is a rare occasion that all three nations agree on an issue.
        UNFORTUNATELY_DUCAL_LAW_PREVENTS_JEUNO_FROM_PARTICIPATING_IN            = 7634,  -- Unfortunately, ducal law prevents Jeuno from participating in such matters.
        HOWEVER_WE_WILL_ASSIGN_OFFICIALS_TO_TAKE_PART                           = 7635,  -- However, we will assign officials to take part as Heralds and watch over the games.
        I_HAVE_NO_OBJECTIONS_NOW_LET_US_RETURN                                  = 7636,  -- I have no objections. Now let us return to our nations and begin with the preparations.
        THEN_IT_HAS_BEEN_DECIDED_SIR_WOLFGANG                                   = 7637,  -- Then it has been decided. Sir Wolfgang.
        AHEM_THEN_IF_THERE_IS_NOTHING_FURTHER_I                                 = 7638,  -- Ahem. Then, if there is nothing further, I call the 136th Conquest Evaluation Assembly to a close.
        THOUGH_I_D_RATHER_BE_SITTING_ON_THE                                     = 7639,  -- Though I'd rather be sitting on the beach, catching some sun, sometimes these stuffy-snuffy meetings can be kind of fun!
        THOUGH_I_D_RATHER_BE_SITTING_ON_THE_2                                   = 7640,  -- Though I'd rather be sitting on the beach, catching some sun, sometimes these stuffy-snuffy meetings can be kind of fun!
        I_COULD_TAKE_UP_MY_STAFF_AND_PARTICIPATE                                = 7641,  -- I could take up my staff and participate in Conflict myself, but my super-duper whammy-slammy spells would be bad for my opponents' health! Ohohohohoho!
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_BASIC                                    = 7642,  -- What do you wish to know about? Basic rules. About the Petra. About Sprint. About Scout. About Gate Breach. About area-specific rules. About returning to battle. About special rules. Nothing at the moment.
        BALLISTA_IS_AN_EXERCISE_ONCE_USED_BY_THE                                = 7643,  -- Ballista is an exercise once used by the San d'Orian armies to train the Royal Knights in the art of the siege. The word ballista means to throw a stone, and the game has been a part of Vana'dielian military history for centuries.
        THE_RULES_ARE_SIMPLE_BALLISTA_IS_PLAYED_BY                              = 7644,  -- The rules are simple. Ballista is played by two teams over a number of hours (Vana'diel time). The team with the most points at the end of the match is the victor.
        PLAYERS_FROM_BOTH_TEAMS_MUST_SEARCH_FOR_PETRAS                          = 7645,  -- Players from both teams must search for Petras that a Herald has buried in various locations across the battlefield. The players must then take these stones and throw them into targets known as Rooks.
        THESE_ROOKS_CAN_APPEAR_IN_VARIOUS_LOCATIONS_AROUND                      = 7646,  -- These Rooks can appear in various locations around the battlefield, and both teams are allowed to throw their Petras into them.
        FINALLY_A_PLAYER_S_STRENGTH_IS_ADJUSTED_DEPENDING                       = 7647,  -- Finally, a player's strength is adjusted depending on his or her level. It is felt that this ultimately allows for a more balanced battle.
        PETRAS_CAN_BE_BURIED_ANYWHERE_ONCE_A_PLAYER                             = 7648,  -- Petras can be buried anywhere. Once a player believes he or she has found one, the Quarry (/quarry) command should be used to dig up the area at his or her feet.
        SOMETIMES_A_PLAYER_MAY_FIND_ITEMS_OTHER_THAN                            = 7649,  -- Sometimes a player may find items other than Petras, such as potions. These temporary items can only be used during the current match (or Best of Three series).
        PLAYERS_CAN_CARRY_MORE_THAN_ONE_PETRA_BUT                               = 7650,  -- Players can carry more than one Petra, but they cannot throw the stones away once they have obtained them. However, players will lose their Petras if they: (1) Successfully throw them into a rook. (2) Leave the area. (3) Are knocked out.
        BUT_DON_T_FORGET_A_PLAYER_WILL_BE                                       = 7651,  -- But don't forget, a player will be unable to use the Sprint command while in possession of a Petra. And, players can only use the Scout command if they carry one of the stones.
        AS_ONE_CAN_SEE_CAREFUL_PLANNING_AND_IMPECCABLE                          = 7652,  -- As one can see, careful planning and impeccable timing are the keys to victory.
        ALL_PARTICIPANTS_OF_BALLISTA_WILL_HAVE_THE_ABILITY                      = 7653,  -- All participants of Ballista will have the ability to use the Sprint command. This will temporarily increase one's movement speed, creating a better chance to find and obtain Petras.
        HOWEVER_REMEMBER_THAT_ONCE_A_PLAYER_HAS_OBTAINED                        = 7654,  -- However, remember that once a player has obtained a Petra, he or she will be unable to use the Sprint command. In its place, though, one may use the Scout command.
        THE_LOCATIONS_OF_THE_ROOKS_ARE_CONSTANTLY_CHANGING                      = 7655,  -- The locations of the Rooks are constantly changing. This makes it quite difficult to find the targets by just randomly walking about the area.
        COMMUNICATION_WITH_ONE_S_TEAM_MEMBERS_IS_OF                             = 7656,  -- Communication with one's team members is, of course, one way to locate Rooks. However, another way is by using the Scout command. This will inform a player of the approximate location of the nearest Rook.
        FINALLY_SCOUT_CAN_ONLY_BE_USED_WHEN_A                                   = 7657,  -- Finally, Scout can only be used when a player is carrying a Petra. Because Sprint cannot be used at this time, players must be weary of approaching enemies.
        SO_A_PETRA_HAS_BEEN_OBTAINED_AND_A                                      = 7658,  -- So, a Petra has been obtained and a Rook located. Now all that's left is tossing the stone in, right? Wrong.
        THERE_IS_ONE_ASPECT_OF_BALLISTA_THAT_HAS                                = 7659,  -- There is one aspect of Ballista that has yet to be mentioned...and this is where the real battle begins.
        TO_THROW_A_PETRA_INTO_A_ROOK_A                                          = 7660,  -- To throw a Petra into a Rook, a player must first wait until the Rook's gate is open. This takes impeccable timing, as the gate is only open for a short while.
        BUT_NOT_JUST_ANYONE_CAN_SCORE_POINTS_THIS                               = 7661,  -- But not just anyone can score points this way. A player must first take down a member of the opposing team and achieve Gate Breach status. Only then will his or her shots count.
        THIS_EXTREME_METHOD_OF_COMBAT_IS_WHAT_MADE                              = 7662,  -- This extreme method of combat is what made the ancient game of Ballista famous, and transformed its participants into heroes.
        RUNNING_ABOUT_LOOKING_FOR_STONES_IS_NO_DIFFERENT                        = 7663,  -- Running about looking for stones is no different from a child's game of hide-and-seek. Knowing when to strike is what separates the men from the boys.
        THE_FOLLOWING_MATCH_TYPES_ARE_AREA_SPECIFIC_ALL                         = 7664,  -- The following match types are area-specific: All or Nothing (one match) * Normal Items Allowed: Jugner Forest All or Nothing (one match) * Normal Items Restricted: Pashhow Marshlands Best of Three (three matches) * Normal Items Allowed: Meriphataud Mountains
        BEST_OF_THREE_SERIES_RULES_ARE_AS_FOLLOWS                               = 7665,  -- Best of Three series rules are as follows: Winning a match will earn a nation one match point. The nation with the most match points at the end of the series will be declared the victor. Winning the third and final match and producing the high scorer will result in two match points awarded. This allows both sides the chance for come-from-behind victories.
        BETWEEN_EACH_OF_THE_MATCHES_A_SHORT_INTERVAL                            = 7666,  -- Between each of the matches, a short interval will be implemented. During this interval, Invisible and Sneak will be cast on all participants. We suggest this time be used to discuss strategies with the other members of your nation's forces.
        PLAYERS_WILL_BE_FORBIDDEN_FROM_USING_ANY_ITEMS                          = 7667,  -- Players will be forbidden from using any items they bring to the battlefield. Only temporary items that are quarried may be used. A total of fifteen temporary items (though only one of each type) can be carried.
        WHEN_THIS_RULE_IS_IN_EFFECT_ALL_PLAYERS                                 = 7668,  -- When this rule is in effect, all players will be presented with five complimentary temporary items at the beginning of the match.
        FOR_MORE_INFORMATION_ON_TEMPORARY_ITEMS_REFER_TO                        = 7669,  -- For more information on temporary items, refer to the special rules.
        AFTER_BEING_KO_D_IF_A_PLAYER_CHOOSES                                    = 7670,  -- After being KO'd, if a player chooses to be revived at the spot he was defeated, 100% of all HP and 50% of all MP will be restored. In addition, the player will maintain 50% of the TP he had earned.
        IF_A_PLAYER_CHOOSES_TO_RETURN_TO_THEIR                                  = 7671,  -- If a player chooses to return to their force's camp, HP and MP will be fully restored, but all TP will be lost.
        PLEASE_NOTE_THAT_MANY_OF_THE_RULES_PREVIOUSLY                           = 7672,  -- Please note that many of the rules previously considered special have been fully implemented. Also, several new special rules have been added.
        LEARN_ABOUT_WHICH_SPECIAL_RULES_TEMPORARY_ITEMS_BALLISTA                = 7673,  -- Learn about which special rules? Temporary items. Ballista Points. Scoring restrictions. Gate Breach radius expansion. Resistance to Sleep. Open entries. Minimum level restrictions. Re-entry restrictions. Participant & Rook numbers. Experience Points. Return.
        PREVIOUSLY_PARTICIPANTS_IN_BALLISTA_WERE_REQUIRED_TO_USE                = 7674,  -- Previously, participants in Ballista were required to use an item the moment they dug it up using the /quarry command. However, players can now stock these items as temporary items for use at any time during the match.
        PLAYERS_CAN_HOLD_UP_TO_TEN_TEMPORARY_ITEMS                              = 7675,  -- Players can hold up to ten temporary items, but only one of each type. If a player finds an item that they already possess, they must use it immediately or throw it away.
        IF_PLAYERS_WHO_POSSESS_TEN_TEMPORARY_ITEMS_FIND                         = 7676,  -- If players who possess ten temporary items find an item that they have not already obtained, they will also have the option to exchange it with one of their current items.
        ALSO_PLAYERS_WILL_NOT_AT_ANY_TIME_BE                                    = 7677,  -- Also, players will not, at any time, be allowed to trade temporary items. However, there are items that can be used on other Ballista participants. Please note that players may not be able to use these special items as soon as they are quarried.
        FINALLY_THE_HERALDS_WILL_COLLECT_TEMPORARY_ITEMS_WHEN                   = 7678,  -- Finally, the Heralds will collect temporary items when the match (the third in a Best of Three series) has concluded.
        BALLISTA_POINTS_ARE_REWARDED_TO_EACH_COMPETITOR_BASED                   = 7679,  -- Ballista Points are rewarded to each competitor based on his or her performance in a single Ballista match. The maximum number of points that can be accumulated per match is #.
        WHILE_IT_IS_TAKEN_INTO_CONSIDERATION_SCORING_PETRAS                     = 7680,  -- While it is taken into consideration, scoring Petras is not the only way to earn Ballista Points. Assisting allies and defeating members of the enemy forces can also earn a high score.
        BALLISTA_POINTS_CAN_BE_TRADED_FOR_SPECIAL_VOUCHERS                      = 7681,  -- Ballista Points can be traded for special vouchers, which may be exchanged for free temporary items at the start of new matches.
        HOWEVER_REMEMBER_THAT_DEPENDING_ON_THE_LEVEL_RESTRICTION                = 7682,  -- However, remember that depending on the level restriction of the match, certain vouchers will not be redeemed at the beginning of a match. Speak with a Marshal directly after a match to register your points.
        PLAYERS_WILL_ONLY_BE_ALLOWED_TO_SCORE_UP                                = 7683,  -- Players will only be allowed to score up to five Petras at a time. Also, a player's Gate Breach status will be automatically disengaged if a Petra is not scored within a certain amount of time. The amount of time is increased for those members of the team currently behind in points.
        ALL_ALLIES_WITHIN_A_CERTAIN_RADIUS_WILL_ACHIEVE                         = 7684,  -- All allies within a certain radius will achieve Gate Breach status when a member of the enemy forces is defeated.
        PLAYERS_RESISTANCE_TO_SLEEP_WILL_BE_INCREASED                           = 7685,  -- Players' resistance to sleep will be increased.
        DURING_THE_ENTRY_PERIOD_FROM_ALL_ADVENTURERS_WILL                       = 7686,  -- During the entry period, from #:, all adventurers will be allowed to join the forces with the smallest number of participants, regardless of allegiance. Open entries will be accepted until both sides have reached maximum capacity.
        IN_ORDER_TO_ENSURE_BALANCED_MATCHES_THE_FOLLOWING                       = 7687,  -- In order to ensure balanced matches, the following level limits are enforced: Level 30 matches: 1`30
        LEVEL_40_MATCHES_31_40_LEVEL_50_MATCHES                                 = 7688,  -- Level 40 matches: 31`40 Level 50 matches: 41`50 Level 60 matches: 51`60 Unrestricted matches: 61`
        PLEASE_NOTE_THAT_ANY_PARTICIPANT_WHO_CANCELS_HIS                        = 7689,  -- Please note that any participant who cancels his or her registration will not be allowed to re-apply for the same match.
        WHEN_THE_TOTAL_NUMBER_OF_PARTICIPANTS_IN_A                              = 7690,  -- When the total number of participants in a match is less than 40, the location of the two camps will be adjusted. Also in this case, the number of Rooks will be reduced to two.
        ANY_ADVENTURER_WHOSE_MAIN_LEVEL_IS_OVER_30                              = 7691,  -- Any adventurer whose main level is over 30 will receive EXP for participating in a Ballista match. However, no EXP will be rewarded if the adventurer fails to actively take part in the match.
        READ_WHICH_CHAPTER_ON_B_P_RANKING_BASIC                                 = 7692,  -- Read which chapter on B.P. Ranking? Basic Information. Registering Points. Rewards. Chevron & Title List. None.
        BALLISTA_POINT_RANKING_IS_BASED_UPON_ALL_BALLISTA                       = 7693,  -- Ballista Point Ranking is based upon all Ballista Points registered from the past ten matches in each of the three participating battle areas.
