        PLEASE_ACCEPT_THIS                                                      = 11560,  -- Please accept this.
        HMM_I_KNOW_NOT                                                          = 11561,  -- Hmm...I know not.
        WELCOME_TO_THE_SAN_D_ORIA_CATHEDRAL                                     = 11562,  -- Welcome to the San d'Oria Cathedral.
        WE_WILL_DO_ANYTHING_IN_OUR_POWER_TO                                     = 11563,  -- We will do anything in our power to see everyone through the gates of Paradise.
        HELLO_THERE                                                             = 11564,  -- Hello there!
        WELCOME                                                                 = 11565,  -- Welcome!
        NOTHING_TO_REPORT_2                                                     = 11566,  -- Nothing to report!
        MAY_THE_GATES_OF_PARADISE_OPEN_TO_ALL                                   = 11567,  -- May the Gates of Paradise open to all San d'Orians!
