        WELCOME_TO_THE_CARPENTERS_GUILD_SHOP                                    = 11577,  -- Welcome to the Carpenters' Guild shop!
        LOOKING_FOR_SOMETHING_IN_PARTICULAR                                     = 11578,  -- Looking for something in particular?
        WELCOME_TO_THE_BLACKSMITHS_GUILD_SHOP                                   = 11579,  -- Welcome to the Blacksmiths' Guild shop.
