        TRULY_I_BEGGED_A_THOUSAND_TIMES_YET_ALWAYS                              = 12440,  -- Truly? I begged a thousand times, yet always the answer was no.
        YEAH_OF_COURSE_ON_ONE_CONDITION                                         = 12441,  -- Yeah, of course. On one condition...
