        YEAH_YOU_HAVE_TO_BRING                                                  = 12443,  -- Yeah. You have to bring %.
        WHAT_YOU_ASK_THE_IMPOSSIBLE_HOW_IS_A                                    = 12444,  -- What? You ask the impossible! How is a child like me supposed to catch %?
        WELL_DUH_JUST_ASK_YOUR_DAD_HE_S                                         = 12445,  -- Well, duh. Just ask your dad. He's a captain of the Royal Knights, after all.
        I_DON_T_KNOW                                                            = 12446,  -- I don't know...
