        YOU_SEE_MY_MOTHER_WAS_KILLED_BY_ORCS                                    = 12462,  -- You see, my mother was killed by Orcs. My father was there, but he couldn't save her.
        HE_BLAMED_HER_DEATH_ON_THE_QUALITY_OF                                   = 12463,  -- He blamed her death on the quality of his armor and weapons. He gave up practicing swordsmanship every morning, and spends all his time scouring the shops for equipment.
        HE_IS_NEEDED_IN_THE_EXPEDITIONS_BUT_ALWAYS                              = 12464,  -- He is needed in the expeditions, but always he declines due to a supposed sickness or insufficiencies in equipment. I fear he will lose his rank as captain.
        I_AM_SURE_A_KNIGHT_OF_MY_FATHER                                         = 12465,  -- I am sure a knight of my father's stature could soon get me %. How can I go fishing now?
