        BEHOLD_THE_BEAUTY_OF_THIS_CATHEDRAL_WE_FAILED                           = 12489,  -- Behold the beauty of this cathedral. We failed to protect it once, but never again.
        NARCHERAL_I_BRING_NEWS                                                  = 12490,  -- Narcheral, I bring news!
        WHAT_ARE_YOU_CERTAIN                                                    = 12491,  -- What!? Are you certain?
