        ADVENTURER_I_HAVE_A_REQUEST_DEPART_AT_ONCE                              = 12495,  -- Adventurer, I have a request. Depart at once for the western borders of Valkurm Dunes. Find the messenger of the dark stalkers there, but only at night.
        DEFEAT_THE_DARK_STALKER_AND_TAKE_ITS                                    = 12496,  -- Defeat the dark stalker and take its %.
