        MY_NAME_IS_ROCHEFOGNE_AND_I_AM_AN                                       = 12506,  -- My name is Rochefogne, and I am an adventurer, too. I have just arrived at San d'Oria...
        AND_ALREADY_I_AM_STRUCK_AT_HOW_LITTLE                                   = 12507,  -- And already I am struck at how little has changed! Time has no dominion over this city.
