        YOU_HAVE_MY_ETERNAL_THANKS_FOR_SAVING_TEDIMOUT                          = 12573,  -- You have my eternal thanks for saving Tedimout!
        THANK_YOU                                                               = 12574,  -- Thank you, %!
        ALL_I_CAN_DO_IS_PRAY_FOR_ADVENTURERS                                    = 12575,  -- All I can do is pray for adventurers. Please, let me pray for you, too.
