        HOW_DARE_YOU_EAVESDROPPING_ON_THE_PAPSQUE_AS                            = 12584,  -- How dare you! Eavesdropping on the papsque as he entertains the prince!
        NO_IT_IS_ALL_RIGHT_YOUR_HOLINESS                                        = 12585,  -- No, it is all right, Your Holiness.
        YOU_CAME_TO_DELIVER_THE_REPORT_YES_WELL                                 = 12586,  -- You came to deliver the report, yes? Well, let us see it.
        SO_THE_ORCS_ARE_SEARCHING_FOR_SOMETHING_WHAT                            = 12587,  -- So... The Orcs are searching for something. What it is we cannot say. This requires further delving.
        HMPH                                                                    = 12588,  -- Hmph.
