        I_IMPLORE_YOU_TO_MAKE_HASTE_TO_KING                                     = 12617,  -- I implore you to make haste to King Ranperre's Tomb. You may find proof of grave-robbers there.
        BUT_WANDER_TOO_DEEPLY_WITHIN_AND_GOBLINS_MIGHT                          = 12618,  -- But wander too deeply within, and Goblins might find you. Tread boldly, my friend, but do not go in over your head!
        VISITORS_REPORT_MISSING_GRAVESTONES_AND_SHADOWS_TWISTING_IN_2           = 12619,  -- Visitors report missing gravestones and shadows twisting in the caverns. Scour the tomb and determine if they speak the truth.
        MAKE_HASTE_TO_KING_RANPERRE_S_TOMB_YOU                                  = 12620,  -- Make haste to King Ranperre's Tomb. You may find proof of grave-robbers there.
        HAVE_YOU_REALLY_SEARCHED_THE_TOMB                                       = 12621,  -- Have you really searched the tomb?
        SO_YOU_GOT_THIS_FROM_BATS_IN_KING                                       = 12622,  -- So, you got this from bats in King Ranperre's Tomb?
        YOU_SEE_THIS_ACTUALLY_BELONGED_TO_AN_ORC                                = 12623,  -- You see, this actually belonged to an Orc. What could Orcs want with the tomb?
        AT_ANY_RATE_YOUR_MISSION_IS_OVER_SPEAK                                  = 12624,  -- At any rate, your mission is over. Speak not a word of this to another.
        AH_THE_RECRUIT_S_BACK_AGAIN_I_M_2                                       = 12625,  -- Ah, the recruit's back again? I'm sorry, but I've no time for you today.
        I_KNOW_YOU_CAME_ALL_THIS_WAY_BUT                                        = 12626,  -- I know you came all this way, but I can't help you right now.
        OH_WHO_AM_I_FOOLING_OF_COURSE_I                                         = 12627,  -- Oh, who am I fooling? Of course I could use your help!
        HAVE_YOU_NOT_HEARD_ORCS_CAME_AND_KIDNAPPED                              = 12628,  -- Have you not heard? Orcs came and kidnapped some children! We think they're keeping them at their lair in Ghelsba.
        WHY_NOT_LONG_AGO_CAME_ILL_NEWS_FROM                                     = 12629,  -- Why, not long ago came ill news from the cathedral. A boy training to be a friar went near Ghelsba and did not return. His name was Tedimout.
