        AS_A_SPECIAL_LIMITED_TIME_SERVICE_TO_COMMEMORATE                        = 13052,  -- As a special, limited-time service to commemorate the recovery of the full mog tablet set, I can teleport you to your destination absolutely free of charge!
        TELEPORT_YES_TELEPORT_WITH_GIL_TELEPORT_WITH_CONQUEST                   = 13053,  -- Teleport? Yes. Teleport with gil. Teleport with conquest points. Later.
        HAVE_A_WONDERFUL_JOURNEY                                                = 13054,  -- Have a wonderful journey!
        UNFORTUNATELY_AT_THIS_TIME_THERE_IS_NOWHERE_I                           = 13055,  -- Unfortunately, at this time there is nowhere I can teleport you. Please come again.
        YOU_HAVE_NOT_YET_REACHED_LEVEL_10_I                                     = 13056,  -- You have not yet reached level 10. I am sorry, but for safety reasons, I am not authorized to teleport anyone under the current level cap.
        YOU_DO_NOT_HAVE_ENOUGH_GIL_PLEASE_COME                                  = 13057,  -- You do not have enough gil. Please come back again.
        YOU_DO_NOT_HAVE_ENOUGH_GIL_3                                            = 13058,  -- You do not have enough gil.
        YOU_DO_NOT_HAVE_ENOUGH_CONQUEST_POINTS_PLEASE                           = 13059,  -- You do not have enough conquest points. Please come back again.
        YOU_DO_NOT_HAVE_ENOUGH_CONQUEST_POINTS                                  = 13060,  -- You do not have enough conquest points.
        WE_LOOK_FORWARD_TO_SEEING_YOU_AGAIN                                     = 13061,  -- We look forward to seeing you again!
        HOWEVER_AT_THIS_TIME_I_AM_ONLY_AUTHORIZED                               = 13062,  -- However, at this time I am only authorized to teleport citizens of [San d'Oria/Bastok/Windurst].
        DEBUG_WARP_TO_REGION                                                    = 13063,  -- Debug: Warp to region #!
        FOR_A_LIMITED_TIME_DURING_THE_STARLIGHT_CELEBRATION                     = 13064,  -- For a limited time during the Starlight Celebration, the Specialty Goods Trade Union is offering all registered adventurers a deal you could not possibly think of passing up.
        TRADE_ME_A_MERE_TEN_AND_I_WILL                                          = 13065,  -- Trade me a mere ten % and I will teleport you to the outpost of any region of your choice, regardless of your current level or which nation has control of the area.
        HOWEVER_REMEMBER_THAT_THE_S_G_T_U                                       = 13066,  -- However, remember that the S.G.T.U will take no responsibility for any...unexpected circumstances that may occur as a result of teleporting to an area with enemies beyond the range of your main job's level.
        NORMALLY_I_AM_ONLY_AUTHORIZED_TO_TELEPORT_CITIZENS                      = 13067,  -- Normally, I am only authorized to teleport citizens of [San d'Oria/Bastok/Windurst], but for a limited time only, my services are open to all registered adventurers.
        TRADE_ME_A_MERE_TEN_AND_I_WILL_2                                        = 13068,  -- Trade me a mere ten % and I will teleport you to the outpost of any region of your choice, regardless of your current level or which nation has control of the area.
        HOWEVER_REMEMBER_THAT_THE_S_G_T_U_2                                     = 13069,  -- However, remember that the S.G.T.U will take no responsibility for any...unexpected circumstances that may occur as a result of teleporting to an area with enemies beyond the range of your main job's level.
        THIS_SERVICE_WILL_LAST_FOR_THE_DURATION_OF                              = 13070,  -- This service will last for the duration of the Starlight Celebration.
        THANK_YOU_VERY_MUCH_FOR_TAKING_PART_IN                                  = 13071,  -- Thank you very much for taking part in our holiday special!
        IF_I_REMEMBER_CORRECTLY_YOU_JUST_MADE_YOUR                              = 13072,  -- If I remember correctly, you just made your payment a few moments ago.
        I_APOLOGIZE_SIR_MA_AM_YOU_HAVE_NOT                                      = 13073,  -- I apologize, sir/ma'am]. You have not completed any supplies quests, thus there are no regions to which I am authorized to teleport you.
        THE_RECOMMENDED_LEVEL_FOR_THE_REQUESTED_AREA_IS                         = 13074,  -- The recommended level for the requested area is #. Are you sure you would like to teleport there?
        YOUR_TEN_ARE_RETURNED_TO_YOU                                            = 13075,  -- Your ten % are returned to you.
        YOUR_INVENTORY_IS_FULL_AND_YOU_CANNOT_CARRY                             = 13076,  -- Your inventory is full and you cannot carry the %. Come back when you have created more room in your bag.
        HERE_YOU_CAN_LEARN_THE_FATE_AND_FORTUNE                                 = 13077,  -- Here you can learn the fate and fortune of an adventuring duo.
        FOR_A_MERE_120_GIL_I_WILL_DIVINE                                        = 13078,  -- For a mere 120 gil, I will divine what today will bring for you and %.
        PAY_120_GIL_FOR_A_FORTUNE_TELLING_PAY                                   = 13079,  -- Pay 120 gil for a fortune telling? Pay up. I make my own fortune.
        NOW_LET_US_SEE_WHAT_THE_WINDS_PORTEND                                   = 13080,  -- Now, let us see what the winds portend...
        ADVENTURING_WITH_TODAY_WILL                                             = 13081,  -- Adventuring with % today will [bring you great fortune!/be highly profitable./bring fair fortune./be mutually advantageous./bring misfortune./be perilous./be disastrous!]
        GOOD_FORTUNE_FILLS_YOUR_CUP_TO_OVERFLOWING_BE                           = 13082,  -- Good fortune fills your cup to overflowing. Be sure to share it with those less blessed by fate.
        STAND_TOGETHER_AND_YOU_HAVE_LITTLE_TO_FEAR                              = 13083,  -- Stand together and you have little to fear. With your combined strength, you can overcome any obstacle.
        DO_NOT_LET_YOUR_GOOD_FORTUNE_BLIND_YOU                                  = 13084,  -- Do not let your good fortune blind you to danger. Pitfalls aplenty await the unwary traveler.
        HAPPINESS_IS_A_STATE_OF_MIND_YOU_CAN                                    = 13085,  -- Happiness is a state of mind. You can find laughter in even the most desperate of situations.
        THE_DAY_AHEAD_WILL_BE_FILLED_WITH_TRIALS                                = 13086,  -- The day ahead will be filled with trials and tribulations, but in time the path before you will run smooth once more.
        THERE_MAY_BE_CLASHES_OF_OPINION_TODAY_BUT                               = 13087,  -- There may be clashes of opinion today, but approach each other with an open mind and all will be well.
        YOU_MUST_RELY_ON_EACH_OTHERS_STRENGTHS_TO                               = 13088,  -- You must rely on each others' strengths to overcome the difficulties you will face today. Don't let petty squabbles bring your downfall.
        PLEASE_ACCEPT_THIS_MODEST_GIFT_IN_CELEBRATION_OF                        = 13089,  -- Please accept this modest gift in celebration of your good fortune.
        EITHER_YOU_OR_HAS_ALREADY_HEARD_FATE_S                                  = 13090,  -- Either you or % has already heard fate's fickle will today. You may only have your fortune told once every Vana'dielian day.
        FORM_A_PARTY_WITH_THE_PERSON_YOU_WISH                                   = 13091,  -- Form a party with the person you wish to check your fortune with, and then speak with me for a reading of your fate.
        YOU_NEED_120_GIL_TO_HAVE_YOUR_FORTUNE                                   = 13092,  -- You need 120 gil to have your fortune told.
        TRICK_OR_TREAT                                                          = 13093,  -- Trick or treat...
        THANK_YOU_AND_NOW_FOR_YOUR_TREAT                                        = 13094,  -- Thank you... And now for your treat...
        HERE_TAKE_THIS                                                          = 13095,  -- Here, take this...
        IF_YOU_PUT_THIS_ON_AND_WALK_AROUND                                      = 13096,  -- If you put this on and walk around, something...unexpected might happen...
        THANK_YOU_2                                                             = 13097,  -- Thank you...
        IF_TWO_PEOPLE_WITH_THE_SAME_COSTUMES_FORM                               = 13098,  -- If two people with the same costumes form a party and approach a bomb balloon, then...
        PEOPLE_ARE_WALLOWING_IN_SIN_THERE_ARE_SO                                = 13099,  -- People are wallowing in sin... There are so many weak-spirited heathens who cannot go a day without lying, cheating, or stealing from their fellows.
        AND_STILL_THERE_ARE_OTHER_INSATIABLE_FOOLS_WHO                          = 13100,  -- And still there are other insatiable fools who crave forbidden fruit and violate our holy law with abandon. Yet for the Gates of Paradise to open, we must reach out a forgiving hand to these deluded wretches.
        AND_NOW_LET_US_ASSUME_AN_ITEM_THOU                                      = 13101,  -- And now... Let us assume an item thou hast obtained in your lust for material possession has been warped by the wrath of the spirits.
        THESE_ITEMS_ARE_IN_A_CURSED_STATE_USELESS                               = 13102,  -- These items are in a cursed state. Useless items that, if left to their own devices, will bring down upon thee a terrible fate. That curse shall remain until the spirits are appeased by the acquisition of an abjuration.
        AN_ABJURATION_IS_THE_ONE_AND_ONLY_KEY                                   = 13103,  -- An abjuration is the one and only key capable of quieting the spirits and removing the curse. It requires great hardship and suffering to obtain one; however, this penance is necessary for the cleansing of thy soul.
        IF_THOU_BRINGST_UNTO_ME_A_CURSED_ITEM                                   = 13104,  -- If thou bringst unto me a cursed item and its opposing abjuration, I shall invoke the blessing of the Goddess and remove thy curse.
        THOU_NEEDST_NOT_HASTEN_THY_STEPS_WHEN_THE                               = 13105,  -- Thou needst not hasten thy steps. When the time is right, thou shalt hear more of curses and abjurations.
        UNTIL_THAT_TIME_IT_IS_BEST_THAT_THOU                                    = 13106,  -- Until that time, it is best that thou forgettest what thou hast learned and be on thy way. May the Gates of Paradise open unto thee.
        THIS_IS_MOST_UNFORTUNATE_HOWEVER_IF_THOU_HAST                           = 13107,  -- This is most unfortunate... However, if thou hast not the appropriate abjuration to counter the curse, then I may not perform the purification ceremony. When thou hast obtained the abjuration, come once again to my side.
        VERILY_THIS_IS_THE_ABJURATION_THAT_IS_REQUIRED                          = 13108,  -- Verily, this is the abjuration that is required. Thou hast done well. If thou bringst the opposing cursed item, I shall perform the purification ceremony forthwith.
        HMM_AH_MY_APOLOGIES_I_WAS_LOST_IN                                       = 13109,  -- Hmm? Ah, my apologies, I was lost in thought. Was there something I could aid you with, my child?
        PRAISE_TO_THE_GODDESS_THOU_HAST_SAFELY_RETURNED                         = 13110,  -- Praise to the Goddess! Thou hast safely returned from the trial of the spirits. Let us perform the purification ceremony at once. At my urging, raise thy hand in supplication to the heavens.
        GREAT_GODDESS_ALTANA_IN_RECOGNITION_OF_THE_PENANCE                      = 13111,  -- Great Goddess Altana. In recognition of the penance % has paid, I beg thee to remove the blight upon the % and absolve % of his/her] sin...
        THE_BLIGHT_UPON_THE_IS_WEAKENING_IT_HAS                                 = 13112,  -- The blight upon the % is weakening... It has been transformed into %!
        THY_SUFFERING_HATH_BEEN_REWARDED_PROOF_OF_THY                           = 13113,  -- Thy suffering hath been rewarded. Proof of thy redemption lies in the % before thee. Thou hast been blessed, %.
        CONTINUE_THY_JOURNEY_INTO_THE_LIGHT_MAY_THE                             = 13114,  -- Continue thy journey into the light. May the Gates of Paradise open unto thee.
        WHAT_IS_THE_MEANING_OF_THIS_DOST_THOU                                   = 13115,  -- What is the meaning of this? Dost thou propose to insult a cardinal of Altana? If thou persists in this tomfoolery, I shall be forced to call upon the Temple Knights to teach thee some manners...
        SIR_LADY_MUCH_I_HAVE_HEARD_OF_YOUR                                      = 13116,  -- Sir/Lady] %! Much I have heard of your noble efforts on the battlefield. If it is not too much of a bother, your assistance is requested for a special mission.
        THE_MISSION_REQUIRES_ESCORTING_THE_NOBLE_YOUNG_MISSUS                   = 13117,  -- The mission requires escorting the noble young missus Lady Cannau, the only daughter of a highly respectable family. However, she is--how would you say--a tad rambunctious. Embarrassed I am to report that we have already had many a proud adventurer quit this task the moment they met her.
        IF_YOU_HAVE_COURAGE_ENOUGH_TO_TAKE_ON                                   = 13118,  -- If you have courage enough to take on this adventure, travel to the Eldieme Necropolis. Whether Lady Cannau is there or not is another question...
        YOU_SHALL_BE_COMPENSATED_GENEROUSLY_UPON_THE_COMPLETION                 = 13119,  -- You shall be compensated generously upon the completion of your task. Good luck and Godspeed.
        YOU_SHALL_FIND_MISS_CANNAU_IN_THE_ELDIEME                               = 13120,  -- You shall find Miss Cannau in the Eldieme Necropolis. That is, if you are lucky enough to spot her...
        WAIT_ARE_YOU_TO_SAY_THAT_YOU_WISH                                       = 13121,  -- Wait... Are you to say that you wish to cancel your contract with us?
        CANCEL_YOUR_CONTRACT_YES_NO                                             = 13122,  -- Cancel your contract? Yes. No.
        I_SEE_THAT_IS_QUITE_DISAPPOINTING                                       = 13123,  -- I see... That is quite disappointing...
        AH_I_HEARD_FROM_MY_MEN_THAT_YOU                                         = 13124,  -- Ah, I heard from my men that you have been successful in escorting the missus. I applaud you on your composure throughout the task.
        SIGH_I_HAVE_THE_FEELING_THIS_MAY_NOT                                    = 13125,  -- <Sigh> I have the feeling this may not be the last time the missus goes galavanting about the necropolis. When that time comes, again we may require your assistance.
        FORGET_NOT_THE_LABORS_OF_THE_COMMON_FOLK                                = 13126,  -- Forget not the labors of the common folk, as they ever support this mighty kingdom.
        IT_S_TIME_FOR_THE_EGG_HUNT_EGG                                          = 13127,  -- It's time for the Egg Hunt Egg-stravaganza, kupo! Here, take this initial egg. Collect and trade eggs until you have made a First 3 combination. When you're done, bring the combo back to me for an egg-squisite prize, kupo!
        THIS_YEAR_THOSE_WHO_MAKE_SPECIAL_UNDECENNIAL_COMBINATIONS               = 13128,  -- This year, those who make special undecennial combinations will receive particularly egg-ceptional prizes, kupo!
        OF_COURSE_WE_WOULDN_T_WANT_YOU_COUNTING                                 = 13129,  -- Of course, we wouldn't want you counting your chocobos before they hatch. Please egg-xert the effort to make a First 3 combination before going all out on these spegg-tacular new ones, kupo.
        WHEN_YOU_VE_GATHERED_A_FIRST_3_COMBINATION                              = 13130,  -- When you've gathered a First 3 combination, bring the eggs back to me! Also, if you want, I can trade you more initial eggs, but you'll have to make it worth my while, kupo!
        WELL_THAT_S_IT_FOR_MY_ANNIVERSARY_EGG                                   = 13131,  -- Well, that's it for my anniversary egg-splanation. Happy hunting, kupo!
        EGG_CELLENT_HERE_S_YOUR_PRIZE_KUPO_NOW                                  = 13132,  -- Egg-cellent! Here's your prize, kupo! Now if only somebody would bring me a super combo... Oh, egg-scuse me! Forget I said that, kupo!
        EGG_STRAORDINARY_HERE_S_YOUR_SPECIAL_PRIZE_KUPO                         = 13133,  -- Egg-straordinary! Here's your special prize, kupo! But how did you figure out the secret combination...?
        HOW_IN_EGGS_PLICABLY_ASTOUNDING_YOU_RE_TRULY                            = 13134,  -- How in-eggs-plicably astounding! You're truly a hard-boiled detective of the highest degree, kupo! Here's your prize, and don't forget to enjoy the rest of the festivities.
        HEY_DON_T_GET_ALL_EGG_CITED_YOU                                         = 13135,  -- Hey, don't get all egg-cited! You can only claim one prize a day, kupo!
        THESE_INITIAL_EGGS_ARE_REALLY_EGG_SPENSIVE_KUPO                         = 13136,  -- These initial eggs are really egg-spensive, kupo! If you want one I'm going to need a little more incentive. No egg-ceptions!
        EGGS_ACTLY_WHAT_I_WANTED_HERE_S_YOUR                                    = 13137,  -- Eggs-actly what I wanted! Here's your reward, kupo!
        KU_KUPO_SUCH_AN_EGG_STRAVAGANT_ITEM_FOR                                 = 13138,  -- Ku-kupo! Such an egg-stravagant item, for little old me? Here's a whole basketful of initial eggs for you, kupo!
        MY_EYES_MY_EYES_GET_OUT_OF_HERE                                         = 13139,  -- My eyes! My eyes! Get out of here, and take those egg-ceptionally nasty things with you, kupo!
        KUPO_KUPO_PLEASE_NO_MORE_KUPO_HERE_TAKE                                 = 13140,  -- Kupo... Kupo```! Please! No more, kupo! Here, take these and get out of here, kupo!
        HEY_I_CAN_ONLY_TRADE_WITH_YOU_ONCE                                      = 13141,  -- Hey, I can only trade with you once a day. We wouldn't want to make the egg hunt over easy, now, kupo!
        HEY_YOU_LOOK_NEW_HERE_KUPO_IF_YOU                                       = 13142,  -- Hey, you look new here, kupo! If you need anything, just let me know!
        HEH_HEH_HEH_I_HAVE_SOMETHING_EGG_SPECIALLY                              = 13143,  -- Heh heh heh... I have something egg-specially egg-citing in store for you, kupo!
        AND_BECAUSE_YOU_RE_AS_COOL_AS_EGG                                       = 13144,  -- And, because you're as cool as egg salad/as hot as a fried egg, sunny-side up], I'm going to give you a super-duper present, kupo!
        TAKE_ANY_ONE_YOU_WANT_AN_A_EGG                                          = 13145,  -- Take any one you want! An "A" egg. A "B" egg. A "C" egg. A "D" egg. An "E" egg. An "F" egg. A "G" egg. An "H" egg. An "I" egg. A "J" egg. A "K" egg. An "L" egg. An "M" egg. An "N" egg. An "O" egg. A "P" egg. A "Q" egg. An "R" egg. An "S" egg. A "T" egg. A "U" egg. A "V" egg. A "W" egg. An "X" egg. A "Y" egg. A "Z" egg. Forget it.
        THERE_ARE_NO_PARTY_MEMBERS                                              = 13146,  -- There are no party members.
        KU_PO_I_CAN_T_EGG_CEPT_SUCH                                             = 13147,  -- Ku.........po! I can't egg-cept such a rare item. You should take more care of your belongings, kupo!
        GOOD_DAY_SIR_MA_AM_I_AM_WITH                                            = 13148,  -- Good day, sir/ma'am]. I am with the Adventurers' Mutual Aid Network (AMAN) and am now taking applications for new mentors.
        WHAT_IS_A_MENTOR_YOU_ASK_WELL_IN                                        = 13149,  -- What is a mentor, you ask? Well, in short, a mentor is an experienced adventurer who is willing to offer some of their time to help out their less traveled companions.
        IF_THIS_SOUNDS_LIKE_THE_JOB_FOR_YOU                                     = 13150,  -- If this sounds like the job for you, then feel free to sign up today.
        TO_BECOME_A_MENTOR_YOU_MUST_HAVE_COMPLETED                              = 13151,  -- To become a mentor, you must have completed the Records of Eminence objective %.
        ACCEPTING_REQUIRES_THAT_YOU_HAVE_OVER_180_HOURS                         = 13152,  -- Accepting % requires that you have over 180 hours of play time...
        AND_HAVE_COMPLETED_THE_RECORDS_OF_EMINENCE_OBJECTIVE                    = 13153,  -- ...and have completed the Records of Eminence objective %.
        PLEASE_NOTE_THAT_REGISTERING_AND_SERVING_AS_A                           = 13154,  -- Please note that registering and serving as a mentor, as well as utilizing the services of the Mentor Program, are to be done at the player's own discretion.
        SQUARE_ENIX_WILL_NOT_BE_HELD_RESPONSIBLE_FOR                            = 13155,  -- SQUARE ENIX will not be held responsible for the actions and/or comments of any mentors. No benefits of any kind will be provided to those who choose to participate in the Mentor Program.
        WHEN_YOU_AGREE_TO_PARTICIPATE_IN_THE_MENTOR                             = 13156,  -- When you agree to participate in the Mentor Program, you are acknowledging that you have read and understood the above terms.
        I_AM_SORRY_BUT_YOU_DO_NOT_MEET                                          = 13157,  -- I am sorry, but you do not meet the requirements necessary to accept the Records of Eminence objective %.
        PLEASE_SPEAK_TO_ME_AGAIN_ONCE_YOU_HAVE                                  = 13158,  -- Please speak to me again once you have accepted %. I will then judge whether or not you meet the requirements.
        YOU_HAVE_ACCEPTED_YES_THEN_LET_ME_CHECK                                 = 13159,  -- You have accepted %, yes? Then let me check my materials here...
        CONGRATULATIONS_YOU_ARE_QUALIFIED_TO_BE_A_MENTOR                        = 13160,  -- Congratulations! You are qualified to be a mentor!
        MY_MATERIALS_HERE_SAY_THAT_YOU_DON_T                                    = 13161,  -- My materials here say that you don't meet the requirements. Keep at it!
        WOULD_YOU_LIKE_TO_SERVE_AS_A_MENTOR                                     = 13162,  -- Would you like to serve as a mentor? Yes. No.
        YOU_ARE_NOW_A_REGISTERED_MENTOR                                         = 13163,  -- You are now a registered mentor.
        YOU_CAN_ENABLE_MENTOR_STATUS_BY_USING_THE                               = 13164,  -- You can enable "Mentor Status" by using the command /mentor on. You can disable the status by using /mentor off.
        MENTOR_STATUS_CAN_ALSO_BE_SWITCHED_ON_AND                               = 13165,  -- Mentor status can also be switched on and off in the Config menu found within the Help Desk.
        YOU_ARE_ALREADY_A_REGISTERED_MENTOR                                     = 13166,  -- You are already a registered mentor.
        A_NEW_OBJECTIVE_HAS_BEEN_ADDED_TO_RECORDS                               = 13167,  -- A new objective, %, has been added to Records of Eminence.
        YOU_WANT_TO_KNOW_ABOUT_MANNEQUINS_HA_HA                                 = 13168,  -- You want to know about mannequins? Ha ha, there's a word I haven't heard in quite a long time. What would a young adventurer such as yourself want with such an outdated piece?
        WELL_I_M_NOT_ONE_TO_JUDGE_PEOPLE                                        = 13169,  -- Well, I'm not one to judge people on their tastes. Yes, there was a time when we here at the Carpenters' Guild manufactured nearly all of the mannequins in the Kingdom. They were our best sellers.
        WHY_THAT_CATALOG_YOU_HAVE_THERE_THAT_WAS                                = 13170,  -- Why, that catalog you have there--that was one of many published and printed by us.
        WE_HAD_SO_MANY_ORDERS_THAT_WE_HAD                                       = 13171,  -- We had so many orders that we had to work twenty-five hours a day to keep up. That is, until the accident...
        HMPH_I_CAN_TELL_BY_THE_LOOK_ON                                          = 13172,  -- Hmph. I can tell by the look on your face that you wish for me to continue. Very well...
        THERE_WAS_TO_BE_A_GRAND_FASHION_SHOW                                    = 13173,  -- There was to be a grand fashion show held by the Weavers' Guild in Windurst, and they needed a large quantity of mannequins to display all their new clothes and armor.
        IT_WAS_AN_ENORMOUS_UNDERTAKING_HOWEVER_HONORED_TO                       = 13174,  -- It was an enormous undertaking. However, honored to receive such a tremendous order from the Federation, the guildmaster at the time accepted the challenge without hesitation.
        AND_AS_PROMISED_THE_GUILD_FINISHED_ALL_OF                               = 13175,  -- And, as promised, the guild finished all of the beautifully constructed mannequins within the allotted time frame and sent them off to Windurst.
        HOWEVER_AS_THE_SHIPMENT_WAS_BEING_CARRIED_DOWN                          = 13176,  -- However, as the shipment was being carried down the Phanauet Channel through Jugner Forest, the ferry was attacked by beastmen. The fiends must have thought the ship was a transport vessel for knights and supplies.
        THE_FEW_ADVENTURERS_THAT_ACCOMPANIED_THE_SHIP_WERE                      = 13177,  -- The few adventurers that accompanied the ship were no match for the enemy, and the ship and her cargo were lost...
        DAYS_LATER_OUR_GUILD_RECEIVED_A_MESSAGE_FROM                            = 13178,  -- Days later, our guild received a message from Windurst saying that they refused to pay for the stolen mannequins, going as far as citing our negligence in guarding the shipment as justification. Outraged by this blatant breach of contract, our guild continued to demand payment. This feud of sorts lasted for years.
        BUT_THAT_WAS_NOT_THE_ONLY_PROBLEM_THAT                                  = 13179,  -- But that was not the only problem that arose from the accident... Weeks after the attack, the beastmen began throwing the arms, legs, and heads of their prizes over our town walls and into our streets. It was as if they were bragging of their victory.
        SEEING_THIS_FILLED_THE_HEARTS_OF_THE_TOWNSPEOPLE                        = 13180,  -- Seeing this filled the hearts of the townspeople with fear. Mannequins soon became a symbol of ill fate, and those that remained in shops and guilds were destroyed.
        AS_A_CRAFTSMAN_IT_PAINS_ME_TO_KNOW                                      = 13181,  -- As a craftsman, it pains me to know that idle superstition has taken such a precedence over fine work. And that is why, as a craftsman, I give my full support to anyone who wishes to recreate such a product. Unfortunately, our guild no longer has any of the materials needed for building a mannequin, nor do I know of one who possesses the skill to construct the pieces necessary.
        AH_BUT_I_DO_HAVE_SOMETHING_THAT_MAY                                     = 13182,  -- Ah, but I do have something that may be of use to you. The goldsmith that constructed the joints for our mannequins left these diagrams. They are of no use to me... Perhaps if a goldsmith were to view them, the plans might give some sort of clue as to their manufacture.
        I_CAN_ALSO_TELL_YOU_THAT_IN_ADDITION                                    = 13183,  -- I can also tell you that in addition to the joints, the following parts were needed to complete a mannequin: %, %, %, %, and %.
        HOWEVER_YOU_WON_T_FIND_ANY_OF_THOSE                                     = 13184,  -- However, you won't find any of those items up on auction. Their sale has been prohibited ever since the accident. If there are any left, they'd be in the hands of the beastmen themselves.
        ARE_YOU_READY_FOR_A_SPINE_CHILLING_STOMACH                              = 13185,  -- Are you ready for a spine-chilling, stomach-churning test of your mettle, kupo!?
        WE_VE_SET_UP_A_SECRET_MARKER_SOMEWHERE                                  = 13186,  -- We've set up a secret marker somewhere in the bowels of a dreadful dungeon. Your goal is to reach that marker alive, kupo!
        OH_A_NEW_ADVENTURER_BEST_OF_LUCK_KUPO                                   = 13187,  -- Oh, a new adventurer! Best of luck, kupo!
        ARE_YOU_HELPING_OUT_THE_NEW_ADVENTURERS_BEST                            = 13188,  -- Are you helping out the new adventurers? Best of luck in your endeavors, kupo!
        YOU_RE_NOT_WEARING_YOUR_YUKATA_PUT_IT                                   = 13189,  -- You're not wearing your yukata! Put it on and show me how it looks, kupo!
        HERE_S_YOUR_REWARD_FOR_REACHING_THE_GOAL                                = 13190,  -- Here's your reward for reaching the goal, kupo!
        WEAR_THE_YUKATA_THE_NEXT_TIME_YOU_COME                                  = 13191,  -- Wear the yukata the next time you come to see me! I can't wait to see how you look, kupo!
        PARTNER_UP_WITH_LOTS_OF_DIFFERENT_ADVENTURERS_AND                       = 13192,  -- Partner up with lots of different adventurers and bring back all kinds of trophies to prove your courage! When you've brought enough, I'll give you something really special, kupo!
        THE_FACE_IN_THE_PORTRAIT_YOU_BROUGHT_ME                                 = 13193,  -- The face in the portrait you brought me is just... Kupupupu!
        INCREDIBLE_KUPO_YOU_MUST_HAVE_NERVES_OF_DARKSTEEL                       = 13194,  -- Incredible, kupo! You must have nerves of darksteel! Here, you've earned this, kupo!
        YOU_TOOK_ANOTHER_DIVE_INTO_THE_DREADED_DUNGEON                          = 13195,  -- You took another dive into the dreaded dungeon, kupo? Well, you deserve a little something for your preternatural perseverance, kupo.
        YOU_HAVEN_T_EARNED_MY_REALLY_SPECIAL_PRESENT                            = 13196,  -- You haven't earned my really special present yet! Only truly dauntless dungeon-delvers get that, kupo!
        THIS_ISN_T_ENOUGH_TO_PROVE_YOU_REACHED                                  = 13197,  -- This isn't enough to prove you reached the goal as a dungeon-delving duo. You have to bring me the item your partner received to show that you were both successful, kupo!
        TO_GO_ON_THIS_FRIGHT_FILLED_FACE_OFF                                    = 13198,  -- To go on this fright-filled face-off with fear, you need a partner who can prove you reached the goal. Come back when you have a buddy in bravery, kupo!
        THIS_ADVENTURE_INTO_ADVERSITY_IS_ONLY_AVAILABLE_TO                      = 13199,  -- This adventure into adversity is only available to two-person parties. Split up into pairs and talk to me again, kupo!
        PLEASE_COME_BACK_WITH_A_DIFFERENT_PARTNER_IT                            = 13200,  -- Please come back with a different partner. It'll be no fun to scare you if your reactions are too similar, kupo!
        YOUR_PARTNER_ISN_T_READY_TO_GO_PLEASE                                   = 13201,  -- Your partner isn't ready to go. Please wait a little longer, kupo.
        YOUR_PARTNER_MUST_TALK_TO_ME_AS_WELL                                    = 13202,  -- Your partner must talk to me as well. I'll be waiting for you whenever you're ready, kupo.
        YOU_CAN_ONLY_CHOOSE_ONE_PARTNER_A_DAY                                   = 13203,  -- You can only choose one partner a day. Come back again tomorrow, kupo!
        HOLD_UP_THERE_IT_LOOKS_LIKE_YOUR_CANDIDATE                              = 13204,  -- Hold up there! It looks like your candidate for courageous companionship has already got a partner! You can't choose that person at the moment, kupo!
        PLEASE_WAIT_A_LITTLE_LONGER_OR_FIND_A                                   = 13205,  -- Please wait a little longer or find a new partner before coming back, kupo.
        ARE_YOU_READY_TO_TEST_YOUR_COURAGE_KUPO                                 = 13206,  -- Are you ready to test your courage, kupo?
        ARE_YOU_READY_TO_GO_READY_KUPO_I                                        = 13207,  -- Are you ready to go? Ready, kupo! I'm too terrified, kupo!
        I_LL_BE_CHECKING_TO_SEE_IF_YOU                                          = 13208,  -- I'll be checking to see if you reached the goal. You can use this magical scroll to make a speedy return to town, kupo.
        IF_YOU_BOTH_SUCCEED_I_LL_HAVE_A                                         = 13209,  -- If you both succeed, I'll have a prize waiting for you! Now, off you go, kupo!
        YOU_CAN_ONLY_CARRY_ONE                                                  = 13210,  -- You can only carry one %.
        ARE_YOU_PARTICIPATING_IN_THIS_PETRIFYING_PILGRIMAGE_WITH                = 13211,  -- Are you participating in this petrifying pilgrimage with the person in your present party?
        HEY_YOU_CHANGED_PARTNERS_YOU_CAN_T_SWITCH                               = 13212,  -- Hey, you changed partners! You can't switch halfway through, kupo!
        WAIT_THE_NUMBER_OF_PEOPLE_IN_YOUR_PARTY                                 = 13213,  -- Wait, the number of people in your party has changed! You have to be in a two-person party, kupo!
        CHOOSE_YOUR_PARTNER_WISELY_COME_BACK_WHEN_YOU                           = 13214,  -- Choose your partner wisely. Come back when you think you have a winning combo, kupo!
        BOO_HAH_HAH_KUPO                                                        = 13215,  -- Boo-hah-hah`...kupo!
        HUH_WHY_AREN_T_YOU_JUMPING_OUT_OF                                       = 13216,  -- Huh? Why aren't you jumping out of your skin in absolute terror? I would've died of fright, kupo!
        HERE_TAKE_THIS_AS_A_TESTAMENT_TO_YOUR                                   = 13217,  -- Here, take this as a testament to your courage. Exchange it for the item your partner received so you can prove that you both reached the goal safely, kupo!
        RETURN_WITH_THE_EVIDENCE_OF_YOUR_SUCCESS_TO                             = 13218,  -- Return with the evidence of your success to the moogle in town. Handing over your partner's item will prove that you were both able to reach me, kupo!
        OH_AND_HERE_S_A_PICTURE_OF_HOW                                          = 13219,  -- Oh, and here's a picture of how your partner's face looked when I popped out of nowhere to scare you. You should hand this in at the same time, kupo! Kupupupu...
        THIS_PLACE_IS_CRAWLING_WITH_NASTIES_YOU_SHOULD                          = 13220,  -- This place is crawling with nasties. You should probably head back to town so you can testify to your partner's bravery.
        WHY_DO_GHOSTS_SAY_BOO_ANYWAY                                            = 13221,  -- Why do ghosts say boo, anyway?
        I_HEARD_THAT_GOING_TO_A_DARK_SCARY                                      = 13222,  -- I heard that going to a dark, scary dungeon is the best way to test your courage. This place definitely qualifies, kupo!
        MAYBE_I_M_DOING_SOMETHING_WRONG_KUPO                                    = 13223,  -- Maybe I'm doing something wrong, kupo?
        IF_IT_GETS_OUT_THAT_I_HAVEN_T                                           = 13224,  -- If it gets out that I haven't scared the wits out of a single person yet, I'm going to get into trouble, kupo...
        UNABLE_TO_ENTER_NEXT_AREA_EXPANSION_PACK_NOT                            = 13225,  -- Unable to enter next area. Expansion pack not installed.
        THE_IRNC_HAS_DISPATCHED_ME_TO_HELP_SUPPORT                              = 13226,  -- The IRNC has dispatched me to help support all those who wish to participate in Conflict.
        BEFORE_YOU_CAN_TAKE_PART_IN_THIS_CONFLICT                               = 13227,  -- Before you can take part in this Conflict event, you must first possess %. You can obtain one from your nation's Conflict Commander, [Excenmille, stationed in Northern San d'Oria./Invincible Shield, stationed in the Metalworks in Bastok./Mhabi Molkot, stationed in Heavens Tower in Windurst.]
        ONLY_ADVENTURERS_WHO_HAVE_ACHIEVED_RANK_3_OR                            = 13228,  -- Only adventurers who have achieved rank 3 or higher may take part in official Ballista matches. Please return when you have proven your loyalty to your home nation.
        HOWEVER_IF_YOU_STILL_WISH_TO_TAKE_PART                                  = 13229,  -- However, if you still wish to take part in Ballista, participation in matches held within Diorama Abdhaljs-Ghelsba is open to all citizens of Vana'diel.
        WHAT_SERVICES_DO_YOU_REQUIRE                                            = 13230,  -- What services do you require?
        WHAT_CAN_I_HELP_YOU_WITH_NOTHING_THE                                    = 13231,  -- What can I help you with? Nothing. The upcoming Ballista matches. The Ballista schedule. A teleport to the Ballista match. The rules of Ballista. Borrow/Return %. Borrow/Return %. Borrow/Return %. The upcoming Brenner matches. A teleport to the Brenner match (Lv #). The rules of Brenner. Borrow/Return %. Borrow/Return %.
        I_AM_ALLOWED_TO_TELEPORT_BALLISTA_PARTICIPANTS_TO                       = 13232,  -- I am allowed to teleport Ballista participants to the site of the next match in exchange for % or # Ballista [Point/Points]. This service is available from twenty-four hours before the start of the match, up until the end of the match.
        CAN_BE_RECEIVED_AFTER_PARTICIPATING_IN_BALLISTA_OR                      = 13233,  -- % can be received after participating in Ballista, or in the event one is not able to participate due to an influx (or lack) of entries.
        I_M_SORRY_BUT_I_AM_NOT_AUTHORIZED                                       = 13234,  -- I'm sorry, but I am not authorized to teleport persons who do not meet the level requirement for the match.
        THE_FOLLOWING_INFORMATION_REGARDS_THE_MATCH_I_AM                        = 13235,  -- The following information regards the match I am currently authorized to teleport you to...
        TELEPORT_RIGHT_AWAY_NOT_YET                                             = 13236,  -- Teleport? Right away. Not yet.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU                                    = 13237,  -- I am sorry, but I cannot teleport you at this time.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU_2                                  = 13238,  -- I am sorry, but I cannot teleport you at this time. Please return when there are less than twenty-four hours remaining until the next match.
        CURRENTLY_THE_FOLLOWING_SPECIAL_RULES_ARE_BEING_IMPLEMENTED             = 13239,  -- Currently, the following special rules are being implemented...
        CURRENTLY_THERE_ARE_NO_SPECIAL_RULES_BEING_IMPLEMENTED                  = 13240,  -- Currently, there are no special rules being implemented.
        THE_NEXT_SCHEDULED_BALLISTA_MATCH_IS_AREA_MATCHUP                       = 13241,  -- The next scheduled Ballista match is: Area: [Jugner Forest/Pashhow Marshlands/Meriphataud Mountains] Matchup: [San d'Oria vs Bastok/Bastok vs Windurst/Windurst vs San d'Oria] Level Restriction: [None/@/@/30/40/50/60/] Participation Fee: # gil Match Format: [All or Nothing * Normal Items Allowed/All or Nothing * Normal Items Restricted/Best of Three * Normal Items Allowed]
        ENTRIES_ARE_NOW_BEING_ACCEPTED                                          = 13242,  -- Entries are now being accepted.
        ENTRY_PERIOD_BEGINS_VANA_DIEL_EARTH_2                                   = 13243,  -- Entry period begins: Vana'diel: Earth:
        MATCH_BEGINS_VANA_DIEL_EARTH_2                                          = 13244,  -- Match begins: Vana'diel: Earth:
        WHILE_WEARING_DURING_A_MATCH_YOU_WILL_BE                                = 13245,  -- While wearing % during a match, you will be able to hear the orders of your nation's Pursuivant. His advice will aid you in battle.
        ALSO_YOU_WILL_BE_INFORMED_OF_ALL_THE                                    = 13246,  -- Also, you will be informed of all the latest match information when entering select cities.
        WOULD_YOU_LIKE_YES_NO                                                   = 13247,  -- Would you like %? Yes. No.
        RETURN_YOUR_YES_NO                                                      = 13248,  -- Return your %? Yes. No.
        OBTAINED_3                                                              = 13249,  -- Obtained: %.
        BY_CARRYING_WITH_YOU_DURING_A_BALLISTA_MATCH                            = 13250,  -- By carrying % with you during a Ballista match, any temporary item you quarry will be automatically placed in your bag without you having to select whether you wish to keep it, use it, or throw it away.
        WHEN_YOUR_INVENTORY_IS_FULL_OR_YOU_CANNOT                               = 13251,  -- When your inventory is full, or you cannot carry any more of a certain item, the newly quarried item will be automatically discarded. If you wish, I can lend you one of these shovels, free of charge.
        BORROW_YES_NO                                                           = 13252,  -- Borrow %? Yes. No.
        YOU_BORROW                                                              = 13253,  -- You borrow %!
        RETURN_THE_YES_NO                                                       = 13254,  -- Return the %? Yes. No.
        YOU_RETURN_THE                                                          = 13255,  -- You return the %!
        WHEN_CARRYING_WITH_YOU_WHILE_PARTICIPATING_IN_A                         = 13256,  -- When carrying % with you while participating in a Ballista match, you will have the option to keep or throw away the first Petra you find. This is useful when you want to continue /sprinting.
        IF_YOU_WISH_I_CAN_LOAN_YOU_ONE                                          = 13257,  -- If you wish, I can loan you one, free of charge.
        BORROW_YES_NO_2                                                         = 13258,  -- Borrow %? Yes. No.
        RETURN_THE_YES_NO_2                                                     = 13259,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_TEMPORARY                            = 13260,  -- When in possession of the key item %, temporary items will be automatically added to the player's inventory when quarried.
        WHEN_A_PLAYER_S_INVENTORY_EXCEEDS_THE_MAXIMUM                           = 13261,  -- When a player's inventory exceeds the maximum capacity, any temporary item found will simply be discarded. You can speak to me to borrow or return the shovel at any time.
        BORROW_THE_YES_NO                                                       = 13262,  -- Borrow the %? Yes. No.
        RETURN_THE_YES_NO_3                                                     = 13263,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_YOU                                  = 13264,  -- When in possession of the key item %, you will have the choice of keeping or throwing away the first Petra you quarry. You will also retain the ability to sprint.
        YOU_CAN_SPEAK_TO_ME_TO_BORROW_OR                                        = 13265,  -- You can speak to me to borrow or return the band at any time.
        SELECT_A_MATCH_LEVEL_VIEW_ALL_LEVELS_NO                                 = 13266,  -- Select a match level... View all levels. No restriction (# gil per match). Level 60 (# gil per match). Level 50 (# gil per match). Level 40 (# gil per match). Level 30 (# gil per match). Return.
        SELECT_FOR_MORE_INFORMATION_NEXT_RETURN                                 = 13267,  -- Select for more information... , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. % / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] Next. Return.
        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                               = 13268,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                   = 13269,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                          = 13270,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                             = 13271,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                          = 13272,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                                 = 13273,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                               = 13274,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                       = 13275,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                   = 13276,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                       = 13277,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                    = 13278,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                               = 13279,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                          = 13280,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE                = 13281,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                            = 13282,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                          = 13283,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                           = 13284,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY             = 13285,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                      = 13286,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                             = 13287,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                      = 13288,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                                 = 13289,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                               = 13290,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                           = 13291,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                             = 13292,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                                 = 13293,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                           = 13294,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                   = 13295,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                            = 13296,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                     = 13297,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                                = 13298,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                           = 13299,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                               = 13300,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                      = 13301,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
        THE_DOOR_IS_LOCKED_TIGHT                                                = 13302,  -- The door is locked tight...
        HEAD_FOR_CARPENTERS_LANDING_YES_NO                                      = 13303,  -- Head for Carpenters' Landing? Yes. No.
        SO_THIS_IS_THE_SAN_D_ORIAN_CATHEDRAL                                    = 13304,  -- So this is the San d'Orian Cathedral... Together with the Tavnazian Cathedral, they form the pillars of our faith.
        IF_ANYONE_IS_TRULY_ATTEMPTING_TO_OPEN_THE                               = 13305,  -- If anyone is truly attempting to open the Gates of Paradise, I am certain it is someone in there...
        HAVE_YOU_LOST_YOUR_WAY_ON_THE_PATH                                      = 13306,  -- Have you lost your way on the path of life? Come, listen to our sermon. Let us be your guide to the light of Paradise.
        WHAT_IS_THIS_YOU_WISH_TO_KNOW_OF                                        = 13307,  -- What is this? You wish to know of the Multinational Expedition and its search for the Gate of the Gods?
        THAT_IS_QUITE_ODD_NOT_BUT_A_FEW                                         = 13308,  -- That is quite odd... Not but a few moments ago, another came asking the same questions. I believe her name was Ulmia. Be she an acquaintance of yours?
        HOW_DO_YOU_ANSWER_YES_NO                                                = 13309,  -- How do you answer? Yes. No.
        I_SEE_ULMIA_TOO_WISHED_TO_LEARN_MORE                                    = 13310,  -- I see. Ulmia, too, wished to learn more of the Gate of the Gods, so I recommended that she attend the upcoming sermon on the subject.
        YES_BY_ALL_MEANS_YOU_MAY_ATTEND_AS                                      = 13311,  -- Yes, by all means you may attend as well. My sermon will begin momentarily.
        ESCHEW_ALL_DESIRE_AND_EMBRACE_ALTANA_ONLY_THEN                          = 13312,  -- Eschew all desire and embrace Altana. Only then will she bless you in her glory.
        THAT_IS_ALL_FOR_TODAY_S_SERMON_MAY                                      = 13313,  -- That is all for today's sermon. May Paradise open its gates to you.
        I_AM_GRATEFUL_TO_HAVE_BEEN_GIVEN_THE                                    = 13314,  -- I am grateful to have been given the opportunity to hear your sermon.
        HOWEVER_THERE_ARE_STILL_MANY_THINGS_I_DO                                = 13315,  -- However, there are still many things I do not understand. Would you be so kind as to spare a few moments to answer my questions?
        OF_COURSE_MY_CHILD_WHAT_IS_IT_YOU                                       = 13316,  -- Of course, my child. What is it you wish to know?
        WHEN_I_WAS_YOUNG_I_OFTEN_HEARD_THE                                      = 13317,  -- When I was young, I often heard the stories of Paradise.
        A_LEGENDARY_LAND_WHERE_THE_GODS_SLUMBER_A                               = 13318,  -- A legendary land where the gods slumber... A gate leading to that land, discovered by the ancients...
        HOWEVER_ACCORDING_TO_THE_STORIES_I_HEARD_THE                            = 13319,  -- However, according to the stories I heard, the ancients angered the Twilight God by attempting to open the forbidden gate. As punishment, he cast a terrible curse upon them all...
        IF_THIS_HIDEOUS_TALE_IS_TRUE_THEN_WHY                                   = 13320,  -- If this hideous tale is true, then why is the San d'Orian Cathedral attempting to convince people that we should open the gates...?
        OR_HAS_THE_CATHEDRAL_DISCOVERED_A_METHOD_TO                             = 13321,  -- Or has the cathedral discovered a method to soothe the wrath of the gods?
        I_MUST_ASSUME_THAT_YOU_ARE_NOT_OF                                       = 13322,  -- ... I must assume that you are not of our kingdom.
        THAT_IS_CORRECT_I_WAS_BORN_IN_THE                                       = 13323,  -- That is correct. I was born in the Marquisate of Tavnazia, and baptized by the Tavnazian Cathedral.
        OUR_CHURCH_TOO_TEACHES_OF_THE_GATES_OF                                  = 13324,  -- Our church, too, teaches of the Gates of the Gods--the Gates of Paradise. However, we are told it is a line that the children of Vana'diel have been forbidden to cross.
        THE_EXACT_OPPOSITE_OF_WHAT_THE_SAN_D                                    = 13325,  -- The exact opposite of what the San d'Orian Cathedral teaches...
        FOR_THE_PAST_TWENTY_YEARS_WE_HAVE_SEARCHED                              = 13326,  -- For the past twenty years, we have searched tirelessly for an entrance to Paradise.
        AND_IT_IS_DURING_THAT_SEARCH_WE_REALIZED                                = 13327,  -- And it is during that search we realized that the only path to soothing the Twilight God's wrath is to eschew all desire and embrace Altana.
        THAT_IS_ALL                                                             = 13328,  -- That is all...?
        I_APOLOGIZE_BUT_I_MUST_PREPARE_FOR_MY                                   = 13329,  -- I apologize, but I must prepare for my next sermon. If you wish to learn more, inquire with one of the high priests.
        IT_IS_THE_LIFEWORK_OF_OUR_MISSIONARIES_TO                               = 13330,  -- It is the lifework of our missionaries to enlighten. May they lead you in the direction of truth...
        BEFORE_THE_GREAT_WAR_WHEN_THE_FORMER_PAPSQUE                            = 13331,  -- Before the Great War, when the former papsque, Muchavatte P Couchiret, was still with us...
        DURING_HIS_TIME_WE_BELIEVED_THAT_THE_GATES                              = 13332,  -- During his time, we believed that the Gates of Paradise were hidden somewhere within the reach of mortal man.
        THE_ROYAL_KNIGHT_YOU_SEARCH_FOR_FRANCMAGE_M                             = 13333,  -- The Royal Knight you search for, Francmage M Mistalle, joined the Multinational Expedition thirty years ago to search for the truth behind that belief. And it is because of that very search...
        WELCOME_TRAVELERS_EVEN_AFTER_LISTENING_TO_THE_VICASQUE                  = 13334,  -- Welcome, travelers. Even after listening to the vicasque's sermon, you still have questions regarding Paradise?
        VERY_WELL_PLEASE_STEP_THIS_WAY_AND_I                                    = 13335,  -- Very well. Please, step this way and I will try to quench your thirst for knowledge.
        THIS_IS_THE_CATHEDRAL_RELIQUARY_IT_WAS_BUILT                            = 13336,  -- This is the cathedral Reliquary. It was built in remembrance of one of our former papsques, Muchavatte P Couchiret.
        DURING_HIS_PAPACY_THE_PAPSQUE_DEVOTED_HIMSELF_TO                        = 13337,  -- During his papacy, the papsque devoted himself to healing the wounds in the hearts of man--wounds left by the flames of war.
        THE_DAWN_GODDESS_WATCHED_OVER_HIM_AND_HIS                               = 13338,  -- The Dawn Goddess watched over him and his work, and blessed him with her glory.
        HOWEVER_THAT_IS_NOT_ALL_SHE_GAVE_HIM                                    = 13339,  -- However, that is not all she gave him. Before his passing, Altana showed the papsque the path to Paradise.
        THE_PATH_TO_PARADISE                                                    = 13340,  -- The path to Paradise...?
        YES_HIS_FINAL_WORDS_TOLD_US_THAT_TO                                     = 13341,  -- Yes. His final words told us that to obtain Paradise, one must eschew all desire and embrace the Dawn Goddess.
        FOR_MANY_YEARS_WE_BELIEVED_THAT_THE_PATH                                = 13342,  -- For many years, we believed that the path to Paradise and gates guarding it were things that actually existed on Vana'diel.
        THE_CATHEDRAL_SCOURED_THROUGH_THE_ANCIENT_TOMES_AND                     = 13343,  -- The cathedral scoured through the ancient tomes and documents in our vaults, went to war with other nations...
        I_HAVE_HEARD_THAT_SAN_D_ORIA_EVEN                                       = 13344,  -- I have heard that San d'Oria even attacked the Tavnazian Cathedral... All this to find a Paradise that was only meant to exist in our hearts...
        INSTILLING_FEAR_TO_FIND_A_LAND_WHERE_MANKIND                            = 13345,  -- Instilling fear to find a land where mankind could live without fear. This paradox ultimately put distance between us and Altana.
        BUT_THANKS_TO_THE_TEACHINGS_OF_MUCHAVATTE_WE                            = 13346,  -- But thanks to the teachings of Muchavatte, we have realized the error of our ways and thus made it our mission to enlighten our brothers and sisters regarding the true path to Paradise.
        DO_YOU_UNDERSTAND                                                       = 13347,  -- Do you understand?
        YES_I_BELIEVE_I_DO                                                      = 13348,  -- Yes, I believe I do.
        HOWEVER_I_HAVE_ONE_LAST_QUESTION_HOW_ARE                                = 13349,  -- However, I have one last question. How are we to break free from the curse of the Twilight God?
        THAT_IS                                                                 = 13350,  -- That is...
        IT_IS_FORBIDDEN_TO_SPEAK_OF_THE_ABHORRENT                               = 13351,  -- It is forbidden to speak of the abhorrent one.
        OF_ALL_THINGS_YOU_SHOULD_KNOW_THIS_WELL                                 = 13352,  -- Of all things, you should know this well, child of Tavnazia.
        ID_13353                                                                = 13353,  -- ...
        TRAVELERS_YOU_NEED_NOT_WORRY                                            = 13354,  -- Travelers, you need not worry.
        IT_IS_OUR_DUTY_TO_SERVE_ALTANA_AND                                      = 13355,  -- It is our duty to serve Altana and introduce her blessed light to the unfortunate masses.
        IF_WE_FOLLOW_THE_TEACHINGS_OF_THE_DAWN                                  = 13356,  -- If we follow the teachings of the Dawn Goddess and do not stray from the path of righteousness, the chains of evil will be broken and the Gates of Paradise will open.
        YES_I_SEE_NOW_THANK_YOU_VERY_MUCH                                       = 13357,  -- Yes... I see now... Thank you very much for your kindness in explaining this all to us.
        NO_YOU_NEED_NOT_THANK_ME_I_AM                                           = 13358,  -- No, you need not thank me. I am simply pleased to know that you now understand the truth behind Paradise.
        WAIT_3                                                                  = 13359,  -- Wait...
        YOU_SAID_THAT_YOU_SEEK_THE_ROYAL_KNIGHT                                 = 13360,  -- You said that you seek the Royal Knight Francmage M Mistalle, did you not?
        IF_I_AM_NOT_MISTAKEN_I_RECALL_A                                         = 13361,  -- If I am not mistaken, I recall a section of Jugner Forest known as Carpenters' Landing being owned by the Knights Mistalle.
        I_DO_NOT_BELIEVE_YOU_WILL_BE_ABLE                                       = 13362,  -- I do not believe you will be able to reach the manor, but you may find some of his hands by the water collecting firewood.
        AH_THE_ADVENTURER_I_CONVERSED_WITH_IN_THE                               = 13363,  -- Ah, the adventurer I conversed with in the reliquary...
        YOU_SAY_YOU_ARE_SEARCHING_FOR_ONE_SIR                                   = 13364,  -- You say you are searching for one Sir Louverance, an envoy of the cathedral?
        HE_WOULD_BE_THE_GRANDSON_OF_FRANCMAGE_M                                 = 13365,  -- He would be the grandson of Francmage M Mistalle, the Royal Knight you were investigating earlier.
        THAT_SIR_LOUVERANCE_HAD_RETIRED_FROM_THE_ROYAL                          = 13366,  -- That Sir Louverance had retired from the Royal Knights is common knowledge; however, I have heard nothing of his enlistment in the order of Temple Knights.
        IF_WE_HIGH_PRIESTS_WERE_NOT_INFORMED_OF                                 = 13367,  -- If we high priests were not informed of his return to military service, he must be entrusted with a mission of the highest importance indeed.
        IT_WOULD_SEEM_TO_ME_THAT_IF_SIR                                         = 13368,  -- It would seem to me that if Sir Louverance is traveling by airship, then the wisest place to search for him would be the port. Do you not agree?
        I_WAS_NOT_AWARE_THAT_SIR_LOUVERANCE_WAS                                 = 13369,  -- I was not aware that Sir Louverance was acting as an envoy for the cathedral.
        HOWEVER_IF_HE_IS_TRAVELING_BY_AIRSHIP_PERHAPS                           = 13370,  -- However, if he is traveling by airship, perhaps you should await his return to San d'Oria at the port.
        AH_MY_CURIOSITY_WAS_SUFFICIENTLY_PIQUED_TO_DO                           = 13371,  -- Ah, %. My curiosity was sufficiently piqued to do some investigating of my own into the Knights Mistalle...
        IT_IS_LOVELY_TO_SEE_YOU_AGAIN_HIGH                                      = 13372,  -- It is lovely to see you again, High Priest Chasalvige. I am afraid I neglected to properly introduce myself at our first meeting.
        MY_NAME_IS_ULMIA_I_WAS_ADVISED_TO                                       = 13373,  -- My name is Ulmia. I was advised to seek your counsel by Lady Hinaree.
        NOW_I_UNDERSTAND                                                        = 13374,  -- Now I understand.
        THE_REASON_FOR_YOUR_KEEN_INTEREST_IN_THE                                = 13375,  -- The reason for your keen interest in the nature of Paradise and the curse of the Twilight God is clear to me.
        LADY_ULMIA_AND_YOU                                                      = 13376,  -- Lady Ulmia. And you, %.
        YOU_NEED_NOT_FEAR_BEING_OVERHEARD_IN_THIS                               = 13377,  -- You need not fear being overheard in this place. Let us be entirely truthful with one another and speak openly of these matters.
        MATTERS_CONCERNING_THE_TAVNAZIAN_CHOIR_S_EFFORTS_TO                     = 13378,  -- ...Matters concerning the Tavnazian choir's efforts to complete the five verses.
        YOU_KNOW_OF_THE_SONG                                                    = 13379,  -- You know of the song...?
        BEFORE_THE_ADVENT_OF_THE_GREAT_WAR_YOU                                  = 13380,  -- Before the advent of the Great War, you came to visit Lady Hinaree with Cardinal Mildaurion and her companion, did you not?
        I_WAS_PERMITTED_TO_ACCOMPANY_PAPSQUE_MUCHAVATTE_AND                     = 13381,  -- I was permitted to accompany Papsque Muchavatte, and was present at the proceedings.
        I_AM_CERTAIN_THAT_AT_THAT_TIME_YOU                                      = 13382,  -- I am certain that at that time, you had little idea of the reason behind that gathering.
        IT_WAS_IN_FACT_A_MEETING_TO_IMPROVE                                     = 13383,  -- It was, in fact, a meeting to improve the failing relations between the cathedrals of San d'Oria and Tavnazia.
        IN_PARTICULAR_THERE_SEEMED_TO_BE_NO_END                                 = 13384,  -- In particular, there seemed to be no end to the unsavory rumors surrounding the Tavnazian Cathedral. This was perhaps due to the strict policy of secrecy the Tavnazians had adopted following the period of internecine conflict in San d'Oria.
        THE_PAPSQUE_SENT_A_MESSENGER_TO_DETERMINE_THE                           = 13385,  -- The papsque sent a messenger to determine the accuracy of these rumors.
        HOWEVER_CARDINAL_MILDAURION_ARRIVED_ACCOMPANIED_BY_TWO_YOUNG            = 13386,  -- However, Cardinal Mildaurion arrived accompanied by two young girls.
        AND_ONE_OF_THOSE_GIRLS_YOU_ULMIA_SANG                                   = 13387,  -- And one of those girls--you, Ulmia--sang a certain song...
        YES_I_REMEMBER_BUT_MY_VOICE_WAS_STILL                                   = 13388,  -- Yes, I remember. But my voice was still untrained and Papsque Muchavatte grew furious at my terrible singing.
        NO_CHILD_THAT_IS_NOT_WHY_HE_WAS                                         = 13389,  -- No, child, that is not why he was angry. The reason behind the papsque's outburst was his fear that the song you were singing would be completed...
        HE_WAS_FRANTIC_TO_STEM_THE_DREADFUL_POWER                               = 13390,  -- He was frantic to stem the dreadful power of that song.
        DREADFUL_POWER                                                          = 13391,  -- Dreadful power?
        IT_IS_PERHAPS_FOR_THE_BEST_THAT_YOU                                     = 13392,  -- It is perhaps for the best that you remained ignorant of the truth.
        THIS_STORY_FINDS_ITS_BEGINNING_ALMOST_FIVE_HUNDRED                      = 13393,  -- This story finds its beginning almost five hundred years ago... It reaches back to an era considered to be a time of humiliation for the Elvaan.
        AT_THAT_TIME_THE_QUON_CONTINENT_WAS_UNDER                               = 13394,  -- At that time, the Quon continent was under the control of an army dispatched by the Federation of Windurst.
        THE_ELVAAN_RACE_HAD_YET_TO_FORM_A                                       = 13395,  -- The Elvaan race had yet to form a nation of their own, and the numerous tribes lived in forests apart from one another.
        BUT_EVEN_AS_NOW_THE_BLOOD_OF_THE                                        = 13396,  -- But even as now, the blood of the Elvaan ran deep with pride. Swearing victory upon his sword, the hero Lanfeaur d'Oraguille came forth to lead our people to freedom.
        ALONG_WITH_GENERAL_ALPHOLLON_TAJEUX_WHO_WAS_LATER                       = 13397,  -- Along with General Alphollon Tajeux, who was later to become the Marquis of Tavnazia, they founded a kingdom on the strength of two valuable artifacts.
        HOWEVER_AFTER_THE_BATTLE_TO_EMANCIPATE_THE_ELVAAN                       = 13398,  -- However, after the battle to emancipate the Elvaan, both of these treasures were lost.
        IN_THEIR_RESPECTIVE_PLACES_IN_THE_CATHEDRALS_OF                         = 13399,  -- In their respective places in the cathedrals of San d'Oria and Tavnazia, two mysterious stone tablets were left behind.
        WE_TOILED_LONG_AND_HARD_TO_SOLVE_THE                                    = 13400,  -- We toiled long and hard to solve the riddles of the tablets, and were finally able to retrieve one of the objects in the age of King Ranperre--the holy sword, Lightbringer.
        IN_SPITE_OF_THIS_SUCCESS_THE_TAVNAZIAN_CATHEDRAL                        = 13401,  -- In spite of this success, the Tavnazian Cathedral refused to reveal the contents of the second tablet.
        A_SECRET_INVESTIGATION_INSTIGATED_BY_THE_SAN_D                          = 13402,  -- A secret investigation instigated by the San d'Orian Cathedral discovered the writings upon the stone were actually the verses of a song.
        YES_YOU_KNOW_THIS_SONG_ONLY_TOO_WELL                                    = 13403,  -- Yes, you know this song only too well... It was the Lay of the Immortals.
        IT_WAS_A_SONG_THAT_WOULD_CONCLUDE_WITH                                  = 13404,  -- It was a song that would conclude with the manifestation of a deity.
        A_SONG_TO_CALL_THE_GODS_I_NEVER                                         = 13405,  -- A song to call the gods!? I never knew...
        THE_TAVNAZIAN_CATHEDRAL_HAD_DECIPHERED_THE_WORDS_BUT                    = 13406,  -- The Tavnazian Cathedral had deciphered the words, but the melody yet eluded them. The search for one who could perform the song was apparently long and arduous.
        HOWEVER_WHEN_YOU_APPEARED_AND_WERE_ABLE_TO                              = 13407,  -- However, when you appeared and were able to sing the opening verse, the song showed its first promise of power.
        BUT_I_I_WAS_TOLD_THE_LAY_WAS                                            = 13408,  -- But I...! I was told the lay was sung to prove that Prishe was not the abhorrent one!
        I_KNOW_THIS_THAT_IS_WHY_I_SUMMONED                                      = 13409,  -- I know this. That is why I summoned you here to explain the truth behind these matters.
        I_HAVE_LEARNED_FROM_THAT_A_KNIGHT_IS                                    = 13410,  -- I have learned from [Lady Hinaree/this adventurer] that a knight is searching for Cardinal Mildaurion under orders from the San d'Orian Cathedral.
        FROM_WHAT_I_COULD_DISCOVER_HE_HAS_TRAVELED                              = 13411,  -- From what I could discover, he has traveled to the Northlands to learn more about the Twilight God.
        I_KNOW_NOT_HER_PURPOSE_BUT_CARDINAL_MILDAURION                          = 13413,  -- I know not her purpose, but Cardinal Mildaurion was also seeking knowledge regarding Promathia.
        CARDINAL_MILDAURION                                                     = 13414,  -- Cardinal Mildaurion!?
        PLEASE_HEED_MY_WORDS_NEVER_FORGET_THE_SIGNIFICANCE                      = 13415,  -- Please heed my words. Never forget the significance of that song, or your own worth as one who holds knowledge of its mysteries. If the cardinal discovers that you still live...
        ID_13416                                                                = 13416,  -- ...!?
        LADY_ULMIA_I_IMPLORE_YOU_FIND_YOUR_COMPANION                            = 13417,  -- Lady Ulmia, I implore you: Find your companion and return to Tavnazia.
        I_SPOKE_WITH_THE_RESEARCHERS_IN_BEAUCEDINE_ON                           = 13418,  -- I spoke with the researchers in Beaucedine on the matter of Sir Louverance.
        FROM_WHAT_I_CAN_GATHER_YOUR_FRIEND_HAS                                  = 13419,  -- From what I can gather, your friend has most likely been transported to the Rhinostery in the Federation of Windurst.
        THAT_IS_GOOD_NEWS_THANK_YOU_HIGH_PRIEST                                 = 13420,  -- That is good news! Thank you, High Priest Chasalvige. We will continue our search in the city of Windurst!
        COULLENE_LOOKS_OVER_CURIOUSLY_FOR_A_MOMENT                              = 13421,  -- Coullene looks over curiously for a moment.
        GUILBERDRIER_LOOKS_OVER_CURIOUSLY_FOR_A_MOMENT                          = 13422,  -- Guilberdrier looks over curiously for a moment.
        BONCORT_LOOKS_OVER_CURIOUSLY_FOR_A_MOMENT                               = 13423,  -- Boncort looks over curiously for a moment.
        CAPIRIA_LOOKS_OVER_CURIOUSLY_FOR_A_MOMENT                               = 13424,  -- Capiria looks over curiously for a moment.
        VILLION_LOOKS_OVER_CURIOUSLY_FOR_A_MOMENT                               = 13425,  -- Villion looks over curiously for a moment.
        HEY_YOU_RE_AN_ADVENTURER_RIGHT_YOU_RE                                   = 13426,  -- Hey! You're an adventurer, right? You're supposed to help people with stuff, right? Take this letter to that [cool guy/cute lady] in the red hat, okay?
        EXCUSE_ME_MISTER_LADY_WOULD_YOU_TAKE_THIS                               = 13427,  -- Excuse me, mister/lady]. Would you take this letter to the [guy/lady] in the red hat?
        ADVENTURER_MAN_LADY_COULD_YOU_TAKE_THIS_LETTER                          = 13428,  -- Adventurer-man/lady]! Could you take this letter to that funny [guy/lady] in the red hat?
        I_WOULD_LIKE_TO_TAKE_THIS_LETTER_TO                                     = 13429,  -- I would like to take this letter to a certain [fellow/woman] wearing a red chapeaux; however, my parents do not allow me to stray far from home. Kind adventurer, might you deliver it in my stead?
        THANK_YOU_THANK_YOU_THANK_YOU                                           = 13430,  -- Thank you! Thank you! Thank you!
        WHOA_THANKS_MISTERRR_LADY                                               = 13431,  -- Whoa! Thanks, misterrr/lady]!
        THANK_YOU_SO_VERY_MUCH_SIR_MA_AM                                        = 13432,  -- Thank you so very much, sir/ma'am]!
        ANOTHER_PRESENT_SORRY_BUT_I_ONLY_HAVE_TWO                               = 13433,  -- Another present? Sorry, but I only have two hands, Mr./Ms.] Adventurer!
        WOW_ANOTHER_PRESENT_AH_BUT_I_DON_T                                      = 13434,  -- Wow! Another present! Ah... But I don't think I can carry all these home at once. Why don't you come back later?
        HEY_DIDN_T_YOU_JUST_GIVE_ME_A                                           = 13435,  -- Hey, didn't you just give me a prrresent? You're starrrting to scare me, mister/lady]...
        I_JUST_ACCEPTED_A_GIFT_FROM_YOU_KIND                                    = 13436,  -- I just accepted a gift from you, kind sir/ma'am]. I could not possibly accept another.
        YOU_VE_BROUGHT_JOY_TO_THE_CHILDREN_OF                                   = 13437,  -- You've brought joy to the children of Vana'diel!
        YOU_VE_BROUGHT_BARRELFULS_OF_JOY_TO_THE                                 = 13438,  -- You've brought barrelfuls of joy to the children of Vana'diel!
        CGP_H_CGF_B                                                             = 13439,  -- #|Cgp|h%CgF#B
        HO_HO_HO_HAVE_YOU_BEEN_WORKING_HARD                                     = 13440,  -- Ho ho ho! Have you been working hard to bring joy to the wee tykes of Vana'diel?
        I_BELIEVE_THE_CHILDREN_ARE_OUR_FUTURE_IF                                = 13441,  -- I believe the children are our future. If we don't nurture them, then all hope will be lost. That's why I've been passing out presents to show them my love. Here, why don't you try it as well?
        IF_YOU_WANT_ANY_MORE_LOVE_TO_GIVE                                       = 13442,  -- If you want any more love to give to the children, you'll have to buy it. Hey, I've gotta make a living too, you know.
        HO_HO_HO_LETTERS_FROM_MY_FANS                                           = 13443,  -- Ho ho ho! Letters from my fans?
        BUT_THERE_ISN_T_A_NAME_ON_THIS                                          = 13444,  -- But there isn't a name on this %... How am I supposed to return the favor if I don't know who to return it to...?
        WHO_SENT_IT_ARTINIEN_AUTHERE_AUVARE_BLENDARE_BRIFALIEN                  = 13445,  -- Who sent it? Artinien. Authere. Auvare. Blendare. Brifalien. Foletta. Leuveret. Maurinne. Miene. Taurette.
        ARE_YOU_SURE_AND_ARE_THE_ONES_WHO                                       = 13446,  -- Are you sure [Artinien/Authere/Auvare/Blendare/Brifalien/Foletta/Leuveret/Maurinne/Miene/Taurette], [Artinien/Authere/Auvare/Blendare/Brifalien/Foletta/Leuveret/Maurinne/Miene/Taurette], and [Artinien/Authere/Auvare/Blendare/Brifalien/Foletta/Leuveret/Maurinne/Miene/Taurette] are the ones who gave you the letters?
        POSITIVE_ABOSLUTELY_WAIT_A_MINUTE                                       = 13447,  -- Positive? Aboslutely! Wait a minute...
        SIGH_IF_THERE_ISN_T_A_NAME_ON                                           = 13448,  -- <Sigh>... If there isn't a name on this %, how am I supposed to return the favor?
        I_KNEW_IT_THOSE_LITTLE_ONES_HAVE_BEEN                                   = 13449,  -- I knew it! Those little ones have been my favorites since I arrived in San d'Oria.
        YOU_KNOW_YOU_OUGHT_TO_TRY_BRINGING_JOY                                  = 13450,  -- You know, you ought to try bringing joy to the children of Vana'diel yourself. Here, you can have this hat.
        WEAR_IT_AND_ALL_THE_KIDS_WILL_KNOW                                      = 13451,  -- Wear it, and all the kids will know that you're here to deliver love!
        REALLY_ACTS_OF_KINDNESS_LIKE_THIS_ALWAYS_FILL                           = 13452,  -- Really! Acts of kindness like this always fill my heart up with this feeling...this feeling that I just can't explain. I'll have to go find those children and give 'em an extra-special present!
        WHEN_IS_THAT_CRAZY_CRAFTSMAN_GOING_TO_COME                              = 13453,  -- When is that crazy craftsman going to come and pick up his materials, kupo...?
        BOY_AM_I_GLAD_TO_SEE_YOU_I                                              = 13454,  -- Boy, am I glad to see you! I've been waiting forever for someone to pick up these supplies, kupo!
        ARE_YOU_SURE_THAT_YOU_HAVE_THE_TIME                                     = 13455,  -- Are you sure that you have the time to be chatting here with me, kupo?
        HAVE_YOU_SEEN_ANY_CRAZY_GOBLINS_RIDING_AROUND                           = 13456,  -- Have you seen any crazy Goblins riding around on chocobos lately, kupo?
        OH_YOU_DON_T_HAVE_TO_WORRY_THEY                                         = 13457,  -- Oh, you don't have to worry. They probably won't attack you. They're playing a game with us moogles, kupo!
        YOU_SEE_WE_TAKE_THESE_CARDS_AND_BURY                                    = 13458,  -- You see, we take these cards and bury them around the outskirts of town. Then the Goblins go out and try to find them. If they do, they can bring them back to us and exchange them for different prizes, kupo.
        THIS_TIME_WE_SPREAD_THEM_OUT_ALL_OVER                                   = 13459,  -- This time, we spread them out all over the area, thinking that the Gobs wouldn't be able to cover that much land, kupo.
        BUT_THAT_WAS_BEFORE_WE_LEARNED_THAT_THEY                                = 13460,  -- But that was before we learned that they had their own chocobos!
        IT_S_JUST_NOT_FAIR_KUPO                                                 = 13461,  -- It's just not fair, kupo!
        NOW_IT_S_ONLY_A_MATTER_OF_TIME                                          = 13462,  -- Now it's only a matter of time before those stinking beastmen find all the cards and we moogles lose the game, kupo!
        AND_THAT_S_WHY_WE_NEED_YOUR_HELP                                        = 13463,  -- And that's why we need your help, kupo! Would you go out into the field and find the cards before the Goblins do?
        THERE_IS_A_VARIETY_OF_DIFFERENT_SETS_FOR                                = 13464,  -- There is a variety of different sets. For each set you bring back safely, I'll secretly give you the present that we were going to give the Goblins, kupo!
        FOR_STARTERS_WHY_DON_T_YOU_TRY_FINDING                                  = 13465,  -- For starters, why don't you try finding %, %, and %? That should throw those smelly Gobs for a real spin, kupo!
        GREAT_A_WHOLE_SET_KUPO_AH_I_WISH                                        = 13466,  -- Great! A whole set, kupo! Ah, I wish I could be there to see the look on those Gobs' faces when all they find is an empty hole. Oh, right! Here's your reward, kupo!
        IF_YOU_HAVE_ANY_EXTRA_TIME_ON_YOUR                                      = 13467,  -- If you have any extra time on your hands, try finding more card sets, kupo! We really have to stick it to those Gobs this year to show them who's boss!
        WOW_ANOTHER_SET_YOU_DON_T_KNOW_HOW                                      = 13468,  -- Wow! Another set! You don't know how much this means to us, kupo! Here, take this!
        YOU_HAND_THE_CLERK_THE_AND_GIL_AND                                      = 13469,  -- You hand the clerk the % and # gil, and your set of armor is returned.
        HELLO_SIR_MA_AM_HAVE_YOU_EVER_FOUND                                     = 13470,  -- Hello, sir/ma'am]. Have you ever found yourself throwing away items because your Mog Safe is overflowing with dusty sets of armor collected on your many adventures? My colleagues and I have heard the cries of our fellow adventurers and joined together to aid all those in need.
        TRADE_ME_A_FULL_SET_AND_FOR_A                                           = 13471,  -- Trade me a full set, and for a small fee (payable on pickup) we will hold on to it, all the while protecting it from thieves, moths, and any/all acts of god and/or goddess.
        PLEASE_BE_FOREWARNED_THAT_WE_CANNOT_STORE_ANY                           = 13472,  -- Please be forewarned that we cannot store any high-quality equipment, and that the signatures on any pieces of collected armor will be lost.
        HOW_MAY_I_BE_OF_SERVICE_TODAY                                           = 13473,  -- How may I be of service today?
        WHAT_TO_DO_NOTHING_VIEW_LIST_OF_STORABLE                                = 13474,  -- What to do... Nothing. View list of storable armor sets. Have stored armor returned.
        WE_ARE_CURRENTLY_OFFERING_STORAGE_SERVICE_FOR_THE                       = 13475,  -- We are currently offering storage service for the following armor sets:
        LET_ME_SEE_AH_YES_LORD_LADY_WE                                          = 13476,  -- Let me see... Ah yes, Lord/Lady] %. We are currently holding the following garments...
        NONE_LEVEL_24_30_ARMOR_LEVEL_31_40                                      = 13477,  -- [View which set?/Remove which set from storage?] None. Level 24`30 armor. Level 31`40 armor. Level 41`50 armor. Artifact armor/High level gear. Relic armor.
        NONE_IRON_CHAINMAIL_SHADE_HARNESS_BRASS_SCALE_ARMOR                     = 13478,  -- [View which set?/Remove which set?] None. Iron Chainmail. Shade Harness. Brass Scale Armor. Wool Robe. Eisenplatte Armor. Soil Gi. Seer's Tunic. Studded Armor. Centurion's Scale Mail. Mercenary Captain's Doublet. Garish Tunic. Noct Doublet.
