        I_AM_SORRY_BUT_YOU_HAVE_ALREADY_BROUGHT_2                               = 16263,  -- I am sorry, but you have already brought me these items.
        HELLO_WHAT_MIGHT_I_INTEREST_YOU_IN_TODAY                                = 16264,  -- Hello! What might I interest you in today?
        YOU_HAVE_CHOCOBO_ITEM_CONFIRMATION_FREE_RUN_GIL                         = 16265,  -- (You have # [chocobuck/chocobucks].) Chocobo [registration/confirmation]. Item confirmation. Free run (# gil). Official race (# [chocobuck/chocobucks]). Re-run. Rule confirmation. Nothing.
        YOU_HAVE_CHOCOBO_ITEM_CONFIRMATION_FREE_RUN_GIL_2                       = 16266,  -- (You have # [chocobuck/chocobucks].) Chocobo [registration/confirmation]. Item confirmation. Free run (# gil). Official race. Re-run. Rule confirmation. Nothing.
        YOU_CANNOT_ACCESS_THIS_MENU_UNTIL_YOU_HAVE                              = 16267,  -- You cannot access this menu until you have registered a chocobo to race.
        TO_REGISTER_YOUR_CHOCOBO_YOU_MUST_FIRST_BRING                           = 16268,  -- To register your chocobo, you must first bring me either % or %.
        YOU_CAN_ONLY_REGISTER_ONE_CHOCOBO_AT_A                                  = 16269,  -- You can only register one chocobo at a time, but you may always register a new one whenever you wish.
