        THERE_ARE_A_TOTAL_OF_FIVE_CENTERS_READILY                               = 16516,  -- There are a total of five centers readily available for your convenience, each of which are located near the transportation portals. There are two to the east and west of here, and one just to the north.
        ALL_CHOCOBET_CENTERS_ARE_CAPABLE_OF_PROVIDING_THE                       = 16517,  -- All chocobet centers are capable of providing the same services.
        THE_GRANDSTAND_FACES_THE_RACETRACK_ITSELF_AND_ALLOWS                    = 16518,  -- The grandstand faces the racetrack itself, and allows spectators to sit and enjoy the races in comfort.
