        INNINGS_BREAKDOWN_BASE_GIL_PLUS_A_GIL_BONUS                             = 16635,  -- innings Breakdown # base gil plus a #-gil bonus # [chocobuck/chocobucks] # [solo victory point/solo victory points]
        TURN_IN_YOUR_YES_NO                                                     = 16636,  -- Turn in your %? Yes. No.
        VERY_WELL_HERE_IS_YOUR_BACK                                             = 16637,  -- Very well. Here is your % back.
