        REIGNITE_THE_SPARK_IN_YOUR_LIFE_WITH_SOME                               = 17614,  -- Reignite the spark in your life with some fantastic fireworks, lovingly crafted by the always-lovely Mighty Maidens!
        COME_ONE_COME_ALL_GET_YOUR_HANDS_ON                                     = 17615,  -- Come one, come all! Get your hands on the Mighty Maidens' new line of cheer-boosting, crowd-pleasing fireworks. They're grrreat fun for the whole family!
        THANK_YOU_SO_MUCH_FOR_PATRONIZING_OUR_HUMBLE                            = 17616,  -- Thank you so much for patronizing our humble establishment! Note that the more fireworks you buy, the better the Mighty Maidens will perform against Ullegore and his minions! At this rate, they will perform like [tone-deaf Tonberries./over-hyped amateurs./fan favorites./superstars!/cultural icons!] Remember, your compassionate consumerism is key to restoring fun and felicity to the realm.
        KUPOPO_MUMOR_S_WOEFUL_ONE_WOMAN_WAIL_SPLIT                              = 17617,  -- Kupopo... Mumor's woeful one-woman wail split my skull in six!
