        WE_MOOGLES_HAVE_SPENT_MANY_A_SLEEPLESS_NIGHT                            = 17829,  -- We moogles have spent many a sleepless night preparing for this year's festivities, kupo. Be sure not to miss any of the exceptionally exciting events that are being held in and about town during this most joyous of seasons.
        OH_AND_THERE_S_ONE_THING_YOU_SIMPLY                                     = 17830,  -- Oh, and there's one thing you simply must know, kupo. Should you come by any gift tokens, bring them to me and I'll furnish you with gorgeous gifts in exchange!
