        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_8                                 = 17886,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        THERE_YOU_GO_THAT_DOESN_T_SOUND_SO                                      = 17887,  -- There you go. That doesn't sound so hard, now, does it?
        BUT_OF_COURSE_IF_YOU_LL_JUST_ALLOW                                      = 17888,  -- But of course! If you'll just allow me to inspect your % for a moment...
        YOUR_FEWELL_SUPPLY_WOULD_APPEAR_TO_BE_AS                                = 17889,  -- Your fewell supply would appear to be as follows: o o # o!# o"# o## o$# o%# o&#.
        RUNNING_LOW_WE_CAN_FILL_YOU_UP_FOR                                      = 17890,  -- Running low? We can fill you up for a nominal fee.
        REPLENISH_FEWELL_YES_NO                                                 = 17891,  -- Replenish fewell? Yes. No.
        LOOKING_FOR_A_FEWELL_FILL_UP_YOU_SAY                                    = 17892,  -- Looking for a fewell fill-up, you say? Then you've come to the right place!
        HM_WHY_YOUR_TANK_IS_ALREADY_FULL_TO                                     = 17893,  -- ...Hm? Why, your tank is already full to bursting. Come back again if you need a refill.
        NOW_LET_S_SEE_HERE_ACCORDING_TO_MY                                      = 17894,  -- Now let's see here... According to my calculations, I can fill you up to capacity for # gil. How does that sound?
        PAY_GIL_DEAL_NO_THANKS                                                  = 17895,  -- Pay # gil? Deal! No thanks.
        UNDERSTOOD_TAKE_CARE_TO_MONITOR_YOUR_RESERVES_CLOSELY                   = 17896,  -- Understood. Take care to monitor your reserves closely, lest you run out of fewell in the midst of a crucial procedure.
        I_M_AFRAID_YOU_HAVEN_T_THE_REQUISITE                                    = 17897,  -- I'm afraid you haven't the requisite gil, friend. Perhaps another time.
        EXCELLENT_NOW_WE_JUST_POP_OPEN_YOUR_HERE                                = 17898,  -- Excellent! Now we just pop open your % here, and...
        THERE_YOU_GO_FILLED_TO_THE_BRIM_WITH                                    = 17899,  -- There you go. Filled to the brim with a fresh batch of fewell! Can you smell those fumes? Mmm-mmm!
        YOUR_HAS_BEEN_FILLED_TO_CAPACITY                                        = 17900,  -- Your % has been filled to capacity!
        YOU_HAND_THE_SYNERGY_ENGINEER_GIL                                       = 17901,  -- You hand the synergy engineer # gil.
        HOW_DO_YOU_EXPECT_ME_TO_DO_THAT                                         = 17902,  -- How do you expect me to do that when your % is sitting inside a furnace, friend? You'll have to come back after you've finished synergizing.
        MATERIALS_YOU_SAY_BUT_OF_COURSE_HAVE_A                                  = 17903,  -- Materials, you say? But of course! Have a look at our selection.
        PURCHASE_SOMETHING_NOT_TODAY_GIL_GIL_GIL                                = 17904,  -- Purchase something? Not today. # : # gil. # : # gil. # : # gil.
        FOR_THAT_COMES_TO_GIL                                                   = 17905,  -- For # , that comes to # gil.
        AH_ANOTHER_DEDICATED_SYNERGIST_LOOKING_TO_REFINE_HIS                    = 17906,  -- Ah, another dedicated synergist looking to refine his/her] technique. Excellent! That motivation will serve you well.
        BUT_I_M_AFRAID_YOU_LL_NEED_EXPERIENCE                                   = 17907,  -- ...But I'm afraid you'll need [/ever so slightly more/a bit more/more/a good deal more/considerably more] experience before you're ready to benefit from my training.
        AND_YES_IT_WOULD_SEEM_YOU_RE_AT                                         = 17908,  -- And yes, it would seem you're at just the right skill level to receive my training. So, what will it be? Which technique would you like to improve?
        TRAIN_IN_WHICH_TECHNIQUE_CANCEL_FEWELL_FEEDING_CURRENT                  = 17909,  -- Train in which technique? Cancel. Fewell feeding. (Current Lv.: #) Furnace thwacking. (Current Lv.: #) Pressure handle. (Current Lv.: #) Safety lever. (Current Lv.: #) Furnace repair. (Current Lv.: #) Fewell recycling. (Current Lv.: #)
        YOU_WISH_TO_IMPROVE_YOUR_TECHNIQUE_IS_THIS                              = 17910,  -- You wish to improve your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique. Is this correct?
        IT_WOULD_SEEM_YOUR_TECHNIQUE_ALREADY_EXCEEDS_MY                         = 17911,  -- It would seem your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique already exceeds my own. There is no more I can teach you.
        TRAIN_IN_THIS_TECHNIQUE_YES_NO                                          = 17912,  -- Train in this technique? Yes. No.
        VERY_WELL_NOW_LISTEN_UP_WATCH_CLOSELY_AND                               = 17913,  -- Very well! Now listen up, watch closely, and try to follow along...
        SEE_YOU_TAKE_THIS_PART_HERE_AND_YES                                     = 17914,  -- ...See, you take this part here, and... Yes, yes...just like that...
        NOW_STEADY_HERE_OR_YOU_LL_BE_PICKING                                    = 17915,  -- ...Now steady here, or you'll be picking exploded furnace shrapnel out of your face for a week! Phew, that was a close one...
        AND_BY_APPLYING_COROLLARY_FIVE_OF_HILDOLF_S                             = 17916,  -- ...And by applying Corollary Five of Hildolf's Third Theory of Inverse Transfocal Equilibrium, we find that...
        CLINK_CLANK_CLUNK_ER_LET_S_TRY_THAT                                     = 17917,  -- <Clink, clank...clunk> ...Er, let's try that once more...
        SUPERB_A_QUICK_LEARNER_I_SEE_IF_ONLY                                    = 17918,  -- ...Superb! A quick learner, I see. If only all my students were as attentive as you!
        YOUR_TECHNIQUE_INCREASES_TO_LEVEL                                       = 17919,  -- Your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique increases to level #!
        RESEARCH_INTO_THE_COMPOSITION_OF_THE_CINDER_PRODUCED                    = 17920,  -- Research into the composition of the cinder produced as a side effect of synergy just might lead to the next breakthrough in our field. Provide us with samples for analysis, and we will gladly reward your contributions.
        TRADE_IN_YOUR_CINDER_CURRENTLY_PZ_NOT_NOW                               = 17921,  -- Trade in your cinder? (Currently: # Pz) Not now. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. # gil: # Pz.
        THIS_IS_WHAT_YOU_WANT_CORRECT                                           = 17922,  -- This is what you want, correct?
        MAKE_THE_EXCHANGE_YES_NO                                                = 17923,  -- Make the exchange? Yes. No.
        IT_WOULD_APPEAR_THAT_YOU_LACK_THE_NECESSARY                             = 17924,  -- It would appear that you lack the necessary quantity of cinder for that transaction.
        EXCELLENT_AND_THIS_IS_YOURS_MAY_IT_SERVE                                = 17925,  -- Excellent! And this is yours. May it serve you well!
        YOU_TRANSFERRED_PZ_OF_CINDER_TO_THE_SYNERGY                             = 17926,  -- You transferred # Pz of cinder to the synergy engineer. # Pz [remains/remain] in your possession.
        ASK_ABOUT_WHAT_NOTHING_SYNERGY_FURNACES_SYNERGY_OVERVIEW                = 17927,  -- Ask about what? Nothing. Synergy furnaces. Synergy overview. Synergy procedure. Synergy recipes. Fewell replenishment. Materials for sale. Synergy techniques. Trading cinder.
        THE_SYNERGY_FURNACES_YOU_SEE_AROUND_TOWN_ARE                            = 17928,  -- The synergy furnaces you see around town are provided as a public service by the Bastokan Institute of Synergy Research, to ensure that no synergist is ever far away from the tools of their trade.
        THE_SYNERGIST_MUST_PROVIDE_HIS_OR_HER_OWN                               = 17929,  -- The synergist must provide his or her own %, as well as any materials to be used in the synergy process. Provided those conditions are met, synergy furnaces may be used free of charge.
        NEEDLESS_TO_SAY_ONLY_ONE_PARTY_MAY_OPERATE                              = 17930,  -- Needless to say, only one party may operate any given furnace at once.
        FORTUNATELY_THERE_ARE_MULTIPLE_FURNACES_INSTALLED_THROUGHOUT_TOWN       = 17931,  -- Fortunately, there are multiple furnaces installed throughout town. If the furnace before you is already in use, please seek out an unused one elsewhere, or wait patiently for your turn.
        YOU_MAY_THINK_OF_SYNERGY_AS_AN_EVOLVED                                  = 17932,  -- You may think of synergy as an evolved form of synthesis. It is a discipline full of heretofore unimagined possibilities, but one which demands consummate skill from its practitioners.
        LIKE_SYNTHESIS_SYNERGY_INVOLVES_COMBINING_MATERIALS_ACCORDING_TO        = 17933,  -- Like synthesis, synergy involves combining materials according to a prescribed recipe to yield oft-spectacular results. The rub is that each synergy recipe also dictates a certain elemental balance that must be achieved for the procedure to be successful.
        THIS_BALANCE_IS_ACHIEVED_THROUGH_SKILLFUL_INFUSION_OF                   = 17934,  -- This balance is achieved through skillful infusion of combustible elemental crystals that we synergists call fewell. To begin the synergy process, you'll have to feed the furnace with fewell and get those flames burning!
        AS_A_GENERAL_RULE_THE_MORE_COMPLEX_THE                                  = 17935,  -- As a general rule, the more complex the recipe, the more fewell it will require. Take care to check your stock before you fire up the furnace, lest you find its flames guttering out at a crucial moment.
        WITH_THE_BELLY_OF_THE_FURNACE_ROARING_UP                                = 17936,  -- With the belly of the furnace roaring up a storm, it's time to toss in your materials and start synergizing! Keep a close eye on the balance of elements and deploy fewell as necessary. Approach the prescribed elemental balance, and your item will take form, allowing you to remove it from the furnace.
        THE_CLOSER_YOU_ARE_TO_THE_IDEAL_ELEMENTAL                               = 17937,  -- The closer you are to the ideal elemental balance, the higher the quality of your finished product will be. In synergy, it pays to be a perfectionist!
        BUT_BE_FOREWARNED_THESE_FURNACES_CAN_ONLY_SUSTAIN                       = 17938,  -- But be forewarned: these furnaces can only sustain the elemental maelstrom swirling and storming inside them for so long.
        IF_THE_FURNACE_S_DURABILITY_SHOULD_FAIL_THE                             = 17939,  -- If the furnace's durability should fail, the synergy process will be interrupted, and you will be forced to start anew.
        TAKE_HEART_THOUGH_AS_ANY_MATERIALS_INSIDE_YOUR                          = 17940,  -- Take heart, though, as any materials inside your % will remain intact. You may retrieve them or attempt the synergy process again as you see fit.
        ANY_FEWELL_CONSUMED_IN_THE_FAILED_SYNERGY_ATTEMPT                       = 17941,  -- Any fewell consumed in the failed synergy attempt, on the other hand, will be permanently lost.
        SYNERGISTS_MUST_ALSO_BE_WARY_OF_DEBRIS_BUILDUP                          = 17942,  -- Synergists must also be wary of debris buildup, an unavoidable side effect of the volatile elemental reactions that take place within the synergy furnace.
        SHOULD_TOO_MUCH_DEBRIS_BE_ALLOWED_TO_ACCUMULATE                         = 17943,  -- Should too much debris be allowed to accumulate, the contents of the furnace will become unstable, potentially leading to unpleasant explosions and eruptions. Such accidents pose considerable risk to the synergy attempt in progress, as well as the physical well-being of the synergist, so be sure to exercise due caution!
        YOU_MAY_BE_ASKING_YOURSELF_WHY_HOW_IN                                   = 17944,  -- You may be asking yourself, Why, how in the name of Hildolf am I going to oversee all of these complicated procedures and variables by myself?
        HERE_S_THE_GOOD_NEWS_YOU_DON_T                                          = 17945,  -- Here's the good news: you don't have to! For you see, synergy furnaces are designed for use by multiple operators.
        THE_MORE_COMPLEX_THE_RECIPE_THE_GREATER_LEVEL                           = 17946,  -- The more complex the recipe, the greater level of skill and hands-on manipulation it will demand. At such times, it would be in your best interest to seek out like-minded synergists and take on the challenge together.
        FINALLY_IT_WOULD_BE_REMISS_OF_ME_NOT                                    = 17947,  -- Finally, it would be remiss of me not to make mention of %, the curious substance whose properties are only now--with the emergence of synergy--becoming known to us.
        THOUGH_THERE_IS_MUCH_YET_TO_BE_LEARNED                                  = 17948,  -- Though there is much yet to be learned, our research has revealed that % may be used to bolster your equipment, if attached in a proper manner.
        MIND_YOU_IS_NOT_EASY_TO_COME_BY                                         = 17949,  -- Mind you, % is not easy to come by, and I can offer no clues as to where or how to obtain it. Should you be fortunate enough to come across some in your travels, however, I encourage you to explore its potential.
        SYNERGY_IS_NOT_A_DISCIPLINE_FOR_THE_FAINT                               = 17950,  -- Synergy is not a discipline for the faint of heart or mind, but with dedication and cooperation, there are great rewards to be reaped. May your career as a synergist prove fruitful!
        FIRST_YOU_LL_BE_WANTING_TO_CHECK_YOUR                                   = 17951,  -- First, you'll be wanting to check your fewell supply. You may do so by speaking with a synergy engineer such as myself, or by examining a synergy furnace.
        YOU_LL_BE_NEEDING_AT_LEAST_ONE_UNIT                                     = 17952,  -- You'll be needing at least one unit of fewell for each element dictated by your recipe. Without this, even the most skilled synergist cannot hope to succeed.
        SHOULD_YOUR_FEWELL_SUPPLY_BE_IN_ORDER_IT                                = 17953,  -- Should your fewell supply be in order, it's time to proceed with the synergy. If you are using one of these public synergy furnaces here, you'll need to examine it and lay claim to its use.
        YOU_MAY_THEN_DEPOSIT_YOUR_INGREDIENTS_SHOULD_THEY                       = 17954,  -- You may then deposit your ingredients. Should they correspond to a proper recipe, the synergy furnace will fire up automatically. Note that as a safety precaution, the furnace will not activate if the recipe is beyond your level of synergy skill.
        FROM_HERE_IT_BECOMES_A_RACE_AGAINST_THE                                 = 17955,  -- From here, it becomes a race against the clock! Through skilled operation of the synergy furnace, you must achieve the elemental balance prescribed by the recipe before the furnace's durability fails.
        FORTUNATELY_SYNERGY_FURNACES_ARE_OUTFITTED_WITH_A_WIDE                  = 17956,  -- Fortunately, synergy furnaces are outfitted with a wide array of features designed to aid the synergist in this demanding task. First, you'll want to confirm the current balance of elements within the furnace and compare it to your desired result.
        NEXT_YOU_CAN_BEGIN_TO_FEED_FEWELL_INTO                                  = 17957,  -- Next, you can begin to feed fewell into the furnace to gradually raise the level of elemental concentration. Feeding fewell into the furnace until the required elemental balance is achieved is the most fundamental operation of synergy.
        HOWEVER_HIGH_CONCENTRATIONS_OF_ELEMENTAL_POWER_CAN_LEAD                 = 17958,  -- However, high concentrations of elemental power can lead to volatile and unpredictable reactions. Simply adding fewell haphazardly without making the necessary adjustments is a recipe for only one thing, and that's disaster.
        IF_YOU_SENSE_THAT_THE_FURNACE_IS_ON                                     = 17959,  -- If you sense that the furnace is on the verge of elemental overload, you'll want to employ the safety lever and pressure handle to prevent an unfortunate accident from occurring.
        YOU_LL_ALSO_WANT_TO_MIND_THE_LAWS                                       = 17960,  -- You'll also want to mind the laws of elemental ascendancy and opposition. Increasing the concentration of a particular element will cause its counterpart to decrease.
        THE_FURNACE_CANNOT_SUSTAIN_ITS_POWER_INDEFINITELY_AND                   = 17961,  -- The furnace cannot sustain its power indefinitely, and will gradually lose durability as the synergy process continues. You'll need to perform periodic furnace repair should the furnace near its breaking point.
        IT_IS_ALSO_POSSIBLE_TO_RECYCLE_STREWN_FEWELL                            = 17962,  -- It is also possible to recycle strewn fewell during synergy. While this will not impact the success or failure of the process itself, it will result in a greater amount of salvageable cinder produced as a by-product.
        THIS_CINDER_IS_OF_GREAT_INTEREST_TO_OUR                                 = 17963,  -- This cinder is of great interest to our researchers back at the institute. As such, we have introduced a reward system through which quality samples can be traded in for an assortment of synergy-related wares.
        AS_MARVELOUS_AN_APPARATUS_AS_THE_SYNERGY_FURNACE                        = 17964,  -- As marvelous an apparatus as the synergy furnace may be, keep in mind that the technology is still in its infancy, and highly unstable. There may be times when accidents occur despite the best efforts of the synergist.
        FOR_YOUR_SAFETY_WE_RECOMMEND_STEPPING_AS_FAR                            = 17965,  -- For your safety, we recommend stepping as far away from the furnace as possible at the first sign of danger. Some synergists claim that giving the furnace a good thwack is also effective in preventing such accidents, but this is pure madness, if you ask me!
        YOU_WILL_ALSO_FIND_THAT_THERE_ARE_NUMEROUS                              = 17966,  -- You will also find that there are numerous techniques that can be applied to make the synergy procedure go even more smoothly.
        IN_MANY_CASES_EXPERTISE_AND_KNOWLEDGE_ACQUIRED_THROUGH                  = 17967,  -- In many cases, expertise and knowledge acquired through crafting will serve you in synergy as well. To truly master synergy, one must master crafting as well.
        NOW_LET_US_RETURN_TO_THE_SYNERGY_PROCESS                                = 17968,  -- Now let us return to the synergy process itself. As your elemental balance approaches that prescribed by the recipe, the furnace will signal you, and you may retrieve your finished product.
        IF_THE_FURNACE_IS_STILL_HOLDING_STRONG_AT                               = 17969,  -- If the furnace is still holding strong at this time, you may choose to keep working to achieve an even closer balance. The closer you come to the ideal balance, the higher the quality of your finished product will be.
        INDEED_MANY_SYNERGY_MASTERS_CONSIDER_THESE_WANING_MOMENTS               = 17970,  -- Indeed, many synergy masters consider these waning moments after the signal to be the time to really show off their skills! Why, if they manage to achieve an elemental surge...
        WHAT_S_AN_ELEMENTAL_SURGE_YOU_ASK_WHY                                   = 17971,  -- What's an elemental surge, you ask? Why, it's a miraculous phenomenon that occurs rarely--ever so rarely--upon feeding the furnace fewell.
        THE_ELEMENTS_REACT_JUST_IN_THE_RIGHT_WAY                                = 17972,  -- The elements react just in the right way, creating a miraculous reaction that brings the level of elemental concentration to exactly the desired level. Truly a boon from the Goddess for any synergist, no?
        AND_THAT_IS_THE_SYNERGY_PROCESS_IN_A                                    = 17973,  -- ...And that is the synergy process in a nutshell. There's quite a bit of information to take in, so don't hesitate to return any time for a refresher course.
        MUCH_LIKE_SYNTHESIS_TO_FASHION_ITEMS_THROUGH_SYNERGY                    = 17974,  -- Much like synthesis, to fashion items through synergy, you will need to follow a recipe. We synergy engineers are always unearthing new recipes, and are happy to share with you those suitable for your level of skill.
        UNLIKE_SYNTHESIS_HOWEVER_A_SYNERGY_RECIPE_IS_MORE                       = 17975,  -- Unlike synthesis, however, a synergy recipe is more than just a list of ingredients. There is also a required elemental balance that must be attained to achieve your desired result.
        SIMPLE_RECIPES_INVOLVE_ONLY_SMALL_DOSES_OF_A                            = 17976,  -- Simple recipes involve only small doses of a limited number of elements, but more complex ones require the synergist to skillfully juggle wide ranges of elements in extremely high concentrations.
        THE_INGREDIENTS_YOU_WILL_HAVE_TO_REMEMBER_ON                            = 17977,  -- The ingredients, you will have to remember on your own. The required elemental balance, however, may be reviewed at any time during the synergy process by observing the readings on the synergy furnace.
        IN_PARTICULAR_RECIPES_THROUGH_WHICH_THE_CURIOUS_SUBSTANCE               = 17978,  -- In particular, recipes through which the curious substance known as % can be attached to equipment are creating quite a buzz among synergistically inclined adventurers these days.
        CANNOT_BE_ATTACHED_DIRECTLY_FIRST_EQUIPMENT_MUST_BE                     = 17979,  -- % cannot be attached directly. First, equipment must be prepared by etching an aperture into which an elementally compatible piece of % can then be embedded.
        THE_TYPE_OF_APERTURE_THAT_MAY_BE_ETCHED                                 = 17980,  -- The type of aperture that may be etched will depend on the piece of equipment. There are also pieces of equipment that, alas, may not be modified at all.
        IF_YOU_ARE_CURIOUS_WHAT_MANNER_OF_APERTURE                              = 17981,  -- If you are curious what manner of aperture may be etched into a particular piece of equipment, you need only trade it to me or one of my colleagues.
        AS_A_GENERAL_RULE_THE_HIGHER_THE_LEVEL                                  = 17982,  -- As a general rule, the higher the level of the item in question, the more difficult the synergy process for creating an aperture will be.
        YOU_WILL_FIND_THAT_CERTAIN_PIECES_OF_EQUIPMENT                          = 17983,  -- You will find that certain pieces of equipment may be etched with multiple apertures. It is, however, only possible to create one aperture at a time.
        ETCHING_REQUIRES_THE_USE_OF_A_CORROSIVE_SUBSTANCE                       = 17984,  -- Etching requires the use of a corrosive substance we call mordant. Deposit mordant into a synergy furnace along with your equipment, and the process will begin.
        MY_COLLEAGUES_AND_I_HAVE_A_STOCK_OF                                     = 17985,  -- My colleagues and I have a stock of mordant available for sale. The best way to learn is to practice, so if you're curious, we encourage you to purchase some and begin experimenting!
        THE_DIFFICULTY_OF_THE_SYNERGY_PROCESS_WHEN_EMBEDDING                    = 17986,  -- The difficulty of the synergy process when embedding evolith is decided by a number of factors.
        SUCH_FACTORS_INCLUDE_THE_VARIETY_OF_APERTURE_AND                        = 17987,  -- Such factors include the variety of aperture and evolith, as well as the quantity of evolith you seek to attach. Embedding the first piece is not too difficult a task, but the second and third pieces will not go in so easily.
        TO_BEGIN_THE_EMBEDDING_PROCESS_DEPOSIT_YOUR_EVOLITH                     = 17988,  -- To begin the embedding process, deposit your evolith into the synergy furnace along with a piece of equipment with a compatible aperture.
        WHEN_ETCHING_OR_EMBEDDING_THE_REQUIRED_ELEMENTAL_BALANCE                = 17989,  -- When etching or embedding, the required elemental balance may be confirmed at any time during the synergy process, so let this be your guide.
        SHOULD_YOU_EVER_WISH_TO_REMOVE_ANY_APERTURES                            = 17990,  -- Should you ever wish to remove any apertures and embedded evolith from a piece of equipment entirely, you may do so with an ingredient we call revertant.
        TOSS_THE_REVERTANT_IN_A_SYNERGY_FURNACE_ALONG                           = 17991,  -- Toss the revertant in a synergy furnace along with your equipment, and its potent powers will restore your item to a pure and pristine state! Be warned, however, that embedded evolith will be lost forever in the process.
        AS_YOU_ARE_NO_DOUBT_ALREADY_AWARE_SYNERGY                               = 17992,  -- As you are no doubt already aware, synergy makes use of a highly combustible form of elemental crystals that we call fewell. The more complex the recipe, the greater the quantity of fewell required.
        VETERAN_SYNERGISTS_KNOW_WELL_THE_HASSLE_OF_HAVING                       = 17993,  -- Veteran synergists know well the hassle of having to constantly monitor their fewell supply and procure crystals to replenish depleted stock.
        TO_FREE_YOU_OF_SUCH_TRIFLING_BURDENS_AND                                = 17994,  -- To free you of such trifling burdens and allow you to focus your mind entirely on your art, we synergy engineers are offering a convenient fewell replenishment service!
        FOR_A_NOMINAL_FEE_CALCULATED_BASED_UPON_THE                             = 17995,  -- For a nominal fee calculated based upon the current state of your fewell reserves, we will instantly refill you to full capacity.
        THAT_S_RIGHT_ALL_ELEMENTS_IN_ONE_SIMPLE                                 = 17996,  -- That's right--all elements in one simple transaction, directly to your %! What could be easier?
        LOOKING_TO_FIRE_UP_YOUR_FURNACE_AND_ENTER                               = 17997,  -- Looking to fire up your furnace and enter the world of %? If so, you've come to the right place!
        WE_RE_PROUD_TO_OFFER_A_SUPPLY_OF                                        = 17998,  -- We're proud to offer a supply of the corrosive agent known as mordant for sale. With this, synergy newcomers can hone their skills and outfit their equipment with evolith-capable apertures in the process.
        MIND_YOU_OUR_STOCK_IS_LIMITED_TO_ONLY                                   = 17999,  -- Mind you, our stock is limited to only the most diluted, readily produced form of the stuff. You'll find that it only has the strength to etch items of relatively low level.
        ETCHING_HIGH_POWERED_EQUIPMENT_REQUIRES_THE_USE_OF                      = 18000,  -- Etching high-powered equipment requires the use of more concentrated and potent forms of mordant. As quantities are limited, we can offer these only in exchange for cinder.
        AH_SYNERGY_TECHNIQUES_THOSE_HANDY_TRICKS_OF_THE                         = 18001,  -- Ah, synergy techniques! Those handy tricks of the trade that can mean the difference between a shiny new item and a major furnace meltdown.
        MY_COLLEAGUES_AND_I_ARE_ALWAYS_EAGER_TO                                 = 18002,  -- My colleagues and I are always eager to train fellow synergists in a wide range of techniques. We can't do it all, though--you'll need to hone your synergy skill in order to benefit from our instruction.
        BEAR_IN_MIND_THAT_CERTAIN_TECHNIQUES_CAN_ONLY                           = 18003,  -- Bear in mind that certain techniques can only be imparted to students possessing specialized crafting knowledge. For example, only skilled smiths will be able to comprehend the method for more efficient fewell feeding.
        ACCOMPLISHED_GOLDSMITHS_WILL_BE_ABLE_TO_OBSERVE_THE                     = 18004,  -- Accomplished goldsmiths will be able to observe the inner workings of the furnace and stave off potential accidents. You will find that all crafting skills--even those you may not expect--may be applied in some way to support the synergy process.
        WORD_HAS_IT_THAT_THERE_ARE_ALSO_PIECES                                  = 18005,  -- Word has it that there are also pieces of equipment that can impart hidden synergy techniques to the wearer. These, too, are said to be only accessible to skilled crafters.
        THE_MORAL_OF_THE_STORY_IS_THIS_WHILE                                    = 18006,  -- The moral of the story is this: while synergy skill is important, neglect not your other crafting skills. To become a true synergy master, finding the proper balance is key.
        SYNERGY_REMAINS_A_YOUNG_DISCIPLINE_AND_RESEARCHERS_BACK                 = 18007,  -- Synergy remains a young discipline, and researchers back at the institute are burning the midnight fewell in the hopes of uncovering the next breakthrough in our field.
        RESEARCH_OF_LATE_IS_CENTERED_AROUND_THE_CINDER                          = 18008,  -- Research of late is centered around the cinder that is left behind as a by-product of each synergy operation. Their composition, it would seem, has much to teach us of the true nature of the complex elemental reactions that go on within the bellies of these furnaces.
        WE_VE_EVEN_INSTITUTED_A_REWARD_PROGRAM_FOR                              = 18009,  -- We've even instituted a reward program for adventurers willing to contribute prime samples in the name of science.
        IT_WOULD_BE_NO_EXAGGERATION_TO_SAY_THAT                                 = 18010,  -- It would be no exaggeration to say that, to us, cinder is worth more than its weight in gold! Bring it to me or my colleagues--preferably in large quantities--and you're sure to be pleased at what we can offer you in return.
        WONDERING_IF_YOUR_CAN_BE_OUTFITTED_WITH_EVOLITH                         = 18011,  -- Wondering if your % can be outfitted with evolith, are you? Well, you've come to the right place!
        A_QUICK_LOOK_AT_ITS_COMPOSITION_SHOULD_TELL                             = 18012,  -- A quick look at its composition should tell us all we need to know. Let's see here...
        CONGRATULATIONS_YOUR_CAN_INDEED_HOLD_EVOLITH_APERTURE_A                 = 18013,  -- Congratulations! Your % can indeed hold [an/another] evolith aperture. A %-shaped aperture, to be exact...
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZE_AND                          = 18014,  -- ...Suitable for evolith of the following size and elemental affinity: Maximum size: # / [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND                         = 18015,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_2                       = 18016,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_3                       = 18017,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        THAT_IS_ALL_SHOULD_YOU_WISH_TO_HAVE                                     = 18018,  -- That is all. Should you wish to have any other pieces of equipment analyzed, you know where to find us.
        HMM_I_M_AFRAID_YOUR_CANNOT_HOUSE_ANY                                    = 18019,  -- Hmm... I'm afraid your % cannot house any more apertures.
        ALAS_IT_S_A_SHAME_BUT_IT_APPEARS                                        = 18020,  -- ...Alas. It's a shame, but it appears your % cannot be etched.
        HMM_WHAT_S_THIS_IT_WOULD_SEEM_THAT                                      = 18021,  -- Hmm, what's this? It would seem that your % cannot be etched at this time.
        DO_YOU_LOVE_SYNERGIZING_AS_MUCH_AS_I                                    = 18022,  -- Do you love synergizing as much as I love synergizing!? 'Cause if you do, you're gonna loooooove the recipes I have for you!
        VIEW_RECIPES_FOR_WHICH_SKILL_LEVEL_ACTUALLY_NEVER                       = 18023,  -- View recipes for which skill level? Actually, never mind. Amateur. Recruit. Initiate. Novice. Apprentice. Journeyman. Craftsman. Artisan. Adept. Veteran.
        BROWSE_TO_WHICH_PAGE_CANCEL_PAGE_PAGE_PAGE                              = 18024,  -- Browse to which page? Cancel. Page [1/9/17/25/33/41/49/57/65/73/81/89/97/105/113/121]. Page [2/10/18/26/34/42/50/58/66/74/82/90/98/106/114/122]. Page [3/11/19/27/35/43/51/59/67/75/83/91/99/107/115/123]. Page [4/12/20/28/36/44/52/60/68/76/84/92/100/108/116/124]. Page [5/13/21/29/37/45/53/61/69/77/85/93/101/109/117/125]. Page [6/14/22/30/38/46/54/62/70/78/86/94/102/110/118/126]. Page [7/15/23/31/39/47/55/63/71/79/87/95/103/111/119/127]. Page [8/16/24/32/40/48/56/64/72/80/88/96/104/112/120/128]. Previous page. Next page.
        VIEW_WHICH_RECIPE_P_NONE_RETURN_TO_PAGE                                 = 18025,  -- View which recipe? ([Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran], p. #). None. %. %. %. %. %. %. %. %. Return to page selection. Previous page. Next page.
        OH_THE_WHY_THAT_S_ONE_OF_MY                                             = 18026,  -- Oh, the %? Why, that's one of my favorite recipes, too! What skills does it require? Let's see here...
        WELL_LOOK_AT_THIS_ALL_YOU_NEED_IS                                       = 18027,  -- Well, look at this. All you need is a furnace and your own Goddess-given synergy skills to make that one! Ain't synergy grand?
        WAIT_NO_DON_T_TELL_ME_YOU_STRIKE                                        = 18028,  -- Wait! No, don't tell me. You strike me as a man/woman] who's looking to learn a thing or two about synergy.
        LEARN_ABOUT_SYNERGY_NOT_TODAY_TEACH_ME_JUST                             = 18029,  -- Learn about synergy? Not today. Teach me! Just give me %.
        A_LIFE_WITHOUT_INTELLECTUAL_CURIOSITY_IS_A_LIFE                         = 18030,  -- A life without intellectual curiosity is a life hardly worth living. Should your eyes one day open to this truth, you are free to return.
        I_THOUGHT_YOU_D_NEVER_ASK_SYNERGY_IS                                    = 18031,  -- I thought you'd never ask! Synergy is both an art and a science: an evolution--nay, a revolution--in synthesis.
        USING_IN_CONJUNCTION_WITH_A_SYNERGY_FURNACE_THE                         = 18032,  -- Using % in conjunction with a synergy furnace--the apparatus you see beside me--the synergist wields the power of myriad elements to fabricate a veritable host of potent items.
        WHAT_WE_CALL_SERVES_TO_DISPENSE_FEWELL_CRYSTALS                         = 18033,  -- What we call % serves to dispense fewell crystals--the lifeblood of the synergy process--whilst also protecting its contents from the volatile reactions that occur within the bowels of the furnace.
        SYNERGY_FURNACES_HAVE_BEEN_INSTALLED_THROUGHOUT_THE_CITY                = 18034,  -- Synergy furnaces have been installed throughout the city for the use of all synergists. The crucible is sufficiently compact and lightweight that you can carry it with you.
        INITIATING_THE_SYNERGY_PROCESS_IS_AS_SIMPLE_AS                          = 18035,  -- Initiating the synergy process is as simple as inserting your % into a furnace and commencing the infusion of elemental fewell.
        NEEDLESS_TO_SAY_WHAT_WILL_HAPPEN_FROM_THERE                             = 18036,  -- Needless to say, what will happen from there is not quite so simple.
        SUCCESSFUL_SYNERGY_IS_CONTINGENT_UPON_MAINTAINING_ELEMENTAL_EQUILIBRIUM = 18037,  -- Successful synergy is contingent upon maintaining elemental equilibrium. The prescribed ratio, of course, will vary depending on the artifact you are attempting to create.
        YOU_CAN_INCREASE_THE_RATIO_OF_A_PARTICULAR                              = 18038,  -- You can increase the ratio of a particular element by burning the corresponding variety of fewell.
        BUT_HEREIN_LIES_THE_RUB_SYNERGY_IS_A                                    = 18039,  -- But herein lies the rub: synergy is a still young science, and the technology we employ remains, shall we say...unstable.
        A_BIT_TOO_MUCH_FEWELL_HERE_A_WRONG                                      = 18040,  -- A bit too much fewell here, a wrong lever pulled there, and the percolating pot will explode, spitting scalding elemental guck every which way to Firesday.
        THAT_S_WHY_SMART_SYNERGISTS_SYNERGIZE_IN_NUMBERS                        = 18041,  -- That's why smart synergists synergize in numbers. Too many culinarians might spoil the broth, but when it comes to synergy, it's the more the merrier!
        AN_ASPIRING_SYNERGIST_I_SEE_IF_YOU_RE                                   = 18042,  -- An aspiring synergist, I see! If you're looking for %, you've certainly come to the right place.
        I_CAN_SELL_YOU_A_SPLENDID_ENTRY_LEVEL                                   = 18043,  -- I can sell you a splendid entry-level model for # gil. A small price to pay to embark on a lifelong journey of scientific discovery, wouldn't you say?
        GIL_PAID_IN_FULL                                                        = 18044,  -- # gil, paid in full!
        AS_PROMISED_HERE_S_YOUR_AND_BECAUSE_I                                   = 18045,  -- As promised, here's your %. And because I like your enthusiasm, I've even stocked it to the brim with fewell for you! How's that for a deal?
        THE_SYNERGIST_MUST_PROVIDE_HIS_OR_HER_OWN_2                             = 18046,  -- The synergist must provide his or her own %, as well as any materials to be used in the synergy process. Synergy furnaces themselves may be used free of charge.
        SHOULD_YOU_WISH_TO_LEARN_MORE_ABOUT_THE                                 = 18047,  -- Should you wish to learn more about the science of synergy, seek out one of the engineers stationed throughout the town.
        HALT_YOU_D_BEST_HAVE_A_GOOD_EXPLANATION                                 = 18048,  -- Halt! You'd best have a good explanation why you're skulking about Chateau d'Oraguille, rabble.
        A_LETTER_HAND_THAT_OVER_THIS_INSTANT                                    = 18049,  -- A letter? Hand that over this instant!
        I_SHALL_RETURN_IN_A_MOMENT_WANDER_NOT                                   = 18050,  -- I shall return in a moment. Wander not an ilm from where you stand!
        MONARLAIS_HALVER_WILL_SEE_YOU_TO_THE_CASTLE                             = 18051,  -- Monarlais Halver will see you. To the castle with you at once, and no detours!
        WELL_MET_HOW_FARE_YOU_THESE_DAYS                                        = 18052,  -- Well met, %. How fare you these days?
        A_LETTER_AND_THIS_SEAL                                                  = 18053,  -- A letter? And this seal...
        SO_THE_SERPENT_WOULD_SEEK_THE_AID_OF                                    = 18054,  -- ...So the serpent would seek the aid of the lion. A curious turn of events, indeed. I must deliver this to my king at once. Come along.
        SO_THE_SERPENT_WOULD_SEEK_THE_AID_OF_2                                  = 18055,  -- ...So the serpent would seek the aid of the lion. A curious turn of events, indeed. I must deliver this to my king at once. Come along.
        AN_IRON_GIANT_WITH_THE_POWER_TO_SMITE                                   = 18056,  -- An iron giant with the power to smite an airship from the sky, and a young Empress who would nonetheless seek to restore its power...
        ID_18057                                                                = 18057,  -- ...
        I_WOULD_HEAR_YOUR_COUNSEL_HALVER                                        = 18058,  -- I would hear your counsel, Halver.
        YOUR_HIGHNESS_I_MUST_CONFESS_MY_HEART_MISGIVES                          = 18059,  -- Your Highness. I must confess, my heart misgives me as to the wisdom of this endeavor...
        HALVER                                                                  = 18060,  -- Halver...!
        THIS_IS_THE_SELFSAME_EMPIRE_AFTER_ALL_THAT                              = 18061,  -- This is the selfsame Empire, after all, that not so long ago did wield the power of this colossus against this Kingdom and our allies.
        THAT_SAID_THEY_HAVE_SINCE_MADE_AMENDS_AND                               = 18062,  -- That said, they have since made amends, and we have accepted their formal apology. To hold past misdeeds against them now would be most...unchivalrous...of us, would it not?
        AND_YET_THE_PAST_CANNOT_BE_SO_READILY                                   = 18063,  -- ...And yet the past cannot be so readily forgotten.
        BEGGING_YOUR_PARDON_MY_PRINCE_I_DARESAY_THAT                            = 18064,  -- Begging your pardon, my prince. I daresay that the mere fact that they seek our consent--rather than engaging in devious and furtive plots--shows that we deal no longer with the Silent Empire of old.
        SETTLE_YOURSELF_HALVER_I_SAID_NOTHING_OF_DENYING                        = 18065,  -- Settle yourself, Halver. I said nothing of denying their plea.
        FORGIVE_ME_MY_PRINCE_I_SPOKE_IN_HASTE                                   = 18066,  -- Forgive me, my prince. I spoke in haste.
        IT_IS_PRECISELY_BECAUSE_I_REMEMBER_WELL_THE                             = 18067,  -- It is precisely because I remember well the past that I believe the Empire's plea to be sincere.
        IT_IS_CLEAR_THIS_EMPRESS_NASHMEIRA_TRULY_INTENDS                        = 18068,  -- It is clear this Empress Nashmeira truly intends to lead her nation to a new age. I have no doubt that she will prove a staunch ally worthy of our trust.
        OHO_NEVER_DID_I_THINK_THIS_DAY_WOULD                                    = 18069,  -- Oho! Never did I think this day would come, but I must say...my brother has the right of it.
        BESIDES_WERE_SOMETHING_TO_GO_AMISS_THE_PRESENCE                         = 18070,  -- Besides, were something to go amiss, the presence of % here should suffice to keep matters in hand.
        I_COULD_NOT_AGREE_MORE_MY_KING                                          = 18071,  -- I could not agree more, my king
        HAS_SERVED_THE_KINGDOM_WITH_LOYALTY_AND_VALOR                           = 18072,  -- % has served the Kingdom with loyalty and valor time and again.
        I_TOO_CAN_VOUCH_FOR_THIS_FATHER                                         = 18073,  -- I, too, can vouch for this, Father.
        I_HAVE_FOUGHT_BY_S_SIDE_AND_YOU                                         = 18074,  -- I have fought by %'s side, and you will find no comrade more honorable.
        THE_KINGDOM_IS_SAFE_IN_HIS_HER_HANDS                                    = 18075,  -- The Kingdom is safe in his/her] hands, Father.
        VERY_WELL_2                                                             = 18076,  -- Very well.
        HALVER_AND_MY_SONS_PRESENT_A_COMPELLING_CASE                            = 18077,  -- Halver and my sons present a compelling case. Return to this Empress, and tell her San d'Oria stands with her. Now farewell, and may the Goddess watch over your journey!
        BESIDES_WERE_SOMETHING_TO_GO_AMISS_THE_PRESENCE_2                       = 18078,  -- Besides, were something to go amiss, the presence of % here should suffice to keep matters in hand.
        HALVER_AND_MY_SON_PRESENT_A_COMPELLING_CASE                             = 18079,  -- Halver and my son present a compelling case. Return to this Empress, and tell her San d'Oria stands with her. Now farewell, and may the Goddess watch over your journey!
        YES_IS_THERE_SOMETHING_YOU_NEED                                         = 18080,  -- Yes? Is there something you need?
        DO_YOU_HAVE_A_QUESTION_NOT_REALLY_ABOUT                                 = 18081,  -- Do you have a question? Not really. About your father... About your grandfather...
        FATHER_HE_SAID_HE_HAD_BUSINESS_AT_THE                                   = 18082,  -- Father? He said he had business at the weaponseller's in the southern part of town. Are you an acquaintance of his?
        HE_S_SO_ENGROSSED_IN_HIS_BLADES_THAT                                    = 18083,  -- He's so engrossed in his blades that he's not given me a swordfighting lesson in weeks! At this rate, I shall never become a knight...
        I_AM_LOATH_TO_BOAST_BUT_HIS_KNOWLEDGE                                   = 18084,  -- I am loath to boast, but his knowledge of armor and weaponry is second to none in the Kingdom. Helbort often consults with him about rare orders.
        YOU_VE_HEARD_OF_GRANDFATHER_THAT_DOES_NOT                               = 18085,  -- You've heard of Grandfather? That does not surprise me. He was, after all, an angler of no small repute.
        WHY_IN_HIS_YOUNGER_DAYS_HE_WOULD_RISE                                   = 18086,  -- Why, in his younger days, he would rise at the crack of dawn, and hike through Jugner Forest to Lake Mechieume. There, he would lose himself in fishing until sunset. Remarkable devotion, is it not?
        OH_WOULD_THAT_I_COULD_GO_ON_SUCH                                        = 18087,  -- Oh, would that I could go on such a fishing trip with my own father! Alas, it seems he did not inherit Grandfather's love for the sport...
        BE_THIS_YOUR_FIRST_VISIT_TO_THE_CATHEDRAL                               = 18088,  -- Be this your first visit to the cathedral? All of Altana's children are welcome here.
        HMM_PRAY_EXCUSE_ME_BUT_I_COULD_NOT                                      = 18089,  -- Hmm? Pray excuse me, but I could not help but notice your interest in that man.
        HIS_IS_A_HEART_RENDING_TALE_HE_SEEKS                                    = 18090,  -- His is a heart-rending tale. He seeks absolution for his callous treatment of a distraught young lady. As her name is unknown to him, he refers to her only as the red-haired maiden.
        YOUNG_MAN_NARY_A_DAY_PASSES_BY_THAT                                     = 18091,  -- Young man. Nary a day passes by that you are not here, offering words of prayer. Surely, such devotion shall not go unnoticed by the Goddess.
        SIGH_I_SINCERELY_WISH_THAT_IT_WERE_SO                                   = 18092,  -- <Sigh> I sincerely wish that it were so, friar. Then I might have peace in my heart once more...
        I_SHALL_RETURN_TO_ADDING_MY_PRAYERS_TO                                  = 18093,  -- I shall return to adding my prayers to those of others.
        MAY_PARADISE_OPEN_ITS_GATES_TO_YOU_4                                    = 18094,  -- May Paradise open its gates to you.
        YOU_SEEK_THE_YOUNG_MAN_FROM_A_MOMENT                                    = 18095,  -- You seek the young man from a moment ago? I'm made to understand he was headed for Laborman's Way.
        HM_AREN_T_YOU_THE_ADVENTURER_FROM_THE                                   = 18096,  -- Hm? Aren't you the adventurer from the cathedral?
        YOU_WISH_TO_KNOW_MORE_OF_THE_MAIDEN                                     = 18097,  -- You...wish to know more of the maiden? It appears my sad exploits have attained notoriety far and wide...
        VERY_WELL_I_HAVE_NO_REASON_TO_CONCEAL                                   = 18098,  -- Very well. I have no reason to conceal this from you. On the contrary, I welcome it that more people would know me for the contemptible wretch that I am.
        WHAT_THAT_FAIR_MAIDEN_IS_YOUR_FRIEND_PLEASE                             = 18099,  -- What!? That fair maiden...is your friend!? Please, you must tell me where I might find her!
        SO_NOT_EVEN_YOU_KNOW_OF_HER_WHEREABOUTS                                 = 18100,  -- So not even you know of her whereabouts... I suppose there is no help for that.
        ALLOW_ME_TO_RECOUNT_MY_TALE_THEN_AS                                     = 18101,  -- Allow me to recount my tale then, as promised.
        IT_ALL_BEGAN_THE_DAY_PAST_WHEN_I                                        = 18102,  -- It all began the day past when I went to attend a sermon at the cathedral.
        THAT_WAS_WHEN_I_FIRST_CAUGHT_SIGHT_OF                                   = 18103,  -- That was when I first caught sight of her, as she stepped through the doors, bathed in the radiant light of morn.
        TRITE_THOUGH_THIS_MUST_SOUND_NEVER_BEFORE_HAD                           = 18104,  -- Trite though this must sound, never before had I laid eyes upon such fairness. I still remember well the ornament that adorned her fiery hair...
        BUT_ABOVE_ALL_I_REMEMBER_THE_DEEP_SORROW                                = 18105,  -- But above all, I remember the deep sorrow that was graven upon her face. To simply imagine the pain that racked her gentle heart sent a dagger sliding through mine own.
        THE_INTENSITY_OF_MY_EMOTIONS_WAS_SUCH_THAT                              = 18106,  -- The intensity of my emotions was such that I could not help but reach out to her.
        B_BEG_PARDONS_MY_LADY_IF_I_MIGHT                                        = 18107,  -- B-beg pardons, my lady! If I might have a m-m-moment...
        HAVE_WE_MET                                                             = 18108,  -- Have we met?
        UM_UH_BREATHE_DAMN_YOU_BREATHE_S_S                                      = 18109,  -- Um...uh... (Breathe, damn you! Breathe!) S-s-something weighs heavily on your mind, that much is p-p-plain to see. I should be honored to share that burden, if it p-p-please you.
        TIS_KIND_OF_YOU_TO_OFFER_BUT_I                                          = 18110,  -- 'Tis kind of you to offer, but I would not presume to prevail upon a stranger.
        NO_I_INSIST_IF_THERE_IS_AUGHT_I                                         = 18111,  -- No, I insist! If there is aught I might do to ease your p-p-pain, you need but ask!
        THIS_IS_HIGHLY_UNUSUAL_FOR_ME_BUT_SINCE                                 = 18112,  -- This is...highly unusual for me, but since you insist...
        FOR_TRUE_YOU_VE_NO_IDEA_HOW_MUCH                                        = 18113,  -- For true!? You've no idea how much this m-m-means to me!
        TO_THINK_THAT_THIS_VISION_OF_BEAUTY_WOULD                               = 18114,  -- To think that this vision of beauty would share with me her deepest hurts! I was above the moon with joy! That is, until she launched into her story...
        SHE_CLAIMED_TO_BE_A_CHAMPION_OF_THE                                     = 18115,  -- She claimed to be a Champion of the Dawn, possessed of the ability to travel to the past. Powerful enemies had come from an alternate reality, and she was battling against them to ensure the survival of our world.
        IN_THE_MIDST_OF_THE_STRUGGLE_HOWEVER_SOMEONE                            = 18116,  -- In the midst of the struggle, however, someone dear to her fell into enemy hands. And to compound matters, those who once cared for her lost all memory of her existence.
        SIGH_I_CONSIDER_MYSELF_WORLDLY_AND_WELL_TRAVELED                        = 18117,  -- <Sigh>... I consider myself worldly and well-traveled, but naught could've prepared me for the words that spilled from her lips.
        AT_SOME_POINT_IN_TIME_I_CANNOT_SAY                                      = 18118,  -- At some point in time--I cannot say exactly when--bemusement turned into amusement, and I decided that all of it was a great big fairy tale.
        I_FOUND_MYSELF_STARING_AT_HER_WIDE_EYED                                 = 18119,  -- I found myself staring at her wide-eyed, nodding dutifully as the events--each more fantastical and ridiculous than the last--were regaled to me in intricate detail.
        AND_THEN_THE_GUILLOTINE_FELL_I_DID_THAT                                 = 18120,  -- And then the guillotine fell. I did that which cannot be undone.
        HEAHEAHEAHEAHHH                                                         = 18121,  -- Heaheaheaheahhh!!!
        H_HEY_WHAT_S_SO_FUNNY                                                   = 18122,  -- H-hey! What's so funny!?
        M_MERCY_MY_LADY_BUT_ANY_MORE_OF                                         = 18123,  -- M-mercy, my lady, but any more of this and my sides are like to burst!
        WHAT_2                                                                  = 18124,  -- What!?
        I_DON_T_BELIEVE_THIS_YOU_BEG_ME                                         = 18125,  -- I don't believe this! You beg me to share my burden, and I oblige you for what? To have you rain spittle on me with your laughter!?
        HMPH_THAT_S_RIGHT_IT_WAS_ALL_MAKE                                       = 18126,  -- Hmph! That's right, it was all make-believe! That you derived such mirth from my tall tale made it worth the telling! I thank you for your precious time!
        FAREWELL_AND_ATOMOS_TAKE_YOU                                            = 18127,  -- Farewell...and Atomos take you!
        I_MUST_BE_EITHER_LOSING_MY_MIND_OR                                      = 18128,  -- I must be either losing my mind or the biggest fool in the world to think it a good idea to pour my heart out to some boorish stranger.
        ATOMO_WHAT_M_MY_LADY_WHERE_ARE_YOU                                      = 18129,  -- Atomo...what? M-my lady, where are you going?
        IN_HINDSIGHT_THE_GRAVENESS_WITH_WHICH_SHE_TOLD                          = 18130,  -- In hindsight, the graveness with which she told her story ought to have been plain as day, even to this blind dolt.
        WHETHER_OR_NOT_THERE_WAS_TRUTH_TO_HER                                   = 18131,  -- Whether or not there was truth to her words was immaterial. The point is, she believed the genuineness of her tale. As such, it was utterly tactless of me--cruel, rather--to make light of her as I did.
        AH_WHAT_I_WOULDN_T_GIVE_FOR_A                                           = 18132,  -- Ah, what I wouldn't give for a chance to see her again and beg forgiveness...
        YOU_AND_I_SCARCE_KNOW_ONE_ANOTHER_BUT                                   = 18133,  -- You and I scarce know one another, but might I trouble you to...tell me her name? The truth is, I've not been able to sleep at night for want of this knowledge.
        IN_LIGHT_OF_THE_GRIEVOUS_WRONG_I_DID                                    = 18134,  -- In light of the grievous wrong I did your friend, I would not be surprised if you were to begrudge me this favor. Yet I must ask that you take pity on me.
        TELL_HIM_LILISETTE_S_NAME_AYE_THE_POOR                                  = 18135,  -- Tell him Lilisette's name? Aye, the poor sod seems repentant. Nay, leave him to wallow in his misery.
        LILISETTE_A_BEAUTIFUL_NAME                                              = 18136,  -- Lilisette... A beautiful name...
        P_PLEASE_I_BEG_OF_YOU                                                   = 18137,  -- P-please! I beg of you!
        I_OWE_YOU_A_DEBT_OF_GRATITUDE                                           = 18138,  -- I owe you a debt of gratitude.
        HAVING_HAD_THIS_OPPORTUNITY_TO_TALK_TO_YOU                              = 18139,  -- Having had this opportunity to talk to you, it feels as if the weight of the world has been lifted off my shoulders.
        MAY_THE_GODDESS_BLESS_YOU_THRICE_OVER_KIND                              = 18140,  -- May the Goddess bless you thrice over, kind adventurer.
        YOU_OBTAIN_HOWEVER_IT_IS_FAR_TOO_SMALL                                  = 18141,  -- You obtain %. However, it is far too small to house an adequate amount of energy. Alone, it serves no purpose.
        THE_TINY_FRAGMENTS_OF_LILISETTE_S_MEMORY_MELD                           = 18142,  -- The tiny fragments of Lilisette's memory meld together to form %!
        WELCOME_TO_THE_MHMU_S_PORTER_SERVICE_KUPO                               = 18143,  -- Welcome to the MHMU's porter service, kupo! Which of your burdensome belongings shall I take off your hands today?
        DO_SOMETHING_KUPO_PORTER_SERVICE_BUY_A_STORAGE                          = 18144,  -- Do something, kupo? Porter service? Buy a storage slip. No, thank you.
        IS_YOUR_GOBBIEBAG_SPLITTING_AT_THE_SEAMS_MOG                            = 18145,  -- Is your gobbiebag splitting at the seams? Mog Safe spilling over? Why, an accomplished adventurer like yourself surely has more stuff than you know what to do with.
        THAT_S_WHERE_I_COME_IN_KUPO_I                                           = 18146,  -- That's where I come in, kupo. I'll gladly hold onto your prized possessions, freeing you space to gather up even grander goodies.
        TO_MAKE_USE_OF_MY_SERVICES_FIRST_YOU                                    = 18147,  -- To make use of my services, first you'll need to buy one of these storage slips for the low, low fee of # gil.
        STORAGE_SLIPS_COME_IN_NUMEROUS_VARIETIES_KUPO_EACH                      = 18148,  -- Storage slips come in numerous varieties, kupo, each corresponding to a different type of item.
        YOU_LL_WANT_TO_PERUSE_THE_FINE_PRINT                                    = 18149,  -- You'll want to peruse the fine print closely, so you don't end up paying good gil for a scrap of parchment useless for the particular item you wish to store.
        NOT_THAT_WE_MOOGLES_WOULD_OBJECT_TO_THAT                                = 18150,  -- Not that we moogles would object to that sort of donation, kupo.
        CHOOSE_THE_ITEM_YOU_WISH_TO_ENTRUST_THEN                                = 18151,  -- Choose the item you wish to entrust, then trade it to me along with a single storage slip. I will take the item and return the slip to you, marked with an invisible seal.
        INVISIBLE_TO_YOU_AT_LEAST_IT_S_PLAIN                                    = 18152,  -- Invisible to you, at least. It's plain as day to us moogles, so don't even think of trying to pull one over on us, kupo.
        WHEN_IT_COMES_TIME_TO_RETRIEVE_YOUR_ITEM                                = 18153,  -- When it comes time to retrieve your item, just trade to me a single storage slip--any slip--once again.
        I_WILL_PRESENT_YOU_WITH_A_LIST_OF                                       = 18154,  -- I will present you with a list of all the items currently in my care, and you may choose the one you wish to withdraw. Simple as that, kupo!
        WHAT_S_MORE_NO_ADDITIONAL_TRANSACTION_FEES_WILL                         = 18155,  -- What's more, no additional transaction fees will be incurred! Pretty generous of us for a change, no?
        NOW_I_BET_YOU_RE_WONDERING_WHAT_THE                                     = 18156,  -- Now I bet you're wondering what the catch is, kupo. So as not to disappoint you, there are a few!
        FOR_ONE_ANY_SIGNED_ITEMS_WILL_LOSE_THEIR                                = 18157,  -- For one, any signed items will lose their signatures if you store them with me.
        WHY_YOU_SAY_HEY_EVEN_WE_MOOGLES_AREN                                    = 18158,  -- Why, you say? Hey, even we moogles aren't perfect! It's better for both of us if you keep your most precious possessions close at hand, kupo.
        NOW_LISTEN_UP_BECAUSE_THERE_S_ANOTHER_CATCH                             = 18159,  -- Now listen up, because there's another catch, and it's a doozy.
        IF_YOU_LOSE_YOUR_STORAGE_SLIP_I_WON                                     = 18160,  -- If you lose your storage slip, I won't be able to return your item. Ever. No ifs, ands, or buts! No I'm sorry, Mister Porter Moogle, it'll never happen again! Rules are rules, kupo, and someone has to keep them.
        LAST_BUT_NOT_LEAST_I_CAN_T_ACCEPT                                       = 18161,  -- Last, but not least, I can't accept equipment bearing Magian trial insignia.
        IF_YOU_HAVE_SUCH_AN_ITEM_THAT_YOU                                       = 18162,  -- If you have such an item that you're simply dying to entrust to me, you'll have to abandon your trial first, kupo.
        AND_THAT_S_ALL_THERE_IS_TO_IT                                           = 18163,  -- And that's all there is to it. This humble moogle can hardly wait to serve you!
        BUY_SOMETHING_P_PREVIOUS_PAGE_NEXT_PAGE_CANCEL                          = 18164,  -- Buy something? (p. #/#). Previous page. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Next page. Cancel.
        WILL_COST_YOU_GIL_DO_WE_HAVE_A                                          = 18165,  -- % will cost you # gil. Do we have a deal, kupo?
        DEAL_KUPO_CURRENT_GIL_CHECK_STORABLE_ITEMS_DEAL                         = 18166,  -- Deal, kupo? (Current gil: #). Check storable items. Deal. No deal.
        THE_WILL_ALLOW_YOU_TO_STORE_THE_FOLLOWING                               = 18167,  -- The % will allow you to store the following items:
        ID_18168                                                                = 18168,  -- %.
        ID_18169                                                                = 18169,  -- %.
        AND_THAT_S_ALL                                                          = 18170,  -- ...and that's all.
        P_PREVIOUS_PAGE_NEXT_PAGE_CANCEL                                        = 18171,  -- % (p. #/#). Previous page. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Next page. Cancel.
        WARNING_IF_YOU_LOSE_YOUR_WHILE_STORING_A                                = 18172,  -- Warning! If you lose your % while storing a corresponding item, you will be forever unable to retrieve that item!
        IS_THAT_I_SEE_KUPO                                                      = 18173,  -- Is that % I see, kupo?
        WHAT_WILL_YOU_DO_RETRIEVE_AN_ITEM_CONFIRM                               = 18174,  -- What will you do? Retrieve an item. Confirm storable items. Nothing.
        RETRIEVE_AN_ITEM_P_PREVIOUS_PAGE_NEXT_PAGE                              = 18175,  -- Retrieve an item? (p. #/#). Previous page. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. Next page. Cancel.
        RETRIEVE_RETRIEVE_IT_LEAVE_IT                                           = 18176,  -- Retrieve %? Retrieve it. Leave it.
        YOU_RETRIEVE_FROM_THE_PORTER_MOOGLE_S_CARE                              = 18177,  -- You retrieve % from the porter moogle's care.
        KUPO_I_M_ALREADY_TAKING_CARE_OF_THAT                                    = 18178,  -- Kupo? I'm already taking care of that item for you.
        YES_VERY_WELL_YOUR_PRECIOUS_PROPERTY_IS_SAFE                            = 18179,  -- %, yes? Very well! Your precious property is safe with me, kupo!
        OF_ITEM_IS_IT_VERY_WELL_YOUR_PRECIOUS                                   = 18180,  -- # [variety/varieties] of item, is it? Very well! Your precious property is safe with me, kupo!
        IS_THAT_A_MAGIAN_INSIGNIA_I_SEE_ON                                      = 18181,  -- Is that a Magian insignia I see on that %? You'll have to abandon your trial before I can take it off your hands, kupo.
