        HAIL_SOLDIER_I_AM_A_PURVEYOR_TASKED_WITH                                = 18195,  -- Hail, soldier. I am a purveyor tasked with furnishing the brave men and women of the Voidwatch with essential supplies. My wares can be yours, provided you've got [Conquest Points/Imperial Standing/Allied Notes] to trade. After all, we can't afford to let our limited resources go to waste in the hands of some unproven rookie.
        PROCURE_SUPPLIES_NOT_NOW                                                = 18196,  -- Procure supplies? ([Points/Standing/Notes]: #) Not now. % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#). % (#).
        HOW_MANY_NONE_ACTUALLY_ONE_COST_THREE_COST                              = 18197,  -- How many? ([Points/Standing/Notes]: #) None, actually. One (Cost: #). Three (Cost: #), Six (Cost: #). Nine (Cost: #). Twelve (Cost: #).
        THIS_WILL_COST_YOU                                                      = 18198,  -- This % will cost you # [Conquest Points/credits of Imperial Standing/Allied Notes].
        IT_SEEMS_YOU_RE_SHORT_ON_SOLDIER_COME                                   = 18199,  -- It seems you're short on [Conquest Points/Imperial Standing credits/Allied Notes], soldier. Come back when you've got a bit more seasoning under your belt.
        PROCEED_REQUIRED_YES_NO                                                 = 18200,  -- Proceed? (Required [Points/Standing/Notes]: #) Yes. No.
        OBTAINS_IN_EXCHANGE_FOR                                                 = 18201,  -- % obtains % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        OBTAINS_IN_EXCHANGE_FOR_2                                               = 18202,  -- % obtains # % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        OBTAINS_IN_EXCHANGE_FOR_3                                               = 18203,  -- % obtains % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        THIS_WILL_COST_YOU_2                                                    = 18204,  -- This % will cost you # [Conquest Points/credits of Imperial Standing/Allied Notes].
        YOU_ALREADY_HAVE_AND_I_M_NOT_AUTHORIZED                                 = 18205,  -- You already have %, and I'm not authorized to furnish you with another. Resources are in short supply. You'll have to make do with what you've already got.
        HOW_MANY                                                                = 18214,  -- How many? ( [Conquest Points/Imperial Standing/Allied Notes]: #)
        YOU_MAY_PURCHASE_UP_TO_AT_A_TIME                                        = 18215,  -- You may purchase up to # at a time.
        HAVE_YOU_HEARD_WHAT_S_GOING_ON_IN                                       = 18216,  -- Have you heard what's going on in Adoulin, the land to the west?
        I_HAVE_THINGS_ARE_STARTING_TO_HEAT_UP                                   = 18217,  -- I have. Things are starting to heat up. But can you imagine? Pioneering new lands in this day and age?
        WHAT_IN_VANA_DIEL_COULD_THEY_POSSIBLY_BE                                = 18218,  -- What in Vana'diel could they possibly be thinking? The lands are filled with airships, yet they pretend at being trailblazers.
        THE_WHOLE_AFFAIR_CERTAINLY_SEEMS_LUDICROUS_ENOUGH_NOT                   = 18219,  -- The whole affair certainly seems ludicrous enough. Not like it affects us here, though.
        ONLY_ADVENTURERS_WOULD                                                  = 18220,  -- Only adventurers would--
        HM_CAN_I_HELP_YOU                                                       = 18221,  -- Hm? Can I help you?
        WHAT_S_THIS_NOW_YOU_WANT_TO_KNOW                                        = 18222,  -- What's this now? You want to know more about the colonization project?
        SORRY_BUT_WE_RE_AS_MUCH_IN_THE                                          = 18223,  -- Sorry, but we're as much in the dark as you!
        BEYOND_THE_REACHES_OF_THE_SEA_OF_ZAFMLUG                                = 18224,  -- Beyond the reaches of the Sea of Zafmlug, toward where the sun sets, lies Adoulin...
        IT_S_A_COUNTRY_IN_ITS_OWN_RIGHT                                         = 18225,  -- It's a country in its own right, no? Quite savage lands for a country, I must declare! Still, though, word is that they are searching for able-bodied adventurers to serve as pioneers.
        IF_MEMORY_SERVES_WASN_T_THE_JEUNO_CHAMBER                               = 18226,  -- If memory serves, wasn't the Jeuno Chamber of Commerce and Industry holding some sort of test for interested applicants? If exploring new lands piques your interest, you might consider heading over to find out more.
        WELL_IF_YOU_TRULY_FEEL_THEY_NEED_YOUR                                   = 18227,  -- Well, if you truly feel they need your aid, I wish you the best of luck.
        A_WAYPOINT_LIES_BEFORE_YOU_IN_ALL_ITS                                   = 18228,  -- A waypoint lies before you in all its mystery.
        YOU_WERE_UNABLE_TO_WARP_TO_YOUR_DESIRED                                 = 18229,  -- You were unable to warp to your desired destination.
        WHAT_WILL_YOU_DO_KINETIC_UNITS_NOTHING_READ                             = 18230,  -- What will you do? (Kinetic Units: #) Nothing. Read an explanation! Go to Western Adoulin. Go to Eastern Adoulin. Go to Ceizak Battlegrounds. Go to Yahse Hunting Grounds. Go to Foret de Hennetiel. Go to Morimar Basalt Fields. Go to Yorcia Weald. Go to Marjami Ravine. Go to Kamihr Drifts. Go to Jeuno. (# unit[/s]) Go to an enigmatic device. Use runes. Decline destination confirmation. Accept destination confirmation.
