        I_SHAN_T_CAUSE_THEE_TEEN_ALL_I                                          = 18270,  -- I shan't cause thee teen. All I ask is that thou wearest this % upon thy finger and let thyself bathe in its luminescent emanations.
        WEAREST_THAT_UPON_THY_FINGER_AND_LET_THYSELF                            = 18271,  -- Wearest that % upon thy finger and let thyself bathe in its luminescent emanations.
