        BEAR_IN_MIND_THAT_TRANSFERRING_THY_SOUL_TO                              = 18307,  -- Bear in mind that transferring thy soul to the frames of other creatures hath its limits. Occasionally stretch thy sinews as a gladiator to both round thy world view and reach higher heights.
        WHAT_IS_IT_THOU_DESIREST                                                = 18308,  -- What is it thou desirest?
        WHICH_REWARD_PRESTIGE_NEEDED_NEEDED_NEEDED_NEEDED_NEEDED                = 18309,  -- Which reward? (Prestige: #) %. (# needed) %. (# needed) %. (# needed) %. (# needed) %. (# needed) %. (# needed) %. (# needed) None.
