        LIFE_IS_FINITE_AND_FLEETING_HOW_WILL_YOU                                = 18349,  -- Life is finite and fleeting. How will you spend the rest of what remains to you?
        WHAT_WILL_YOU_DO_LET_TIME_PASS_BY                                       = 18350,  -- What will you do? Let time pass by idly. Exchange merit points. View accomplishments 1. View accomplishments 2.
        EXCHANGE_FOR_WHAT_POINT_NOTHING_PREVIOUS_PAGE_NEXT                      = 18351,  -- Exchange for what? (# point[/s]) Nothing. %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) %. (#) Previous page. Next page.
