        GLARE_I_CAN_DO_NOTHING_WITH_THAT_AMOUNT                                 = 18353,  -- <Glare>... I can do nothing with that amount.
        GLARE_IF_ALL_YOU_COVET_IS_PEACE_THEN                                    = 18354,  -- <Glare>... If all you covet is peace, then I have nothing further to discuss with you.
