        MAKE_FOR_THE_TERRITORY_TO_WHICH_YOUR_PHANTOM                            = 18356,  -- Make for the territory to which your phantom gem belongs.
        IT_IS_THERE_THAT_YOUR_DESIRES_SHALL_BE                                  = 18357,  -- It is there that your desires shall be fulfilled.
        BE_NOT_SO_CAVALIER_TO_THINK_THAT_YOUR                                   = 18358,  -- Be not so cavalier to think that your success is assured, however. Those with no heart show no mercy. Challenge them without just resolve, and your bout will surely end in failure.
