        CURRENT_ACCOMPLISHMENTS_MY_BUSINESS_HERE_IS_FINISHED_STYGIAN            = 18361,  -- Current accomplishments: My business here is finished. Stygian Pact. ([Unfinished/Conquered/Honors]) hampion of the Dawn. ([Unfinished/Conquered/Honors]) ivine Interference. ([Unfinished/Conquered/Honors]) aiden of the Dusk. ([Unfinished/Conquered/Honors]) he Wyrm God. ([Unfinished/Conquered/Honors]) he Orb's Radiance. ([Unfinished/Conquered/Honors])
        HMPH_IT_SEEMS_YOU                                                       = 18362,  -- Hmph. It seems you [are hardly fit to be disemboweled by these fiends, so superior are they to you/can hold your own against these colossi of combat/have transcended even these ferocities and reign over all with an iron fist].
        I_AM_EXCENMILLE_M_AURCHIAT_OVERSEER_OF_ALL                              = 18364,  -- I am Excenmille M Aurchiat, overseer of all Conflict-related matters.
        I_SEE_YOU_WISH_TO_TRY_YOUR_HAND                                         = 18365,  -- I see. You wish to try your hand at Trust.
        IN_BYGONE_TIMES_I_MIGHT_HAVE_SAID_THAT                                  = 18366,  -- In bygone times, I might have said that adventurers were to be kept at an arm's distance like the deranged mother of one's partner.
        YET_WHEN_I_CHOSE_TO_REVIVE_THE_ANCIENT                                  = 18367,  -- Yet when I chose to revive the ancient traditions of Conflict and Ballista, it was you--the adventurers--who heeded the call to battle.
        AS_SUCH_I_SHALL_PERMIT_YOU_TO_ENGAGE                                    = 18368,  -- As such, I shall permit you to engage in the Trust ritual with me.
        YOU_ARE_NOT_AWARE_OF_WHAT_TRUST_MAGIC                                   = 18369,  -- You...are not aware of what Trust magic is?
        SOMETIMES_I_WONDER_IF_GONDEBAUD_S_HEAD_IS                               = 18370,  -- Sometimes I wonder if Gondebaud's head is filled with naught but cobwebs.
        THE_TRUST_RITUAL_DRAWS_FORTH_ENERGY_FROM_ARDENT                         = 18371,  -- The Trust ritual draws forth energy from ardent bonds of trust and camaraderie as are forged betwixt brothers-in-arms upon the battlefield.
        TO_CUT_TO_THE_QUICK_IF_A_STRONG                                         = 18372,  -- To cut to the quick, if a strong bond exists between the two of us, you will be able to summon an alter ego of me.
        INDEED_I_COULD_DRIVE_YOUR_FOES_INTO_THE                                 = 18373,  -- Indeed, I could drive your foes into the sea as I did the Orcs of Rhazowa.
        THE_PROBLEM_IS_I_COULD_HARDLY_PICK_YOU                                  = 18374,  -- The problem is, I could hardly pick you out of a lineup with similarly built individuals.
        YET_IF_OUR_BONDS_ARE_NOT_STRONG_ENOUGH                                  = 18375,  -- Yet if our bonds are not strong enough, then the magic is doomed to certain failure.
        LET_US_REFLECT_NOT_JUST_ON_HOW_THE                                      = 18376,  -- Let us reflect not just on how the two of us came to know each other, but also on how our mutual experiences have shaped us.
        I_REMEMBER_THE_HONORABLE_EFFORTS_YOU_PUT_FORTH                          = 18377,  -- I remember the honorable efforts you put forth in Ballista.
        WHEN_THE_SUN_GROWS_DIM_AND_I_RETIRE                                     = 18378,  -- When the sun grows dim and I retire to my quarters, drips of wax gather on my desk as I pore over the day's results. Never could I forget those whose accomplishments stood out from the rest.
        REMEMBER_YOUR_EXPLOITS_IN_THE_ARENA_OF_CHOCOBO                          = 18379,  -- [I/I also] remember your exploits in the arena of chocobo races. Your impressive flexibility turned more than one head.
        I_REMEMBER_MEETING_YOU_WHEN_I_WAS_YOUNGER                               = 18380,  -- I[/, too,] remember meeting you when I was younger. Or perhaps it was one just like you.
        YES_I_RECALL_IT_CLEARLY_NOW_YOU_REMIND                                  = 18381,  -- Yes, I recall it clearly now. You remind me of an adventurer I once had a grand time with...hohoho.
        I_AM_REMINDED_OF_THOSE_I_FOUGHT_WITH                                    = 18382,  -- I am reminded of those I fought with side by side...and of my [other/father].
        HOUSE_AURCHIAT_IS_KNOWN_TO_LOOK_TOWARD_THE                              = 18383,  -- House Aurchiat is known to look toward the future, using the past as lessons rather than memories...but I would be remiss if I did not admit that your presence has stirred wonderful feelings within me.
        YES_I_AM_READY_TO_COMMIT_TO_THE                                         = 18384,  -- Yes...I am ready to commit to the ritual.
        COME_TAKE_MY_HAND_AND_CONCENTRATE_ON_THE                                = 18385,  -- Come. Take my hand and concentrate on the bonds that the two of us have forged.
        DISGRACEFUL                                                             = 18386,  -- Disgraceful!
        HMMM_NO_I_M_NOT_DISPLEASED_I_M                                          = 18387,  -- Hmmm...? No, I'm not displeased. I'm rather pleasantly surprised at our joint success.
        WHAT_IS_DISGRACEFUL_IS_THE_VERY_THOUGHT_THAT                            = 18388,  -- What is disgraceful is the very thought that there could be two of me! How can my power be unmatched when there are two Excenmilles?
        THINK_OF_IT_THINK_OF_THE_POSSIBILITIES_THIS                             = 18389,  -- Think of it, %! Think of the possibilities this magic could open up if only we harness it properly! A whole army of Excenmilles could even...
        YES_THE_ORC_EMPIRE_WOULD_BE_LIKE_A                                      = 18390,  -- Yes, the Orc Empire would be like a prostrate babe crying out for its mother's milk.
        HAHAHAHA_WOULD_YOU_FANCY_THAT_TONIGHT_WE_DRINK                          = 18391,  -- Hahahaha, would you fancy that? Tonight we drink, tomorrow we vanquish!
        I_AM_WARMING_TO_THE_IDEA_OF_THIS                                        = 18392,  -- I am warming to the idea of this Trust more and more!
        THOUGH_I_MUST_ADMIT_I_BARELY_EXPECTED_SUCCESS                           = 18393,  -- Though I must admit, I barely expected success to come so easily.
        I_TRIUMPHED_IN_THE_BONDING_ONLY_ONCE_BEFORE                             = 18394,  -- I triumphed in the bonding only once before. It was with my old friend Rahal, leader of the Royal Knights, but all those who came after have failed spectacularly.
        BUT_THAT_MAN_CAN_BE_SO_INFURIATING_GO                                   = 18395,  -- But that man can be so infuriating! Go here! Hold your sword like this! Turn ninety degrees and touch your nose!
        MAKE_SURE_YOU_DO_NOT_FALL_INTO_THE                                      = 18396,  -- Make sure you do not fall into the same trap.
        IN_COMMEMORATION_OF_THIS_MONUMENTAL_EVENT_I_HEREBY                      = 18397,  -- In commemoration of this monumental event, I hereby present you with a scroll containing all we have achieved. Using this should enable you to summon my alter ego.
        I_ADVISE_YOU_TO_TRY_YOUR_HAND_AT                                        = 18398,  -- I advise you to try your hand at your nearest convenience--outside of town, that is.
        MAY_I_SUGGEST_EAST_OR_WEST_RONFAURE_THEY                                = 18399,  -- May I suggest East or West Ronfaure? They are both nearby, and provide ideal conditions for you to try out this newfound power. When you are finished, return here and inform me as to how you are progressing.
        WERE_YOU_SUCCESSFUL_PLEASE_TELL_ME_EVERYTHING                           = 18400,  -- Were you successful? Please, tell me everything.
        HOW_DID_THINGS_GO_SWIMMINGLY_DROWNINGLY                                 = 18401,  -- How did things go? Swimmingly. Drowningly.
        IT_IS_WONDERFUL_TO_HEAR_THAT_YOU_ARE                                    = 18402,  -- It is wonderful to hear that you are getting along well with my alter ego. Good things come in threes, so one more positive thing must await you yet!
        I_SEE_WELL_SAN_D_ORIA_WAS_NOT                                           = 18403,  -- I see... Well, San d'Oria was not built in a day. Keep at it, and I am certain your efforts will be rewarded once more.
        THE_I_HAVE_BEQUEATHED_TO_YOU_WILL_SURELY                                = 18404,  -- The % I have bequeathed to you will surely be of interest to Gondebaud. He can tell you more--and please, treat my alter ego well. Don't go barking inane orders like Rahal did.
        ALL_OF_US_INVOLVED_IN_THIS_GRAND_EXPERIMENT                             = 18405,  -- All of us involved in this grand experiment are attempting to figure out the exact methodology behind it. This is bigger than San d'Oria. The nations of Bastok and Windurst are as serious as we are.
        THIS_IS_INTENDED_NOT_JUST_FOR_YOUR_OWN                                  = 18406,  -- This % is intended not just for your own betterment, but for the betterment of us all. Go forth, and discover all there is to be learned.
        CURILLA_OF_THE_TEMPLE_KNIGHTS_IS_ALSO_PARTICIPATING                     = 18407,  -- [By the way/While I have your attention], Curilla of the Temple Knights is also participating in this initiative.
        I_MUST_WARN_YOU_HOWEVER_THAT_SHE_HAS                                    = 18408,  -- I must warn you, however, that she has little time for those who have done her no favors. I highly doubt she would consent to undergoing the ritual with you.
        INCREASE_YOUR_REPUTATION_AROUND_VANA_DIEL_AND_DO                        = 18409,  -- Increase your reputation around Vana'diel and do all you can for [San d'Oria/your home nation] first.
        I_CANNOT_SAY_FOR_CERTAIN_WHETHER_SHE_WOULD                              = 18410,  -- I cannot say for certain whether she would accept you or not, but it could do no harm to make an official visit and make your intentions clear.
        HM_YOU_WISH_TO_KNOW_WHERE_CURILLA_IS                                    = 18411,  -- Hm? You wish to know where Curilla is[ anyway?/?]
        WHY_SHE_CAN_BE_FOUND_IN_CHATEAU_D                                       = 18412,  -- Why, she can be found in Chateau d'Oraguille, located to the northeast of here. [However, I would not expect the guards there to let you pass./You cannot miss it.]
        I_MUST_BID_YOU_ADIEU_MAY_GLORY_SHINE                                    = 18413,  -- I must bid you adieu. May glory shine upon you, and on the grand nation of San d'Oria!
        I_AM_NOT_THE_ONLY_ONE_PARTICIPATING_IN                                  = 18414,  -- I am not the only one participating in the Trust initiative here in San d'Oria. You would do well to speak with Curilla, leader of the Temple Knights.
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH                              = 18415,  -- Perhaps it would behoove you to speak with Rolandienne in Southern San d'Oria (G-10).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_2                            = 18416,  -- Perhaps it would behoove you to speak with Isakoth in Bastok Markets (E-11).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_3                            = 18417,  -- Perhaps it would behoove you to speak with Fhelm Jobeizat in Windurst Woods (J-10).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_4                            = 18418,  -- Perhaps it would behoove you to speak with Eternal Flame in Western Adoulin (H-11).
        PERHAPS_IT_WOULD_BEHOOVE_YOU_TO_SPEAK_WITH_5                            = 18419,  -- Perhaps it would behoove you to speak with Nantoto in Lower Jeuno (H-8).
        INVISIBLE_EYES_UPON_YOU_CAUSE_THE_HAIRS_ON                              = 18420,  -- Invisible eyes upon you cause the hairs on the back of your neck to rise.
        THE_NODS_IN_AGREEMENT                                                   = 18421,  -- The % nods in agreement.
        A_NEW_RECORDS_OF_EMINENCE_OBJECTIVE_IS_NOW                              = 18422,  -- A new Records of Eminence objective is now available!
        A_NEW_RECORDS_OF_EMINENCE_OBJECTIVE_IS_NOW_2                            = 18423,  -- A new Records of Eminence objective, %, is now available!
        YOU_WISH_TO_EXCHANGE_YOUR_SPARKS                                        = 18424,  -- You wish to exchange your sparks?
        WAIT_BUT_A_MOMENT_HERE_FOLLOW_THIS_COMMAND                              = 18425,  -- Wait but a moment. Here, follow this command--er, compendium to the letter and you should be able to learn a thing or two.
        AH_THIS_ALMOST_SLIPPED_MY_MIND_SHOULD_YOU                               = 18426,  -- Ah, this almost slipped my mind. Should you receive any distinct sorts of artifacts for completing an objective, I will be happy to take them off your hands.
        WORRY_NOT_FOR_I_AM_NOT_OUT_TO                                           = 18427,  -- Worry not, for I am not out to rob you of your glory. Quite the opposite, in fact. I will provide you with a worthwhile reward for collecting them.
        THANKS_TO_YOUR_DONATION_I_NOW_HAVE_IN                                   = 18428,  -- Thanks to your donation, I now have # in safekeeping.
        OHOHOHO_TURNING_IN_SPARKS_I_SEE                                         = 18429,  -- Ohohoho... Turning in sparks, I see.
        HOLD_YOUR_HOARDER_HARES_HERO_HEROINE_I_LOVE                             = 18430,  -- Hold your hoarder hares, hero/heroine]. I love your enthusiasm, but you're not going to learn a thing without a primer. Ahhh, here it is. Have a look-see.
        OH_CRUD_THAT_S_RIGHT_YOU_SHOULD_TRADE                                   = 18431,  -- Oh, crud, that's right. You should trade me any special artifacts you get from completing objectives.
        WHY_WHAT_A_GOOD_QUESTION_BECAUSE_I_LL                                   = 18432,  -- Why? What a good question! Because I'll give you a nifty-difty reward at some point, that's why.
        THANKS_FOR_DOING_WHAT_I_ASKED_NOW_I                                     = 18433,  -- Thanks for doing what I asked. Now I have a total of # from you.
        YOU_WANT_TO_TRRRADE_IN_SPARKS_DO_YOU                                    = 18434,  -- You want to trrrade in sparks, do you?
        LET_ME_WAKE_UP_FROM_MY_CATNAP_FIRST                                     = 18435,  -- Let me wake up from my catnap first... Alright, now rrread this.
        WAIT_WAIT_WAIT_IF_YOU_HAPPEN_TO_GET                                     = 18436,  -- Wait, wait, wait! If you happen to get any purrrticularly interesting items from completing objectives, send them my way.
        DON_T_WORRY_I_M_AS_HONEST_AS                                            = 18437,  -- Don't worry, I'm as honest as a cat when the meat's out of reach. I thought of taking them all for myself...
        BUT_I_DON_T_WANT_TO_MAKE_FUR                                            = 18438,  -- ...but I don't want to make fur fly with the Adventurers' Mutual Aid Network, so I'll do my job like a good little kitty.
        GRRREAT_NOW_I_HAVE_FROM_YOU_THANKS                                      = 18439,  -- Grrreat! Now I have # from you. Thanks!
        HM_OH_SPARK_EXCHANGE_OF_COURSE                                          = 18440,  -- Hm? Oh, spark exchange... Of course.
        I_M_NOT_COMPLETELY_SURE_BUT_THIS_MIGHT                                  = 18441,  -- I'm not completely sure, but this might help set some things straight...I guess.
        LET_ME_ADD_ONE_THING_PLEASE_FIND_IT                                     = 18442,  -- Let me add one thing. Please find it within your heart of hearts to give me anything of particular interest you get from completing objectives.
        I_LL_MAKE_IT_WORTH_YOUR_WHILE_I                                         = 18443,  -- I'll make it worth your while...I swear! Just keep at it and I'll be sure to surprise you with a hot, steaming helping of gratitude one day.
        THANKS_FOR_DOING_YOUR_PART_IN_THE_BATTLE                                = 18444,  -- Thanks for doing your part in the battle for love and peace! With this latest addition, I'm now keeping track of # for you.
        RECORDS_OF_EMINENCE_IS_A_SYSTEM_BROUGHT_TO                              = 18445,  -- Records of Eminence is a system brought to you by the caring folks at the Adventurers' Mutual Aid Network. Set your own objectives whenever you desire, and fulfill them to receive compensation.
        TO_SET_THESE_TASKS_SELECT_OBJECTIVE_LIST_FROM                           = 18446,  -- To set these tasks, select 'Objective List' from the Quests menu, then choose ones that suit your fancy.
        YOU_WILL_BE_REWARDED_WITH_GIL_AND_SPARKS                                = 18447,  -- You will be rewarded with gil and sparks of eminence, which serve the same function as points, notes, credits, and other such methods of quantifying one's greatness. As an extra incentive, adventurers will earn three times the amount of sparks for completing an objective the first time.
        COMPLETED_OBJECTIVES_WILL_VANISH_FROM_YOUR_QUEST_LIST                   = 18448,  -- Completed objectives will vanish from your quest list unless they are repeatable. In the event that you wish to make room for different objectives, you will need to remove them manually.
        AS_A_COROLLARY_REGARDING_REWARDS_YOU_LL_BE                              = 18449,  -- As a corollary regarding rewards, you'll be blessed with special remuneration once you complete several objectives. Bask in the joy of these pleasant surprises when you can.
        LASTLY_ANY_AND_ALL_ACTS_OF_VANDALISM_DIRECTED                           = 18450,  -- Lastly, any and all acts of vandalism directed against your % are strictly prohibited.
        SHOULD_YOU_BE_FOUND_IN_VIOLATION_OF_THIS                                = 18451,  -- Should you be found in violation of this dictum, the heavens will part and wrath incarnate will descend to mete out justice upon you.
        THE_MAXIMUM_NUMBER_OF_THAT_MAY_BE_STORED                                = 18452,  -- The maximum number of % that may be stored is #.
