        YOU_DO_NOT_POSSESS_ENOUGH_SPARKS_OF_EMINENCE                            = 18454,  -- You do not possess enough sparks of eminence to complete the transaction.
        YOU_HAVE_REACHED_THE_MAXIMUM_NUMBER_OF_SPARKS                           = 18455,  -- You have reached the maximum number of sparks that you can exchange this week (#). Your ability to purchase skill books and equipment will be restricted until next week.
        YOU_MAY_USE_UP_TO_MORE_SPARKS_OF                                        = 18456,  -- You may use up to # more sparks of eminence to purchase items.
        EXCHANGE_FOR_WHAT_SPARKS_ITEMS_SKILL_INCREASING_TOMES                   = 18457,  -- Exchange for what? (Sparks: #) Items. Skill-increasing tomes. Equ. Lv.1 - 9. (Up to #) Equ. Lv.10 - 19. (Up to #) Equ. Lv.20 - 29. (Up to #) Equ. Lv.30 - 39. (Up to #) Equ. Lv.40 - 50. (Up to #) Equ. Lv.51 - 70. (Up to #) Equ. Lv.71 - 98. (Up to #) Equ. Lv.99. (Up to #) 10. Trust. Exchange A.M.A.N. currencies. Exchange Seven Treasures. Wise words on Records of Eminence. Nothing.
