        IT_APPEARS_THAT_YOU_HAVE_ARRIVED_AT_A_2                                 = 18525,  -- It appears that you have arrived at a new survival guide provided by the Servicemen's Mutual Aid Network. Common sense dictates that you should now be able to teleport here from similar tomes throughout the world.
        BEFORE_YOU_LIES_A_SURVIVAL_GUIDE_PENNED_BY_2                            = 18526,  -- Before you lies a survival guide penned by the Servicemen's Mutual Aid Network. It touches on such topics as teleportation and battle records.
        WHAT_CHAPTER_WILL_YOU_READ_NONE_TELEPORTATION_ASSISTANCE                = 18527,  -- What chapter will you read? None. Teleportation Assistance. Field Support. Other mysteries.
        THE_METICULOUSLY_ILLUMINATED_TEXT_WITHIN_EXPLAINS_THAT_ADVENTURERS      = 18528,  -- The meticulously illuminated text within explains that adventurers may travel to the location of any previous books visited after paying a sum of gil or the requisite amount of tabs.
        NO_OTHER_SURVIVAL_GUIDE_LOCATIONS_HAVE_BEEN_RECORDED                    = 18529,  -- No other survival guide locations have been recorded. Visiting another one would certainly alleviate this issue.
