        TRAVEL_TO_UP_AND_AWAY_I_M_DOWN                                          = 18533,  -- Travel to %? [Add to favorites/Delete from favorites]. Up and away! I'm down and out.
        TRAVEL_TO_TRAVEL_USING_GIL_GIL_TRAVEL_USING                             = 18534,  -- Travel to %? [Add to favorites/Delete from favorites]. Travel using # gil. (# gil) Travel using # tab[/s]. (# total) One-time free Warp for the objective. Not just yet.
        YOU_DO_NOT_HAVE_ENOUGH_TABS                                             = 18535,  -- You do not have enough tabs.
        THE_RECORDS_INDICATE_YOU_HAVE_FOUGHT_VALIANTLY_FOR                      = 18536,  -- The records indicate you have fought valiantly for Vana'diel for # hour[/s].
        AT_THE_BOTTOM_OF_THE_PAGE_IS_A                                          = 18537,  -- At the bottom of the page is a reminder. It perfunctorily states that you may receive % once you have logged a total of # hours.
        AS_PER_THE_CUSTOM_NOTED_WITHIN_YOU_ARE                                  = 18538,  -- As per the custom noted within, you are eligible to receive % for the # hour[/s] of fighting you've accrued.
        ACCEPT_THE_REWARD_YES_PLEASE_NO_THANKS                                  = 18539,  -- Accept the reward? Yes, please. No, thanks.
        YOU_MAY_CHANGE_THE_WAY_YOU_SELECT_AREAS                                 = 18540,  -- You may change the way you select areas listed in Teleportation Assistance.
        ANY_CHANGES_TO_MAKE_KEEP_COURSE_SELECT_BY                               = 18541,  -- Any changes to make? Keep course. Select by region. Select by content.
        AREA_SELECTION_WILL_NOW_BE_MADE_BY                                      = 18542,  -- Area selection will now be made by [region/content].
        NOWHERE_FOR_NOW_SELECT_FROM_AMONGST_FAVORITES_ORIGINAL                  = 18543,  -- Nowhere for now. Select from amongst favorites. Original release areas. Rise of the Zilart areas. Chains of Promathia areas. Treasures of Aht Urhgan areas. Wings of the Goddess areas. . . . . . . Seekers of Adoulin areas.
        TRAVEL_TO_WHICH_REGION_ON_SECOND_THOUGHT_NONE                           = 18544,  -- Travel to which region? On second thought, none. Select from amongst favorites. [San d'Oria/Movalpolos]. [Bastok/Tavnazian Arch]. [Windurst/Lumoria]. [Jeuno/Mamool Ja Savage]. [Tavnazia/Halvung]. [West. Aht Urhgan/Arrapago Is]. [Adoulin Isles/Ruins of Alzadaal]. [Ronfaure/Ronfaure Front]. [Zulkheim/Norvallen Front]. [Norvallen/Gustaberg Front]. [Gustaberg/Derfland Front]. [Derfland/Sarutabaruta Front]. [Sarutabaruta/Aragoneu Front]. [Kolshushu/Fauregandi Front]. [Aragoneu/Valdeaunia Front]. [Fauregandi/East. Ulbuka]. [Valdeaunia/Ra'Kaznar]. [Qufim/]. [Li'Telor/]. [Kuzotz/]. [Vollbow/]. [Elshimo Low/]. [Elshimo Up/]. [Tu'Lia/]. Previous page. Next page.
        TRAVEL_TO_WHERE_NOWHERE                                                 = 18545,  -- Travel to where? Nowhere. %. %. %. %. %. %. %. %. %. [Add location to favorites/Remove location from favorites].
        HAS_BEEN                                                                = 18546,  -- % has been [added to your list of favorites/removed from your list of favorites].
        YOUR_LIST_OF_FAVORITES_IS_FULL_YOU_MUST                                 = 18547,  -- Your list of favorites is full. You must remove an existing entry to add new ones.
        REMOVE_WHICH_ENTRY_NONE_OF_THESE                                        = 18548,  -- Remove which entry? None of these. %. %. %. %. %. %. %. %. %.
        PLEASED_TO_MEET_YOU_NEW_RECRUIT_IS_THERE                                = 18549,  -- Pleased to meet you, new recruit. Is there anything about which you wish to inquire?
        INQUIRE_ABOUT_WHAT_I_WANT_TO_FIND_SOME                                  = 18550,  -- Inquire about what? I want to find some quests! I want to try the tutorial event! Teach me about Records of Eminence! Teach me about the Trust initiative! I want a map of the area I'm in! I want maps of the whole city! How do I give items to people? How do I fight outside town? What are quests and missions? Tell me more about Southern San d'Oria! I have other questions. Nothing for now.
        I_CAN_MARK_THE_LOCATIONS_OF_IMPORTANT_PEOPLE                            = 18551,  -- I can mark the locations of important people on your map of the San d'Oria area, should you require it.
        YOU_CAN_FIND_A_MAP_PEDDLER_TAKING_REFUGE                                = 18552,  -- You can find a map peddler taking refuge in the shade of a tree to the southwest, near the gate to West Ronfaure.
        THERE_IS_AN_ELDERLY_WOMAN_NEAR_THE_FOUNTAIN                             = 18553,  -- There is an elderly woman near the fountain due south of here who will be more than happy to sell you maps.
        THERE_ARE_PEOPLE_WILLING_TO_SELL_YOU_MAPS                               = 18554,  -- There are people willing to sell you maps in both Northern and Southern San d'Oria, but the vendor in Northern San d'Oria is closer...if you are in a hurry.
        OUR_KINGDOM_HAS_PREPARED_A_SPECIAL_TOUR_OF                              = 18555,  -- Our kingdom has prepared a special tour of duty for newly enlisted troops such as you. Hopefully you make the best of it.
        TO_BEGIN_THE_JOURNEY_SIMPLY_TALK_TO_ALAUNE                              = 18556,  -- To begin the journey, simply talk to Alaune in Southern San d'Oria. She resides near the gate to West Ronfaure.
        TO_RENDEZVOUS_WITH_HER_HEAD_DIRECTLY_SOUTH_AND                          = 18557,  -- To rendezvous with her, head directly south and pass through the gate leading to Southern San d'Oria.
        TO_RENDEZVOUS_WITH_HER_ASCEND_THE_STAIRS_THAT                           = 18558,  -- To rendezvous with her, ascend the stairs that lead southwest, which should take you to Northern San d'Oria.
        ONCE_THERE_PROCEED_SOUTHWARD_UNTIL_YOU_REACH_SOUTHERN                   = 18559,  -- Once there, proceed southward until you reach Southern San d'Oria.
        I_SHALL_MARK_HER_POSITION_UPON_YOUR_MAP                                 = 18560,  -- I shall mark her position upon your map so you may locate her more easily once you are in that vicinity.
        IT_IS_POSSIBLE_TO_CHECK_WHO_HAS_BEEN                                    = 18561,  -- It is possible to check who has been marked on your map by opening the Map menu, selecting the Markers option, and then scrolling to the right.
        PERFORMING_A_WIDE_SCAN_FROM_THE_MAP_MENU                                = 18562,  -- Performing a Wide Scan from the Map menu also allows you to locate people in your vicinity, should that method prove more convenient.
        WHETHER_DECORATED_IN_BATTLE_OR_RECENTLY_ENLISTED_ALL                    = 18563,  -- Whether decorated in battle or recently enlisted, all can benefit from trying their hand at Records of Eminence. It is a simple method for participating in Vana'diel's many adventures, and bestows rewards all its own.
        OPEN_THE_MAIN_MENU_GO_RIGHT_TO_GET                                      = 18564,  -- Open the main menu, go right to get to the next screen, and select Objective List under the Quests submenu.
        SELECT_TUTORIAL_HEAD_TO_BASICS_AND_ACCEPT_THE                           = 18565,  -- Select Tutorial, head to Basics, and accept the objective First Step Forward to get started down this magnificent road.
        PERMIT_ME_TO_PROVIDE_YOU_WITH_A_HINT                                    = 18566,  -- Permit me to provide you with a hint for completing First Step Forward.
        FIND_THE_PERSON_DESIGNATED_BY_THE_OBJECTIVE_IN                          = 18567,  -- Find the person designated by the objective in Southern San d'Oria. I shall mark their location on your map.
        RECORDS_OF_EMINENCE_CONTAINS_A_PLETHORA_OF_OBJECTIVES                   = 18568,  -- Records of Eminence contains a plethora of objectives, many of which will surely fit your play style. It would behoove you to take advantage of this opportunity.
        THE_TRUST_INITIATIVE_IS_A_SPECIAL_MAGIC_REGIMEN                         = 18569,  -- The Trust initiative is a special magic regimen developed by one of the world's finest academies of magic.
        THOSE_WHO_SUCCESSFULLY_UNDERGO_TRAINING_WILL_BE_BESTOWED                = 18570,  -- Those who successfully undergo training will be bestowed with the ability to call forth powerful allies into battle.
        ONLY_ADVENTURERS_WHO_HAVE_PROVEN_THEIR_WORTH_BY                         = 18571,  -- Only adventurers who have proven their worth by achieving level five are eligible to participate. I will provide you with further information when you reach that landmark.
        GONDEBAUD_IS_THEIR_REPRESENTATIVE_AND_HE_IS_STATIONED                   = 18572,  -- Gondebaud is their representative, and he is stationed in Southern San d'Oria. I shall mark his location on your map should you desire to make further inquiries.
        IF_YOU_HARBOR_DOUBTS_ABOUT_SOMETHING_I_HAVE                             = 18573,  -- If you harbor doubts about something I have not yet touched upon, first open the main menu. From there, scroll right to the second page and select the Help Desk option.
        ONCE_YOU_HAVE_DONE_THAT_SELECT_HELP_DESK                                = 18574,  -- Once you have done that, select Help Desk again from the list of categories that appears in the new window. Finally, enter the section entitled I need help with the game controls.
        THE_ANSWER_TO_YOUR_QUESTION_LIKELY_LIES_THERE                           = 18575,  -- The answer to your question likely lies there.
        THOUGH_I_WISH_THE_SITUATION_WERE_LESS_DIRE                              = 18576,  -- Though I wish the situation were less dire, there exist many who require your aid. Do you wish to reference the materials I have gathered on them?
        INQUIRE_ABOUT_WHICH_LOCALE_NONE_SOUTHERN_SAN_D                          = 18577,  -- Inquire about which locale? None. Southern San d'Oria: # individual[/s]. Northern San d'Oria: # individual[/s]. Port San d'Oria: # individual[/s]. Chateau d'Oraguille: # individual[/s].
        THE_FOLLOWING_INDIVIDUALS_ARE_LIKELY_TO_REQUEST_YOUR                    = 18578,  -- The following individuals are likely to request your assistance if you are to speak to them.
        WHO_WILL_YOU_GO_SEE_IN_SOUTHERN_SAN                                     = 18579,  -- Who will you go see in Southern San d'Oria? No one. Glenne. Rosel. Raimbroy. Andecia. Parvipon. Legata. Amutiyaal. Atelloune. Maugie. Hanaa Punaa. Gondebaud. Balasiel. Balasiel. Hanaa Punaa. Helbort. Sobane. Norejaie. Paouala. Taumila. Hanaa Punaa. Balasiel. Femitte. Amaura. Deraquien. Sobane. Sharzalion. Balasiel. Rouva.
        WHO_WILL_YOU_GO_SEE_IN_NORTHERN_SAN                                     = 18580,  -- Who will you go see in Northern San d'Oria? No one. Miageau. Ailbeche. Abeaule. Abioleget. Secodiand. Kuu Mohzolhi. Ramua. Someone atop the tower. Pagisalis. Someone atop the tower. Olbergieut. Abeaule. Maloquedil. Someone atop the tower. Morjean. Eperdur. Eperdur. Vamorcote. Belgidiveau. Gulmama. Rondipur. Castilchat. Narcheral. Ailbeche. Ailbeche. Miaux.
        AGM_ANTRENEAU_WHO_WILL_YOU_GO_SEE_IN                                    = 18581,  -- Agm[(Antreneau) Who will you go see in Port San d'Oria? No one. Altiret. Gulemont. Fontoumant. Regine. Gallijaux. Joulet. Nogelle. Antreneau. Vounebariont. Portaure. Antreneau. Ceraulian. Eddy.
        WHO_WILL_YOU_GO_SEE_IN_CHATEAU_D                                        = 18582,  -- Who will you go see in Chateau d'Oraguille? No one. Halver. Curilla. Chalvatot. Curilla. Curilla. Someone beyond the door. Rahal. Curilla. Someone beyond the door. Someone beyond the door.
        ALLOW_ME_TO_MAKE_THINGS_EASIER_FOR_YOU                                  = 18583,  -- Allow me to make things easier for you and mark their location on your map.
        HEADING_THERE_ARE_WE_ALLOW_ME_TO_MARK                                   = 18584,  -- Heading there, are we? Allow me to mark your map so you do not lose your way.
        FINALLY_SOME_INFORMATION_TO_HELP_YOU_IN_YOUR                            = 18585,  -- FiNAllY, sOmE InFOrmAtiOn tO hELp yOu In yoUr TrAVelS.
        ONE_MORE_THING                                                          = 18586,  -- One more thing.
        I_HAVE_SAVED_A_RATHER_PARAMOUNT_DETAIL_FOR                              = 18587,  -- I have saved a rather paramount detail for last. Allow me to explain.
        THERE_S_STILL_ONE_OTHER_THING_REMAINING_TO                              = 18588,  -- There's still one other thing remaining to share with you.
        YOU_CAN_WARP_BETWEEN_PLACES_KNOWN_AS_HOME                               = 18589,  -- YoU CAn wArP BetWEen PlACes KnOwn aS HoME pOinTs. TheY ARe moST CoNveNieNT, sO maKe SuRE to ReGIsTer ThEM bY TouCHing ThE SurFaCE.
        HOME_POINTS_WILL_PROBABLY_TURN_OUT_TO_BE                                = 18590,  -- Home points will probably turn out to be among your best companions. Make sure to examine one if you find it, so you can warp between them and cover large distances fast.
        YOU_MAY_TELEPORT_BETWEEN_THESE_CRYSTALLINE_NODES_CALLED                 = 18591,  -- You may teleport between these crystalline nodes called home points for efficient travel. Be sure to examine any you stumble upon.
        THERE_S_SOME_SPECIAL_CRYSTAL_NODES_KNOWN_AS                             = 18592,  -- There's some special crystal nodes known as home points that'll undoubtedly serve you well. Don't forget to interact with all that you find, as they can help you get to far away places.
        IF_YOU_FIND_YOURSELF_IN_A_FARAWAY_PLACE                                 = 18593,  -- If yOU fINd yOurSeLF iN A fARaWay pLaCe, maKe sURe tO FinD a StoRE to BuY a Map fROm! wIth a MaP, yoU CaN ChEck WheRe yOu ArE!
        SHOULD_YOU_FIND_YOURSELF_LOST_IN_THE_MIDDLE                             = 18594,  -- Should you find yourself lost in the middle of nowhere, try to make it back to town to buy a map. That way, you can get your bearings.
        REMEMBER_TO_PURCHASE_A_MAP_FROM_THE_APPROPRIATE                         = 18595,  -- Remember to purchase a map from the appropriate vendor before going to a faraway land. If you do, you can check your location within that place.
        DID_YOU_KNOW_THAT_SOME_VENDORS_WILL_SELL                                = 18596,  -- Did you know that some vendors will sell you maps of specific areas? It sure beats stumbling around like a dullard!
        DON_T_WASTE_PRECIOUS_ITEMS_BY_SELLING_THEM                              = 18597,  -- DoN'T WaSTe pRecIOus iTemS By sEllINg tHeM tO a StoRe. MaKE eVen MoRe MonEy By PuTTing tHeM uP At tHe AucTIon HouSe!
        I_HATE_TO_SAY_IT_BUT_THE_MERCHANTS                                      = 18598,  -- I hate to say it, but the merchants around here are pretty stingy. You'd have more luck listing any unwanted goods at the auction house.
        I_ADVISE_YOU_TO_PUT_ANY_UNWANTED_GOODS                                  = 18599,  -- I advise you to put any unwanted goods up for sale at the auction house rather than be taken advantage of by the vendors here.
        IF_THERE_S_SOMETHING_YOU_VE_GOT_THAT                                    = 18600,  -- If there's something you've got that you don't need, try putting it up at the auction house rather than selling it to some unscrupulous vendor.
        MANY_UNDEAD_MONSTERS_CAN_SENSE_WHEN_YOU_ARE                             = 18601,  -- MaNY uNdEaD MOnsTeRS cAn SenSe WhEn yOU Are LoW oN HP, aNd wIll TAke tHaT opPOrtUnItY tO ComE AfTEr yOu!
        UNDEAD_ENEMIES_TEND_TO_COME_OUT_OF_THE                                  = 18602,  -- Undead enemies tend to come out of the woodwork when your HP is low. Be careful.
        THE_UNDEAD_OFTEN_ASSAULT_ADVENTURERS_WITH_LOW_HP                        = 18603,  -- The undead often assault adventurers with low HP, which is all the more reason to never let your guard down in the wilderness.
        UNDEAD_ARE_ALWAYS_OUT_FOR_BLOOD_AND_BRAINS                              = 18604,  -- Undead are always out for blood and brains, so watch out if you're low on health! They'll make a beeline right for you.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_STRENGTH                    = 18605,  -- LeT'S tALk aBouT AttRIButeS. InCReaSing yoUr StrenGTh (STR) wiLL iNcrEase YouR pHYsiCal, bUt NOt MaGiCal, AttACk.
        INCREASING_YOUR_STRENGTH_STR_RAISES_YOUR_ATTACK_POWER                   = 18606,  -- Increasing your strength (STR) raises your attack power, but--sadly--not your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER                 = 18607,  -- Increasing your strength (STR) enhances your attack power, but--regrettably--does nothing for your magic attack.
        INCREASING_YOUR_STRENGTH_STR_ENHANCES_YOUR_ATTACK_POWER_2               = 18608,  -- Increasing your strength (STR) enhances your attack power, but unfortunately does nothing for the efficacy of your magic.
        LET_S_TALK_ABOUT_ATTRIBUTES_INCREASING_YOUR_DEXTERITY                   = 18609,  -- LeT'S tALk aBouT AttRIButeS. InCReaSinG yoUr DeXteRIty (DEX) wiLl IncReaSe yOuR AccURacY aNd cRiTIcaL HIt rAtE.
        INCREASING_YOUR_DEXTERITY_DEX_INCREASES_THINGS_LIKE_YOUR                = 18610,  -- Increasing your dexterity (DEX) increases things like your accuracy and critical hit rate.
        INCREASING_YOUR_DEXTERITY_DEX_IMPROVES_SUCH_FACULTIES_AS                = 18611,  -- Increasing your dexterity (DEX) improves such faculties as accuracy and critical hit rate.
        INCREASING_YOUR_DEXTERITY_DEX_ENHANCES_ATTRIBUTES_SUCH_AS               = 18612,  -- Increasing your dexterity (DEX) enhances attributes such as accuracy and critical hit rate.
