        INCREASING_YOUR_AGILITY_AGI_INCREASES_THINGS_LIKE_YOUR                  = 18618,  -- Increasing your agility (AGI) increases things like your physical evasion and ranged accuracy. It also decreases enemies' critical hit evasion.
        INCREASING_YOUR_AGILITY_AGI_IMPROVES_SUCH_FACULTIES_AS                  = 18619,  -- Increasing your agility (AGI) improves such faculties as physical evasion and ranged accuracy. It also reduces enemies' critical hit evasion.
