        LOOK_AS_LONG_AS_YOU_DESIRE_I_SHALL                                      = 18633,  -- Look as long as you desire. I shall not interfere.
        RUMOIE_IN_SOUTHERN_SAN_D_ORIA_ALSO_FANCIES                              = 18634,  -- Rumoie in Southern San d'Oria also fancies herself something of a cartographer. You can always go to her if you want your map marked.
        THE_ACTION_OF_HANDING_OVER_OBJECTS_TO_OTHERS                            = 18635,  -- The action of handing over objects to others is termed trading here. To trade items to people, open the main menu--which will appear on the right-hand side of your screen--and select Trade.
        IN_THE_EVENT_YOU_HAVE_NEGLECTED_TO_TARGET                               = 18636,  -- In the event you have neglected to target your interlocutor, please do so after selecting the Trade option. Afterwards, choose the item or items you wish to bequeath in the window that appears and hit OK.
        THIS_PROCESS_WILL_BE_AN_INTEGRAL_PART_OF                                = 18637,  -- This process will be an integral part of the quests and missions you shall undertake in the future, so I entreat you to commit it to memory.
        SHOULD_YOU_BE_IN_POSSESSION_OF_PLEASE_TRADE                             = 18638,  -- Should you be in possession of %, please trade it to me. In return, I shall bestow some monetary remunerations upon you, care of the monarchy.
        IT_WOULD_BEHOOVE_YOU_TO_REMEMBER_THE_FOLLOWING                          = 18639,  -- It would behoove you to remember the following points when engaging in combat outside the city gates. One: outfit yourself with weapons and armor. Two: magic spells are learned from scrolls.
        THIRDLY_AND_OF_THE_UTMOST_IMPORT_IS_THAT                                = 18640,  -- Thirdly--and of the utmost import--is that you check your adversaries before challenging them. It would not do for you to go charging into battle against an enemy who thoroughly outclasses you.
        FINALLY_NEVER_FORGET_TO_CHECK_YOUR_SPOILS_OF                            = 18641,  -- Finally, never forget to check your spoils of war.
        TASKS_ISSUED_BY_RESIDENTS_OF_THE_CITY_FOR                               = 18642,  -- Tasks issued by residents of the city for you to complete are called quests. Simply fulfill the requirements, such as procuring the desired item, to receive a reward.
        ON_THE_OTHER_HAND_ORDERS_HANDED_DOWN_DIRECTLY                           = 18643,  -- On the other hand, orders handed down directly from those involved with the nation's administration are called missions. Converse with the guard by the gate for a more detailed explanation.
        OPEN_THE_MAP_OPTION_FROM_THE_MAIN_MENU                                  = 18644,  -- Open the Map option from the main menu, select Markers, and then scroll to the right. That will tell you where you need to go.
        SELECTING_MAP_FROM_THE_MAIN_MENU_OPENS_THE                              = 18645,  -- Selecting Map from the main menu opens the map of the area in which you currently reside. Select Markers and press the right arrow key to see all the markers placed on your map.
        SHE_MIGHT_BE_A_TAD_MORE_CRITICAL_THAN                                   = 18646,  -- She might be a tad more critical than most, so you might want to be careful.
        OPEN_THE_MAP_OPTION_FROM_THE_MAIN_MENU_2                                = 18647,  -- Open the Map option from the main menu, select Markers, and then scroll to the right to find where she is stationed.
        BY_THE_WAY_TEILSA_IS_A_LADY_OF                                          = 18648,  -- By the way, Teilsa is a lady of traditional Elvaan upbringing, so try not to say anything that will offend her sensibilities. Anyway, let me mark her location on your map.
        NOW_YOU_CAN_CHECK_HER_POSITION_ANYTIME_BY                               = 18649,  -- Now you can check her position anytime by opening the Map option from the main menu, selecting Markers, and scrolling to the right.
        IT_MIGHT_BE_IN_YOUR_BEST_INTERESTS_TO                                   = 18650,  -- It might be in your best interests to speak to [Urbiolaine/Igsli/Teldro-Kesdrodo/Nunaarl Bthtrogg] in % [(G-10)/(E-11)/(J-10)/(H-11)].
        JOIN_WHICH_UNITY_I_NEED_TIME_TO_CONSIDER                                = 18651,  -- Join which Unity? I need time to consider. Pieuje. Ayame. Invincible Shield. Apururu. Maat. Aldo. Jakoh Wahcondalo. Naja Salaheem. Flaviria. Yoran-Oran. Sylvie.
        SHOULD_YOU_JOIN_ONE_UNITY_YOU_WILL_NOT                                  = 18652,  -- Should you join one Unity, you will not be able to switch to another one until the rankings are tallied. Proceed anyway?
        JOIN_UNITY_YES_NO                                                       = 18653,  -- Join [Pieuje's/Ayame's/Invincible Shield's/Apururu's/Maat's/Aldo's/Jakoh Wahcondalo's/Naja Salaheem's/Flaviria's/Yoran-Oran's/Sylvie's] Unity? Yes. No.
        SWITCHING_UNITIES_WILL_COST_A_TOTAL_OF_UNITY                            = 18654,  -- Switching Unities will cost a total of # Unity accolade[/s], and you will be unable to switch until the rankings are tabulated. Are you sure you wish to switch Unities?
