        UNITY_CONCORD_IS_A_SYSTEM_PROMULGATED_AND_MANAGED                       = 18673,  -- Unity Concord is a system promulgated and managed by the Adventurers' Mutual Aid Network.
        PARTICIPATING_ADVENTURERS_ARE_ABLE_TO_RECEIVE_A_VARIETY                 = 18674,  -- Participating adventurers are able to receive a variety of benefits and rewards just by engaging in their everyday activities.
        UNITY_IS_A_CATCHALL_TERM_THAT_REFERS_TO                                 = 18675,  -- Unity is a catchall term that refers to the group that participants belong to.
        UNITY_LEADERS_ARE_INDIVIDUALS_WHO_HAVE_STRONG_TIES                      = 18676,  -- Unity leaders are individuals who have strong ties to adventurers' activities and are sterling representatives of their home nations.
        MEMBERS_OF_THE_SAME_UNITY_CAN_CONVERSE_WITH                             = 18677,  -- Members of the same Unity can converse with each other over great distances through the use of specialized figurines known as %.
        CHAT_SETTINGS_MAY_BE_CHANGED_BY_SELECTING_STATUS                        = 18678,  -- Chat settings may be changed by selecting Status from the main menu, and choosing Unity Info under the Unity submenu.
        YOU_MAY_NOT_ALWAYS_BE_ABLE_TO_JOIN                                      = 18679,  -- You may not always be able to join the chat if too many players are participating at once.
        THOSE_BELONGING_TO_A_UNITY_ARE_ABLE_TO                                  = 18680,  -- Those belonging to a Unity are able to undertake special Records of Eminence objectives related to Unity Concord activities.
        THE_THREE_PERTINENT_CATEGORIES_INCLUDE_SHARED_OBJECTIVES_UNITY          = 18681,  -- The three pertinent categories include shared objectives, Unity leader-specific objectives, and Wanted battle objectives.
        SHARED_OBJECTIVES_MAY_BE_TAKEN_REGARDLESS_OF_WHICH                      = 18682,  -- Shared objectives may be taken regardless of which Unity you have joined. These tasks can be undertaken at any time, and change every day at midnight (JST).
        UNITY_LEADER_SPECIFIC_OBJECTIVES_ARE_TIED_TO_THE                        = 18683,  -- Unity leader-specific objectives are tied to the Unity's eponymous leader and change each week.
        WANTED_OBJECTIVES_CENTER_AROUND_VANQUISHING_PARTICULARLY_HEINOUS_FOES   = 18684,  -- Wanted objectives center around vanquishing particularly heinous foes that terrorize Vana'diel.
        THESE_OBJECTIVES_ARE_OF_A_HIGHER_CALIBER_AND                            = 18685,  -- These objectives are of a higher caliber, and thus require currency known as Unity accolades to undertake.
        SHARED_AND_LEADER_SPECIFIC_OBJECTIVES_PROVIDE_MORE_ACCOLADES            = 18686,  -- Shared and leader-specific objectives provide more accolades than run-of-the-mill objectives.
        VANA_DIEL_HAS_ALWAYS_BEEN_PLAGUED_BY_NEFARIOUS                          = 18687,  -- Vana'diel has always been plagued by nefarious foes pillaging the landscape, but relatives of some of the more heinous ones have been spotted lately.
        THE_A_M_A_N_HAS_DEEMED_IT                                               = 18688,  -- The A.M.A.N. has deemed it necessary to eliminate these Wanted targets, and has notified Unity members that they are of the utmost priority.
        A_LIST_OF_THESE_FOES_CAN_BE_VIEWED                                      = 18689,  -- A list of these foes can be viewed at any time by selecting the appropriate subcategory under the objectives list.
        UNITY_CONCORD_REPRESENTATIVES_ARE_ABLE_TO_PROVIDE_PARTICIPANTS          = 18690,  -- Unity Concord representatives are able to provide participants with transportation to the areas where these threats can be found.
        THOUGH_TACKLING_THE_PROFANE_WILL_LIKELY_REQUIRE_PARTICIPATION           = 18691,  -- Though tackling the profane will likely require participation of your allies, the objective can be undertaken so long as at least one person has set the appropriate objective.
        WHEN_YOU_SET_THE_OBJECTIVE_AND_COMMENCE_THE                             = 18692,  -- When you set the objective and commence the battle, the requisite number of Unity accolades will be deducted from your total.
        SUCCESSFUL_CHALLENGERS_WILL_BE_REWARDED_WITH_SPECIAL_REWARDS            = 18693,  -- Successful challengers will be rewarded with special rewards in addition to the normal sparks of eminence.
        NO_UNITY_ACCOLADES_WILL_BE_CHARGED_SHOULD_YOU                           = 18694,  -- No Unity accolades will be charged should you commence the battle without having the appropriate objective set, but the rewards you can reap from your efforts will be limited.
        YOU_CAN_SNATCH_UNPARALLELED_EQUIPMENT_AND_MATERIALS_FROM                = 18695,  -- You can snatch unparalleled equipment and materials from the slain corpses of Wanted targets.
        AN_A_M_A_N_SPECIALIST_VERSED_IN                                         = 18696,  -- An A.M.A.N. specialist versed in arcane harmonization has kindly offered to use these materials to bring out the latent potential in such pieces.
        ONE_OF_THE_UNITY_GUIDES_WILL_BE_PLEASED                                 = 18697,  -- One of the Unity guides will be pleased to accept certain combinations of equipment and materials to begin the process for you.
        A_NUMBER_OF_ACCOLADES_IS_REQUIRED_FOR_THIS                              = 18698,  -- A number of accolades is required for this service, but the precision and accuracy of her methods are without equal, and there is no worry of your equipment being destroyed.
        YOU_CAN_USE_SPECIFIED_MATERIALS_TO_ADD_NEW                              = 18699,  -- You can use specified materials to add new attributes to equipment that has been upgraded.
        UTILIZING_ADDITIONAL_MATERIALS_AFTER_ADDING_AN_ATTRIBUTE_CAN            = 18700,  -- Utilizing additional materials after adding an attribute can accumulate Reinforcement Points for the equipment and increase its rank.
        INCREASING_YOUR_EQUIPMENT_S_RANK_CAN_BOOST_ITS                          = 18701,  -- Increasing your equipment's rank can boost its attributes, while some equipment can also have additional attributes added later.
        SPEAK_TO_THE_UNITY_GUIDES_AFTER_GATHERING_THE                           = 18702,  -- Speak to the Unity guides after gathering the necessary materials for your equipment in order to add attributes to it or increase its rank.
        THE_FIRST_TIME_YOU_ADD_AN_ATTRIBUTE_TO                                  = 18703,  -- The first time you add an attribute to a piece of equipment will require the use of Unity accolades.
        IT_ALSO_REQUIRES_THAT_YOU_FIRST_COMPLETE_A                              = 18704,  -- It also requires that you first complete a specific Records of Eminence objective.
        THE_WORK_YOU_REQUEST_WILL_BE_CARRIED_OUT                                = 18705,  -- The work you request will be carried out on-site by a specially trained Unity guide.
        COMPLETING_RECORDS_OF_EMINENCE_OBJECTIVES_AS_PART_OF                    = 18706,  -- Completing Records of Eminence objectives as part of a Unity will reward you with Unity accolades in addition to sparks of eminence.
        THESE_ACCOLADES_NOT_ONLY_SERVE_AS_A_SYMBOL                              = 18707,  -- These accolades not only serve as a symbol of prestige, but can also be exchanged for a variety of services.
        SOME_OF_THESE_SERVICES_INCLUDE_PURCHASING_ITEMS_SECURING                = 18708,  -- Some of these services include purchasing items, securing battle zones for hunting Wanted targets, fees for strengthening equipment, and more.
        PLEASE_NOTE_THAT_YOU_MAY_ONLY_EXCHANGE_A                                = 18709,  -- Please note that you may only exchange a maximum of # accolades per week (Earth time).
        YOU_MAY_SWITCH_UNITIES_ONCE_DURING_THE_UNITY                            = 18710,  -- You may switch Unities once during the Unity ranking tabulation period.
        THIS_IS_NOT_A_DECISION_TO_BE_TAKEN                                      = 18711,  -- This is not a decision to be taken lightly, for switching Unities will cause you to forfeit any benefits you were receiving from your previous one.
        THIS_PROCESS_REQUIRES_A_FAIR_DEAL_OF_PAPERWORK                          = 18712,  -- This process requires a fair deal of paperwork, and the A.M.A.N. will charge you an accolade fee based on your rank.
        HOWEVER_YOUR_VALOROUS_DEEDS_REMAIN_WHEREVER_YOU_CHOOSE                  = 18713,  -- However, your valorous deeds remain wherever you choose to go, and you will not lose any other accolades.
        RANKINGS_ARE_DECIDED_THROUGH_THE_COMBINED_EFFORTS_OF                    = 18714,  -- Rankings are decided through the combined efforts of each of the Unity's members.
        THE_A_M_A_N_TABULATES_ALL_THE                                           = 18715,  -- The A.M.A.N. tabulates all the good deeds done during a period of time and confers benefits on a Unity for the following ranking period.
        SOME_OF_THESE_BENEFITS_INCLUDE_CHANGES_TO_UNITY                         = 18716,  -- Some of these benefits include changes to Unity accolades gained and the effects of equipment earned from Wanted battles.
        YES_YOU_READ_THAT_CORRECTLY_THE_ATTRIBUTES_OF                           = 18717,  -- Yes, you read that correctly--the attributes of certain equipment will increase in line with your Unity's ranking.
        ON_THE_OTHER_HAND_MEMBERS_OF_A_UNITY                                    = 18718,  -- On the other hand, members of a Unity that finds itself on the lower rungs will enjoy an increase in accolades and capacity points earned to help bring them up to par.
        ADDITIONALLY_AN_INDIVIDUAL_S_EVALUATION_IS_THE_SUM                      = 18719,  -- Additionally, an individual's evaluation is the sum of the accolades they have earned divided by #. A Unity's ranking is the average of all eligible members' individual evaluations.
        THE_A_M_A_N_DOES_NOT_LOOK                                               = 18720,  -- The A.M.A.N. does not look kindly on those who only seek to siphon rewards from others' hard work, and thus only confers these boons on those who have collected at least a certain number of accolades.
        UNITY_LEADERS_MAY_ALSO_JOIN_YOU_AS_ALTER                                = 18721,  -- Unity leaders may also join you as alter egos for a limited period of time.
        THOSE_WITH_EVALUATIONS_OF_OR_GREATER_WILL_BE                            = 18722,  -- Those with evaluations of # or greater will be able to call forth an alter ego of their leader to assist them in battle.
        THOSE_ELIGIBLE_WILL_BE_ABLE_TO_USE_THE                                  = 18723,  -- Those eligible will be able to use the alter ego from the moment they acquire the appropriate ranking level until the tabulation after the next.
        A_LEADER_S_ALTER_EGO_GROWS_IN_POWER                                     = 18724,  -- A leader's alter ego grows in power the higher their Unity is ranked.
        CHANGING_UNITIES_WILL_REMOVE_THE_PLAYER_S_ABILITY                       = 18725,  -- Changing Unities will remove the player's ability to call forth their leader's alter ego at the moment they leave their current Unity, regardless of personal evaluation or remaining time.
        A_PLAYER_WILL_HAVE_TO_WORK_HARD_IN                                      = 18726,  -- A player will have to work hard in their new Unity and acquire a sufficient evaluation to regain the ability to call forth their new Unity's leader.
        IT_GOES_WITHOUT_SAYING_THAT_PLAYERS_MUST_FIRST                          = 18727,  -- It goes without saying that players must first have acquired a Trust permit in order to avail themselves of this opportunity.
        THOSE_DESIRING_TO_PARTICIPATE_SHOULD_SEEK_OUT_ONE                       = 18728,  -- Those desiring to participate should seek out one of the initiative's representatives, dressed in green, in one of the three nations.
        YOU_ARE_CURRENTLY_UNDER_UNITY_RESTRICTION_PLEASE_TRY                    = 18729,  -- You are currently under Unity restriction. Please try again during the next tabulation period.
        THE_A_M_A_N_HAS_REMOVED_THE                                             = 18730,  -- The A.M.A.N. has removed the Unity restrictions placed on you. Please choose your Unity.
        YOU_CALL_OUT_FOR_AID_FROM_THE_UNITY                                     = 18731,  -- You call out for aid from the Unity leaders, but none have heeded your call. Please try again.
        YOU_HAVE_ALREADY_CHANGED_UNITIES_PLEASE_WAIT_UNTIL                      = 18732,  -- You have already changed Unities. Please wait until the next tabulation period.
        SHOULD_YOU_CHOOSE_TO_BE_TELEPORTED_TO_THIS                              = 18733,  -- Should you choose to be teleported to this area, you will not have enough accolades to participate in the Wanted battle. Teleport anyway?
        TELEPORT_ANYWAY_YES_PLEASE_NO_THANK_YOU                                 = 18734,  -- Teleport anyway? Yes, please. No, thank you.
        THE_MANDRAGORA_SURREPTITIOUSLY_HANDS_YOU_SOMETHING                      = 18735,  -- The mandragora surreptitiously hands you something.
        THE_CRYSTAL_RESONATES_DEEP_WITHIN_YOUR_SOUL                             = 18736,  -- The crystal resonates deep within your soul!
        VANA_DIEL_IN_THE_YEAR_898                                               = 18737,  -- Vana'diel...in the year 898?
        I_MUST_MAKE_HASTE_FOR_REISENJIMA_AND_FIND                               = 18738,  -- I must make haste for Reisenjima and find the master before...
        THERE_S_SOMETHING_ELSE                                                  = 18739,  -- There's something else?
        YOU_SAY_MY_FATHER_TOLD_YOU_TO_SEEK                                      = 18740,  -- You say my father told you to seek me out?
        I_VE_BEEN_TRYING_TO_FIGURE_OUT_AS                                       = 18741,  -- I've been trying to figure out as much as I can about the strange portals that link our Vana'diel to another dimension.
