        THANK_YOU_FOR_THIS_NOW_I_ONLY_NEED_2                                    = 19231,  -- Thank you for this. Now I only need you to bring me # more.
        THIS_IS_EVERYTHING_I_REQUIRE_TO_BRING_ME                                = 19232,  -- This is everything I require to bring me one step closer to paradise. I hope that you may join me there some day.
        THIS_IS_AN_EXPLANATION_OF_THE_ASSIST_CHANNEL                            = 19233,  -- This is an explanation of the Assist Channel feature, which allows new and returning players to seek help from veteran adventurers.
        YOU_MUST_TAKE_ON_THE_RECORDS_OF_EMINENCE                                = 19234,  -- You must take on the % Records of Eminence objective before receiving the explanation.
        YOU_MUST_COMPLETE_BEFORE_TAKING_ON_THE_RECORDS                          = 19235,  -- You must complete % before taking on the % Records of Eminence objective.
        WHAT_DO_YOU_WANT_TO_LEARN_ABOUT_WHAT                                    = 19236,  -- What do you want to learn about? What is the Assist Channel? How can I post a message? What are the requirements? Where can I access it? Tell me about mentor messages. Where can I find mentors? What are Thumbs Up and Warnings? What happens if I am muted? When do my posting rights expire? Nothing for now.
        THE_ASSIST_CHANNEL_IS_A_SPECIAL_CHAT_CHANNEL                            = 19237,  -- The Assist Channel is a special chat channel that allows adventurers to ask questions and receive advice from veteran players known as mentors.
        PRESS_THE_SPACE_BAR_TO_BRING_UP_THE                                     = 19238,  -- Press the space bar to bring up the text window at the bottom of the screen and type /assistj (your message) or /assiste (your message) to post your message.
        YOU_CAN_ALSO_USE_AJ_FOR_ASSISTJ_AND                                     = 19239,  -- You can also use /aj for /assistj, and /ae for /assiste.
        ADDITIONALLY_PRESSING_CTRL_Q_WILL_DISPLAY_ASSISTJ_OR                    = 19240,  -- Additionally, pressing CTRL+Q will display /assistj or /assiste in the text window for you.
        YOU_CAN_CHANGE_THE_CTRL_Q_SHORTCUT_COMMAND                              = 19241,  -- You can change the CTRL+Q shortcut command...
        BY_GOING_TO_MAIN_MENU_CONFIG_MISC_2                                     = 19242,  -- ...by going to Main Menu > Config > Misc. 2 > Key Assignment > Commands > Chat: /AssistE or /AssistJ.
        IT_IS_RECOMMENDED_THAT_YOU_USE_ASSISTJ_AJ                               = 19243,  -- It is recommended that you use /assistj (/aj) when posting in Japanese, and /assiste (/ae) when posting in English.
        YOU_MUST_MEET_ONE_OF_THE_FOLLOWING_CONDITIONS                           = 19244,  -- You must meet one of the following conditions in order to post to the Assist Channel.
        ID_1_YOU_ARE_A_NEW_PLAYER_YOU_MAY                                       = 19245,  -- 1. You are a new player You may post messages from the moment you first set foot in Vana'diel.
        ID_2_YOU_ARE_A_RETURNEE_AS_A_RETURNING                                  = 19246,  -- 2. You are a returnee As a returning player, you may post messages upon logging in with a character that has not logged in for at least 48 days.
        ID_3_YOU_ARE_A_MENTOR_YOU_MAY_POST                                      = 19247,  -- 3. You are a mentor You may post messages as long as you remain a mentor to other players.
        NEW_PLAYERS_AND_RETURNEES_MAY_POST_MESSAGES_UNTIL                       = 19248,  -- New players and returnees may post messages until they have been logged in for a total of 48 hours since first receiving their posting rights.
        IF_YOU_WISH_TO_CHECK_HOW_LONG_YOU                                       = 19249,  -- If you wish to check how long you can continue to post for, speak to an and choose "When do my posting rights expire?" to see how much time you have left.
        THE_ASSIST_CHANNEL_CAN_ONLY_BE_USED_IN                                  = 19250,  -- The Assist Channel can only be used in the following areas.
        AVAILABLE_AREAS                                                         = 19251,  -- Available areas: %, %, %, %, %, %...
        ID_19252                                                                = 19252,  -- ...%, %, %, %, %, %, %, %...
        ID_19253                                                                = 19253,  -- ...%, %, %, %, %, %, %, %...
        AND_YOUR_MOG_HOUSE_RENT_A_ROOM                                          = 19254,  -- ...%, %, %, and your Mog House (Rent-a-Room).
        YOU_CANNOT_POST_OR_READ_MESSAGES_OUTSIDE_OF                             = 19255,  -- You cannot post or read messages outside of the areas listed above.
        EVEN_IN_AREAS_WHERE_MESSAGES_ARE_ALLOWED_YOU                            = 19256,  -- Even in areas where messages are allowed, you cannot post consecutive messages. Please wait a while after posting a message.
        MENTOR_MESSAGES_ARE_ACCOMPANIED_BY_A_FLAG_O                             = 19257,  -- Mentor messages are accompanied by a flag (o/) marker. This marker indicates the mentor's reliability (Mentor Class) and experience as an adventurer (Mastery Rank).
        AS_A_MENTOR_S_MENTOR_CLASS_INCREASES_THE                                = 19258,  -- As a mentor's Mentor Class increases, the color and shape of the marker will change: o/ > o9 > oC
        A_OC_MARKER_IS_A_SIGN_THAT_THE                                          = 19259,  -- A oC marker is a sign that the mentor has earned the highest levels of trust from other adventurers.
        THE_NUMBER_AFFIXED_TO_THE_MARKER_IS_THE                                 = 19260,  -- The number affixed to the marker is the mentor's Mastery Rank, and indicates how experienced the mentor is as an adventurer.
        THE_HIGHER_THE_NUMBER_THE_MORE_EXPERIENCED_THE                          = 19261,  -- The higher the number, the more experienced the mentor is.
        YOU_CAN_CHECK_YOUR_OWN_MASTERY_RANK_EVEN                                = 19262,  -- You can check your own Mastery Rank even if you do not serve as a mentor, so feel free to take a look every now and then if you are curious.
        YOU_CAN_CHECK_YOUR_MASTERY_RANK_BY_GOING                                = 19263,  -- You can check your Mastery Rank by going to Main Menu > Status > Profile.
        IF_YOU_WISH_TO_SPEAK_DIRECTLY_TO_A                                      = 19264,  -- If you wish to speak directly to a mentor, you can search for mentors by going to Main Menu > Help Desk > Mentor Search.
        THE_THUMBS_UP_FEATURE_ENABLES_YOU_TO_LET                                = 19265,  -- The Thumbs Up feature enables you to let mentors know when their comments proved to be especially helpful.
        MENTORS_WHO_EARN_LOTS_OF_THUMBS_UP_REPLIES                              = 19266,  -- Mentors who earn lots of Thumbs Up replies from other adventurers will see their Mentor Class increase.
        REMEMBER_TO_GIVE_A_THUMBS_UP_TO_ANY                                     = 19267,  -- Remember to give a Thumbs Up to any mentor you feel helped you out or taught you something useful.
        A_WARNING_IS_A_FEATURE_THAT_CAN_ONLY                                    = 19268,  -- A Warning is a feature that can only be used by mentors.
        PLEASE_USE_THIS_FEATURE_WHEN_A_POST_S                                   = 19269,  -- Please use this feature when a post's contents are insufficient or otherwise may be construed as harassment.
        TO_SEND_A_THUMBS_UP_OR_WARNING_TO                                       = 19270,  -- To send a Thumbs Up or Warning to another player, open the Chat Log Window and move the cursor over the relevant message and press the confirm button (Enter key) to bring up the evaluation menu.
        EVALUATIONS_CAN_BE_MADE_FOR_10_MINUTES_FOLLOWING                        = 19271,  -- Evaluations can be made for 10 minutes following the designated player's latest post to the Assist Channel.
        YOU_MAY_SEND_UP_TO_ONE_THUMBS_UP                                        = 19272,  -- You may send up to one Thumbs Up and one Warning per day (Earth time).
        THE_MUTE_FEATURE_PLACES_RESTRICTIONS_ON_YOUR_ABILITY                    = 19273,  -- The Mute feature places restrictions on your ability to post, meaning that other players will be unable to see the messages you post to the Assist Channel.
        PLEASE_REFRAIN_FROM_POSTING_UNSUITABLE_CONTENT_SO_THAT                  = 19274,  -- Please refrain from posting unsuitable content so that the veteran adventurers are not forced to mute you.
        MUTE_STATUS_CAN_BE_REMOVED_BY_PLAYERS_THAT                              = 19275,  -- Mute status can be removed by players that have the necessary Mute List access rights, or it will be removed automatically 24 hours (Earth time) after the mute status was enabled.
        YOU_ARE_FREE_TO_POST_MESSAGES_TO_THE                                    = 19276,  -- You are free to post messages to the Assist Channel until you decide to stop serving as a mentor.
        YOU_MAY_POST_MESSAGES_TO_THE_ASSIST_CHANNEL                             = 19277,  -- You may post messages to the Assist Channel until : on //. (Time remaining: Approx. # [sec./min./hr.])
        IF_YOU_LOG_OUT_WHILE_YOU_STILL_HAVE                                     = 19278,  -- If you log out while you still have time available, your remaining time will be carried over to the next time you log in.
        YOU_ARE_ABOUT_TO_LOSE_THE_ABILITY_TO                                    = 19279,  -- You are about to lose the ability to post messages to the Assist Channel.
        YOU_ARE_UNABLE_TO_POST_MESSAGES_TO_THE                                  = 19280,  -- You are unable to post messages to the Assist Channel.
        TAKE_ON_THE_RECORDS_OF_EMINENCE_OBJECTIVE_FROM                          = 19281,  -- Take on the % Records of Eminence objective from the Tutorial section of the Records of Eminence Menu and speak to the A.M.A.N. liaison.
        FAIR_GREETINGS_TO_YOU_WANDERER_I_AM_A                                   = 19282,  -- Fair greetings to you, wanderer. I am a linkshell concierge, charged with uniting lone explorers of Vana'diel with linkshells of similar goals.
        HOW_MAY_I_HELP_YOU_TODAY                                                = 19283,  -- How may I help you today?
        WHAT_DO_YOU_DESIRE_NOTHING_FOR_NOW_SHOW                                 = 19284,  -- What do you desire? Nothing for now. Show me recruiting linkshells. I'd like to hand out %. Tell me more. Open up the linkshell window.
        IT_WAS_MY_PLEASURE_TO_MEET_WITH_YOU                                     = 19285,  -- It was my pleasure to meet with you this fine day. May you encounter many friendly faces throughout your travels.
        EXCELLENT_PLEASE_SELECT_WHICH_LINKSHELL_YOU_ARE_INTERESTED              = 19286,  -- Excellent. Please select which linkshell you are interested in contacting.
        ARE_YOU_CERTAIN                                                         = 19287,  -- Are you certain?
        REALLY_RECEIVE_THE_LINKPEARL_OF_COURSE_NO_THANK                         = 19288,  -- Really receive the linkpearl? Of course. No, thank you.
        IN_THE_INTEREST_OF_FAIRNESS_I_AM_UNABLE                                 = 19289,  -- In the interest of fairness, I am unable to distribute multiple linkpearls to someone on the same day. Please come back tomorrow.
        IT_IS_MY_SINCERE_PLEASURE_TO_BESTOW_THIS                                = 19290,  -- It is my sincere pleasure to bestow this upon you.
        YOUR_NEW_LINKSHELL_IS_BEYOND_DOUBT_FILLED_WITH                          = 19291,  -- Your new linkshell is beyond doubt filled with many looking for new companions. Be sure to say a few words of greeting.
        I_HAVE_PREPARED_A_SMALL_MANUAL_DESCRIBING_THE                           = 19292,  -- I have prepared a small manual describing the importance of treating others with respect. Please have a quick glance at it when you have a moment.
        MAY_YOUR_NEW_LINKSHELL_PROVIDE_YOU_WITH_FOND                            = 19293,  -- May your new linkshell provide you with fond memories that will last a lifetime.
        THOUGH_IT_PAINS_ME_TO_SAY_THIS_I                                        = 19294,  -- Though it pains me to say this, I have no % that meet your requirements at this time.
        SHOULD_YOU_DESIRE_I_CAN_CANCEL_YOUR_REGISTRATION                        = 19295,  -- Should you desire, I can cancel your registration.
        CANCEL_REGISTRATION_YES_PLEASE_NOT_AT_THIS_TIME                         = 19296,  -- Cancel registration? Yes, please. Not at this time.
        SHOULD_YOU_DESIRE_TO_LOOK_FOR_MEMBERS_I                                 = 19297,  -- Should you desire to look for members, I can distribute % in your stead by utilizing the energies continued within your equipped %.
        DURING_THE_PROCESS_PLEASE_EQUIP_EITHER_OR_AS                            = 19298,  -- During the process, please equip either % or % as Linkshell 1 and select I'd like to hand out %.
        ONE_THAT_STEP_HAS_BEEN_COMPLETED_I_WILL                                 = 19299,  -- One that step has been completed, I will ask you a series of questions.
        TO_CANCEL_YOUR_REGISTRATION_EQUIP_OR_AS_LINKSHELL                       = 19300,  -- To cancel your registration, equip % or % as Linkshell 1, speak to me again, and select the appropriate linkshell from the list.
        UNFORTUNATELY_ONLY_THOSE_EQUIPPED_WITH_OR_AS_LINKSHELL                  = 19301,  -- Unfortunately, only those equipped with % or % as Linkshell 1 are able to distribute %.
        ONCE_IN_A_LIFETIME_MEETINGS_MAKE_FOR_WONDERFUL                          = 19302,  -- Once-in-a-lifetime meetings make for wonderful stories, but no treasure can compare to being part of a group of friends you can call home.
        LINKSHELL_CONCIERGES_SUCH_AS_MYSELF_BRING_TOGETHER_ADVENTURERS          = 19303,  -- Linkshell concierges such as myself bring together adventurers of similar interests.
        IN_A_WORD_WE_MATCH_ADVENTURERS_LOOKING_FOR                              = 19304,  -- In a word, we match adventurers looking for linkshells with those linkshells interested in taking in new members.
        I_ACCEPT_FROM_LINKSHELLS_THE_WORLD_OVER_AND                             = 19305,  -- I accept % from linkshells the world over and distribute them to appropriate adventurers.
        THIS_SERVICE_IS_PROVIDED_BY_THE_ADVENTURERS_MUTUAL                      = 19306,  -- This service is provided by the Adventurers' Mutual Aid Network, and as such, anyone working for Vana'diel's greater good is eligible to participate.
        ADDITIONALLY_PLEASE_BE_AWARE_THAT_I_AM_ONLY                             = 19307,  -- Additionally, please be aware that I am only able to offer you one % per day.
        THOUGH_WE_WOULD_LIKE_TO_OFFER_THIS_SERVICE                              = 19308,  -- Though we would like to offer this service free of charge, the network has its own expenses that must be paid, so we charge a nominal fee of # gil at the time of registration.
        IT_IS_ALSO_WORTH_NOTING_THAT_CAN_ONLY                                   = 19309,  -- It is also worth noting that % can only be registered by adventurers who have been active in Vana'diel for at least # days (Earth time).
        IT_IS_WORTH_NOTING_THAT_EACH_CONCIERGE_MAY                              = 19310,  -- It is worth noting that each concierge may only register a maximum of # linkshells.
        ONCE_THE_NUMBER_OF_REGISTRATIONS_HAS_HIT_THE                            = 19311,  -- Once the number of registrations has hit the limit, existing registrations will be canceled in order of oldest to newest.
        SERVER_MAINTENANCES_WILL_ALSO_IMMEDIATELY_CANCEL_ALL_REGISTRATIONS      = 19312,  -- Server maintenances will also immediately cancel all registrations, so be sure to keep your information up-to-date.
        THANK_YOU_FOR_TAKING_THE_TIME_TO_USE                                    = 19313,  -- Thank you for taking the time to use our service. Let me confirm the information contained within.
        CORRECT                                                                 = 19314,  -- , correct?
        LS0                                                                     = 19315,  -- LS0: .
        LS1                                                                     = 19316,  -- LS1: .
        LS0_NO_SENDING                                                          = 19317,  -- LS0: (No sending).
        LS1_NO_SENDING                                                          = 19318,  -- LS1: (No sending).
        SHALL_I_START_LOOKING_FOR_NEW_MEMBERS_FOR                               = 19319,  -- Shall I start looking for new members for a fee of # gil?
        LOOK_FOR_NEW_MEMBERS_GIL_THAT_SOUNDS_WONDERFUL                          = 19320,  -- Look for new members? (# gil) That sounds wonderful. I'd rather not.
        I_M_QUITE_SORRY_TO_HEAR_YOU_DECLINE                                     = 19321,  -- I'm quite sorry to hear you decline. Please let me know if you change your mind.
        I_WILL_NOW_ASK_YOU_A_SERIES_OF                                          = 19322,  -- I will now ask you a series of questions about your preferences. Be sure to answer truthfully so that you can find new members that match your style.
        WHAT_IS_YOUR_LANGUAGE_PREFERENCE_JAPANESE_ENGLISH_OTHER                 = 19323,  -- What is your language preference? Japanese. English. Other. Back.
        WHAT_DAYS_ARE_YOU_MOST_ACTIVE_EVERY_DAY                                 = 19324,  -- What days are you most active? Every day. Weekends and holidays. Weekdays. Monday. Tuesday. Wednesday. Thursday. Friday. Saturday. Sunday. Back.
        WHAT_DAYS_ARE_YOU_MOST_ACTIVE_NO_DAY                                    = 19325,  -- What days are you most active? [-/Z]No day set. [-/Z]Mondays. [-/Z]Tuesdays. [-/Z]Wednesdays. [-/Z]Thursdays. [-/Z]Fridays. [-/Z]Saturdays. [-/Z]Sundays. [-/Z]Holidays. Back. Next. Update.
        WHEN_DO_YOU_PLAYING_ON_NO_TIME_SET                                      = 19326,  -- When do you [start/stop] playing on [weekdays/weekends]? No time set. 12:00 a.m. 1:00 a.m.:00 a.m.:00 a.m. 4:00 a.m. 5:00 a.m. 6:00 a.m. 7:00 a.m. 8:00 a.m. 9:00 a.m. 10:00 a.m. 11:00 a.m. 12:00 p.m. 1:00 p.m.:00 p.m.:00 p.m. 4:00 p.m. 5:00 p.m. 6:00 p.m. 7:00 p.m. 8:00 p.m. 9:00 p.m. 10:00 p.m. 11:00 p.m. Back.
        DESIGNATE_A_TIME_ZONE_NO_DESIGNATION_JAPANESE_STANDARD                  = 19327,  -- Designate a time zone. No designation. Japanese Standard Time (JST). Pacific Time (PST|PDT). Greenwich Mean Time (GMT). Back.
        WHAT_TIME_ARE_YOU_ACTIVE_JST_IN_THE                                     = 19328,  -- What time are you active? (JST) In the morning. In the afternoon. In the evening. At night. In the wee hours of the morning. Return to previous selection.
        WHAT_TIME_ARE_YOU_ACTIVE_PST_PDT_IN                                     = 19329,  -- What time are you active? (PST|PDT) In the morning. In the afternoon. In the evening. At night. In the wee hours of the morning. Return to previous selection.
        WHAT_TIME_ARE_YOU_ACTIVE_GMT_IN_THE                                     = 19330,  -- What time are you active? (GMT) In the morning. In the afternoon. In the evening. At night. In the wee hours of the morning. Return to previous selection.
        HOW_MANY_MEMBERS_ARE_YOU_LOOKING_FOR_1                                  = 19331,  -- How many members are you looking for? 1... 4. 5. 6. 7. 8. 9. 10. Back.
        HOW_MANY_ACTIVE_MEMBERS_DO_YOU_HAVE_1                                   = 19332,  -- How many active members do you have? 1-6. 7-18. 19+. Back.
        HOW_WOULD_YOU_CHARACTERIZE_YOUR_LINKSHELL_NO_INFO                       = 19333,  -- How would you characterize your linkshell? [|/Z] No info provided. [|/Z] New players welcome. [|/Z] Returnees welcome. [|/Z] Adults only. [|/Z] 10 year veterans active. [|/Z] Casual players. [|/Z] Battle and synthesis support. [|/Z] Anyone welcome. [|/Z] End content-focused. [|/Z] Ambuscade-focused. [|/Z] Never give up. [|/Z] High-end gear. [|/Z] Looking for crafters. [|/Z] Trial memberships welcome. [|/Z] Multiple linkshells OK. [|/Z] Community events held. [|/Z] New linkshell. Back. Next. Update.
        LINKSHELL_CHARACTERISTICS_NO_INFO_PROVIDED_NEW_PLAYERS_WELCOME          = 19334,  -- Linkshell characteristics. No info provided. New players welcome. Returnees welcome. Adults only. 10 year veterans active. Casual players. Battle and synthesis support. Anyone welcome. End content-focused. Ambuscade-focused. Never give up. High-end gear. Looking for crafters. Trial memberships welcome. Multiple linkshells OK. Community events held. New linkshell. Back
        STYLE                                                                   = 19335,  -- Style: [Do everything/Engage in hard-core battle content/Engage in casual battle content/Vanquish HNMs/Meet other new players/Assist each other/Engage in synthesis and trading/Nothing].
