        MOST_ACTIVE_2                                                           = 19338,  -- Most active: [Every day/Weekends/Weekdays/Mondays/Tuesdays/Wednesdays/Thursdays/Fridays/Saturdays/Sundays] [at no time in particular/in the morning (PST|PDT)/in the afternoon (PST|PDT)/in the evening (PST|PDT)/at night (PST|PDT)/in the wee hours of the morning (PST|PDT)].
        MOST_ACTIVE_3                                                           = 19339,  -- Most active: [Every day/Weekends/Weekdays/Mondays/Tuesdays/Wednesdays/Thursdays/Fridays/Saturdays/Sundays] [at no time in particular/in the morning (GMT)/in the afternoon (GMT)/in the evening (GMT)/at night (GMT)/in the wee hours of the morning (GMT)].
        LOOKING_FOR_MORE_MEMBER                                                 = 19340,  -- Looking for # more member[/s].
