        OF_COURSE_INJECTING_YOUR_OWN_PERSONAL_FLAVOR_MAY                        = 19353,  -- Of course, injecting your own personal flavor may act as a conversation starter and help people to remember you.
        NO_MATTER_WHICH_ROUTE_YOU_CHOOSE_MAKE_SURE                              = 19354,  -- No matter which route you choose, make sure to always remain polite. There is no better way to start a friendship off on the right foot.
