        ANOTHER_IMPORTANT_POINT_IS_TO_ALWAYS_BE_MINDFUL                         = 19357,  -- Another important point is to always be mindful of the listener. How would you feel if someone said that to you? Think carefully before sending someone a message.
        IT_ALSO_HELPS_TO_BE_CLEAR_AND_CONCISE                                   = 19358,  -- It also helps to be clear and concise.
        BEING_VAGUE_MIGHT_CAUSE_OTHERS_TO_GET_THE                               = 19359,  -- Being vague might cause others to get the wrong impression.
