        FURTHERMORE_REFRAIN_FROM_MAKING_DISPARAGING_OR_AGGRESSIVE_REMARKS       = 19361,  -- Furthermore, refrain from making disparaging or aggressive remarks.
        ONCE_YOU_ARE_CLOSE_TO_SOMEONE_YOU_MAY                                   = 19362,  -- Once you are close to someone, you may be more comfortable letting your hair down, but it is strongly recommended that you refrain from any actions that may be construed as harassment.
